import Link from '../../components/Link';
import ScrollContainer from '../../components/ScrollContainer';
const _not_found = {title: "Unknown", jsx: <><h2 id="magic-armor-not_found-error">Error</h2>
<p>Unable to find the requested magic armor.</p>
</>};
const _mistmail = {title: "Mistmail", jsx: <><h2 id="magic-armor-mistmail-mistmail">Mistmail</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 127</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 285</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 3rd<br/><strong>Slot</strong> armor; <strong>Price</strong> 2,250 gp; <strong>Weight</strong> 25 lbs.</p>
<p>The fine links of this +1 <Link to="/eq-armor/chain_shirt">chain shirt</Link> form a pattern of roiling clouds. On command once per day, the wearer can transform it into thick fog that fills his space and provides <Link to="/rule/concealment">concealment</Link> (20% miss chance) for 3 minutes. This mist moves with the character. Effects that disperse the mist or destroy it cause the armor to reform into its solid shape on the character's body, as does speaking the command word or entering a place where the fog-magic doesn't function (such as underwater). If the character tries to don another suit of armor while the mistmail is in fog form, it reforms at the character's feet.</p>
<h3 id="magic-armor-mistmail-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/obscuring_mist">obscuring mist</Link>; <strong>Price</strong> 1,250 gp</p>
</>};
const _kimle_coat = {title: "Kimle Coat", jsx: <><h2 id="magic-armor-kimle_coat-kiml-coat">Kiml&eacute; Coat</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 73, 252</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> armor; <strong>Price</strong> 2,300 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This +1 <Link to="/eq-armor/leather">leather</Link> armor is made of kiml&eacute;, a linen-like cloth made of a sea plant the church of <Link to="/faith/gozreh">Gozreh</Link> cultivates, and resembles a snug light coat with a tattered lower fringe in the shape of trailing seaweed. The wearer of a kiml&eacute; coat gains a +5 bonus on Swim checks. Once per day, the wearer can breathe water for 1 minute.</p>
<h3 id="magic-armor-kimle_coat-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/water_breathing">water breathing</Link>, creator must have 5 ranks in the Swim skill; <strong>Price</strong> 1,230 gp</p>
</>};
const _grim_gloom_mail = {title: "Grim Gloom Mail", jsx: <><h2 id="magic-armor-grim_gloom_mail-grim-gloom-mail">Grim Gloom Mail</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 252</Link><br/><strong>Aura</strong> faint abjuration and necromancy; <strong>CL</strong> 3rd<br/><strong>Slot</strong> armor; <strong>Price</strong> 2,380 gp; <strong>Weight</strong> 40 lbs.</p>
<p>This ugly +1 <Link to="/eq-armor/chainmail">chainmail</Link> resists polishing and easily acquires bent links and other cosmetic damage from everyday use, though such blemishes never impair its function as armor. Once per day as a standard action, the wearer can afflict one target within 30 feet with bad luck, giving it a -2 penalty to Armor Class, on attack rolls, or on saving throws (wearer's choice) for 1 minute. In addition, once per day, the wearer can use <em>protection from good.</em></p>
<h3 id="magic-armor-grim_gloom_mail-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/bestow_curse">bestow curse</Link>, <Link to="/spell/protection_from_good">protection from good</Link>, <Link to="/domain/curse">Curse</Link> subdomain or <Link to="/hex/evil_eye">evil eye</Link> hex; <strong>Price</strong> 1,340 gp</p>
</>};
const _inheritors_breastplate = {title: "Inheritor's Breastplate", jsx: <><h2 id="magic-armor-inheritors_breastplate-inheritors-breastplate">Inheritor's Breastplate</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_103_the_hellfire_compact">Pathfinder #103: The Hellfire Compact pg. 73</Link>, <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 252</Link><br/><strong>Aura</strong> faint abjuration and transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> armor; <strong>Price</strong> 2,430 gp; <strong>Weight</strong> 30 lbs.</p>
<p>This reflective +1 <Link to="/eq-armor/breastplate">breastplate</Link> is decorated with a sword-and-starburst symbol. The armor is normally a golden color, but in battle it becomes silver-gray. The wearer can cast <em>bless weapon</em> and <em>remove fear</em> each once per day.</p>
<h3 id="magic-armor-inheritors_breastplate-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/bless_weapon">bless weapon</Link>, <Link to="/spell/remove_fear">remove fear</Link>; <strong>Price</strong> 1,390 gp</p>
</>};
const _otyugh_hide = {title: "Otyugh Hide", jsx: <><h2 id="magic-armor-otyugh_hide-otyugh-hide">Otyugh Hide</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 128</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 5th<br/><strong>Slot</strong> armor; <strong>Price</strong> 2,565 gp; <strong>Weight</strong> 25 lbs.</p>
<p>This muddy brown +1 <Link to="/eq-armor/hide">hide</Link> armor carries a fetid stench like raw sewage, and occasionally sprouts angry and uncomfortable-looking blisters. Creatures other than the wearer are repulsed by the otyugh armor's vile putridity.</p>
<p>Any creature ending its turn adjacent to the wearer becomes <Link to="/misc/sickened">sickened</Link> (Fortitude DC 13 negates) for as long as it remains adjacent to the wearer and for 1 round thereafter. A creature that strikes the wearer with a bite attack is affected the same way, even if it possesses exceptional reach and attacks while not adjacent to the wearer. If the wearer is swallowed whole, the attacker is automatically sickened and must succeed at a DC 13 Fortitude save at the beginning of its turn or be forced to regurgitate and drop the wearer harmlessly in an adjacent square (though the wearer is knocked <Link to="/rule/prone">prone</Link> during the regurgitation). Creatures with the <Link to="/umr/scent">scent</Link> ability suffer a -2 penalty to their saving throw against the stench of the otyugh armor. These abilities are poison effects; creatures immune to poison are immune to these effects as well. The wearer is immune to this effect.</p>
<p>The wearer gains a +2 competence bonus on saves against disease, poison, and any effect that would cause her to become <Link to="/misc/nauseated">nauseated</Link> or sickened.</p>
<h3 id="magic-armor-otyugh_hide-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/contagion">contagion</Link>, <Link to="/spell/stinking_cloud">stinking cloud</Link>; <strong>Price</strong> 1,365 gp</p>
</>};
const _iadaran_dress_uniform = {title: "Iadaran Dress Uniform", jsx: <><h2 id="magic-armor-iadaran_dress_uniform-iadaran-dress-uniform">Iadaran Dress Uniform</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 12</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> armor; <strong>Price</strong> 2,625 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This finely crafted +1 <Link to="/eq-material/mithral">mithral</Link> <Link to="/eq-armor/parade">parade</Link> armor from Kyonin is as light and comfortable as regular clothing. An Iadaran dress uniform counts as a <Link to="/eq-misc/courtiers_outfit">courtier's outfit</Link> (including appropriate jewelry) when the wearer is interacting with nobles or courtiers, in addition to providing a +2 circumstance bonus on Diplomacy and Intimidate checks to influence people from the elven home nation. Further, the wearer also gains a +2 competence bonus on Perception and Sense Motive checks to intuit that a creature is concealing its true beliefs, feelings, or motives.</p>
<h3 id="magic-armor-iadaran_dress_uniform-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/owls_wisdom">owl's wisdom</Link>, creator must be an <Link to="/race/elf">elf</Link>; <strong>Price</strong> 2,265 gp</p>
</>};
const _milanite_armor = {title: "Milanite Armor", jsx: <><h2 id="magic-armor-milanite_armor-milanite-armor">Milanite Armor</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 252</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 3rd<br/><strong>Slot</strong> armor; <strong>Price</strong> 2,780 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This +1 <Link to="/eq-armor/leather">leather</Link> armor usually looks like heavy protective work clothing, such as the garb of a professional blacksmith, butcher, or woodcutter. Once per day when an adjacent ally falls unconscious, the wearer can use <em>cure light wounds</em> on that ally as a swift action; if the wearer falls unconscious and this ability has not already been expended for the day, it automatically triggers on the wearer.</p>
<h3 id="magic-armor-milanite_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/cure_light_wounds">cure light wounds</Link>; <strong>Price</strong> 1,470 gp</p>
</>};
const _ghoul_hide = {title: "Ghoul Hide", jsx: <><h2 id="magic-armor-ghoul_hide-ghoul-hide">Ghoul Hide</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 51</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 3rd<br/><strong>Slot</strong> armor; <strong>Price</strong> 2,865 gp; <strong>Weight</strong> 25 lbs.</p>
<p>Typically crafted in the nation of Geb, this morbid +1 <Link to="/eq-armor/hide">hide</Link> armor is stitched from the flesh torn from the bodies of <Link to="/monster/ghoul">ghoul</Link> servants as a punishment for failing their masters in some manner. The wearer of this armor is immune to the paralytic touch of ghouls, ghasts, and lacedons.</p>
<p>If the wearer is the subject of a bite attack or is swallowed whole, the attacker must succeed at a DC 13 Fortitude save or contract <Link to="/disease/ghoul_fever">ghoul fever</Link>.</p>
<h3 id="magic-armor-ghoul_hide-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/ghoul_touch">ghoul touch</Link>; <strong>Price</strong> 1,515 gp</p>
</>};
const _red_stalker_armor = {title: "Red Stalker Armor", jsx: <><h2 id="magic-armor-red_stalker_armor-red-stalker-armor">Red Stalker Armor</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 159</Link>, <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 253</Link><br/><strong>Aura</strong> faint enchantment; <strong>CL</strong> 3rd<br/><strong>Slot</strong> armor; <strong>Price</strong> 3,035 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This dark red +1 <Link to="/eq-armor/leather">leather</Link> armor is modeled after the armor worn by the Blood Watch guards in Ilizmagorti, the home city of the <Link to="/rule/red_mantis">Red Mantis</Link> assassins. Vented and airy, the armor is suitable for wearing in dense jungles, humid rainforests, and other formidable environments. The wearer also gains a +5 competence bonus on Bluff checks to feint.</p>
<h3 id="magic-armor-red_stalker_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, creator must have 5 ranks in Bluff; <strong>Price</strong> 1,598 gp</p>
</>};
const _rosy_hauberk = {title: "Rosy Hauberk", jsx: <><h2 id="magic-armor-rosy_hauberk-rosy-hauberk">Rosy Hauberk</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 253</Link><br/><strong>Aura</strong> faint conjuration and transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> armor; <strong>Price</strong> 3,035 gp; <strong>Weight</strong> 25 lbs.</p>
<p>This metallic +1 <Link to="/eq-armor/chain_shirt">chain shirt</Link> is woven with the petals, buds, and stalks of numerous kinds of beautiful flowers, and the garment is so finely cut that it makes even unsightly wearers appear to have flattering proportions. The wearer can use <em>aspect of the nightingale</em> and <em>summon instrument</em> each once per day.</p>
<h3 id="magic-armor-rosy_hauberk-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/aspect_of_the_nightingale">aspect of the nightingale</Link>, <Link to="/spell/summon_instrument">summon instrument</Link>; <strong>Price</strong> 1,965 gp</p>
</>};
const _pallid_chain = {title: "Pallid Chain", jsx: <><h2 id="magic-armor-pallid_chain-pallid-chain">Pallid Chain</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 252</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 3rd<br/><strong>Slot</strong> armor; <strong>Price</strong> 3,300 gp; <strong>Weight</strong> 40 lbs.</p>
<p>The links of this +1 <Link to="/eq-armor/chainmail">chainmail</Link> are a dull, sickly white color that resembles old bone, and the suit's gauntlets are tipped with silver-black finger spikes. Once per day as a standard action, the wearer can ask one question of an undead creature or a destroyed undead creature's corpse, as if using <em>speak with dead,</em> except the target can only answer questions that pertain to events that occurred after it became undead.</p>
<h3 id="magic-armor-pallid_chain-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/speak_with_dead">speak with dead</Link>; <strong>Price</strong> 1,800 gp</p>
</>};
const _pelt_of_the_demon_mother = {title: "Pelt of the Demon Mother", jsx: <><h2 id="magic-armor-pelt_of_the_demon_mother-pelt-of-the-demon-mother">Pelt of the Demon Mother</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 253</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 3rd<br/><strong>Slot</strong> armor; <strong>Price</strong> 3,325 gp; <strong>Weight</strong> 25 lbs.</p>
<p>This +1 <Link to="/eq-armor/hide">hide</Link> armor appears to be made from a horrific amalgam of rotted animal pelts and animal bones, and is usually decorated with the skulls of tiny rodents or vermin and trimmed with the fur of a black wolf. The wearer can use <em>disguise self</em> and <em>unnatural lust</em> each once per day.</p>
<h3 id="magic-armor-pelt_of_the_demon_mother-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/disguise_self">disguise self</Link>, <Link to="/spell/unnatural_lust">unnatural lust</Link>; <strong>Price</strong> 1,745 gp</p>
</>};
const _djezet_skin = {title: "Djezet Skin", jsx: <><h2 id="magic-armor-djezet_skin-djezet-skin">Djezet Skin</h2>
<p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 25</Link><br/><strong>Aura</strong> faint enchantment; <strong>CL</strong> 3rd<br/><strong>Slot</strong> armor; <strong>Price</strong> 3,410 gp; <strong>Weight</strong> 7 lbs.</p>
<p>When unattended, <Link to="/eq-material/djezet">djezet</Link> skin appears as a curiously smooth sphere of rust-red metal. When it's held and a command word is spoken, the armor oozes across the wearer's body like a second skin. The armor can be removed as a free action by stepping out of it, causing it to pool on the floor. Djezet skin acts as a suit of +1 <Link to="/eq-armor/leather">leather</Link>, except it is made of metal (and thus druids cannot wear it) and has no armor check penalty and a 0% chance of arcane spell failure. Additionally, the wearer of djezet skin gains a +5 circumstance bonus on Diplomacy checks to make requests of creatures with an attitude of friendly or helpful.</p>
<h3 id="magic-armor-djezet_skin-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/charm_person">charm person</Link>; <strong>Price</strong> 1,785 gp</p>
</>};
const _starsong_mail = {title: "Starsong Mail", jsx: <><h2 id="magic-armor-starsong_mail-starsong-mail">Starsong Mail</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 253</Link><br/><strong>Aura</strong> faint conjuration and transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> armor; <strong>Price</strong> 3,460 gp; <strong>Weight</strong> 40 lbs.</p>
<p>This +1 <Link to="/eq-armor/chainmail">chainmail</Link> is usually a metallic midnight blue and may sport a badge in the shape of a butterfly, moth, or <Link to="/eq-weapon/starknife">starknife</Link>. Once per day, the wearer can use <em>expeditious retreat.</em> If the armor's wearer sleeps in or next to the armor, the armor automatically casts <em>dream feast</em> once per night on the wearer or the last creature who wore it.</p>
<h3 id="magic-armor-starsong_mail-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/dream_feast">dream feast</Link>, <Link to="/spell/expeditious_retreat">expeditious retreat</Link>; <strong>Price</strong> 1,880 gp</p>
</>};
const _powerhouse_pelt = {title: "Powerhouse Pelt", jsx: <><h2 id="magic-armor-powerhouse_pelt-powerhouse-pelt">Powerhouse Pelt</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 33</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> armor; <strong>Price</strong> 3,515 gp; <strong>Weight</strong> 20 lbs.</p>
<p>Crafted from the skin of a great cat, this +1 <Link to="/eq-armor/hide">hide</Link> armor provides its wearer a +2 competence bonus on all ability checks to perform feats of strength, such as bending bars, and forcing doors. This bonus doesn't apply on any other Strength-related rolls (including Strength-based skill checks and melee attack and damage rolls). The wearer also treats her Strength score as if it were 8 higher than normal for the purpose of determining her <Link to="/rule/carrying_capacity">carrying capacity</Link>.</p>
<h3 id="magic-armor-powerhouse_pelt-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/ant_haul">ant haul</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>; <strong>Price</strong> 1,915 gp</p>
</>};
const _sea_banshee_coat = {title: "Sea Banshee Coat", jsx: <><h2 id="magic-armor-sea_banshee_coat-sea-banshee-coat">Sea Banshee Coat</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 253</Link><br/><strong>Aura</strong> faint conjuration and transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> armor; <strong>Price</strong> 3,605 gp; <strong>Weight</strong> 20 lbs.</p>
<p>This +1 <Link to="/eq-armor/studded_leather">studded leather</Link> is styled like a captain's jacket with long, sturdy leather tails that cover the wearer's thighs, and it is festooned with steel studs crafted to look like gold coins. The wearer can use <em>abundant ammunition</em> and <em>purify food and drink</em> each once per day.</p>
<h3 id="magic-armor-sea_banshee_coat-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/abundant_ammunition">abundant ammunition</Link>, <Link to="/spell/purify_food_and_drink">purify food and drink</Link>; <strong>Price</strong> 1,890 gp</p>
</>};
const _calamitous_mail = {title: "Calamitous Mail", jsx: <><h2 id="magic-armor-calamitous_mail-calamitous-mail">Calamitous Mail</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 250</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> armor; <strong>Price</strong> 3,750 gp; <strong>Weight</strong> 25 lbs.</p>
<p>This style of +1 <Link to="/eq-armor/chain_shirt">chain shirt</Link> is decorated with small agates, and was first created by followers of the halfling goddess of mischief and battle. The wearer gains a +1 luck bonus on all saving throws.</p>
<h3 id="magic-armor-calamitous_mail-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/divine_favor">divine favor</Link>; <strong>Price</strong> 2,000 gp</p>
</>};
const _perfection_leather = {title: "Perfection Leather", jsx: <><h2 id="magic-armor-perfection_leather-perfection-leather">Perfection Leather</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 253</Link><br/><strong>Aura</strong> faint divination, necromancy, and transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> armor; <strong>Price</strong> 3,860 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This +1 <Link to="/eq-armor/leather">leather</Link> armor is usually inscribed with <Link to="/faith/irori">Irori's</Link> open-hand symbol at the neck, and with meditative mantras along the sleeves. The wearer can use <em>guidance, stone fist,</em> and <em>touch of fatigue</em> each once per day.</p>
<h3 id="magic-armor-perfection_leather-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/guidance">guidance</Link>, <Link to="/spell/stone_fist">stone fist</Link>, <Link to="/spell/touch_of_fatigue">touch of fatigue</Link>; <strong>Price</strong> 2,010 gp</p>
</>};
const _ekujae_jungle_armor = {title: "Ekujae Jungle Armor", jsx: <><h2 id="magic-armor-ekujae_jungle_armor-ekujae-jungle-armor">Ekujae Jungle Armor</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 51</Link><br/><strong>Aura</strong> faint abjuration and transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> armor; <strong>Price</strong> 3,900 gp; <strong>Weight</strong> 20 lbs.</p>
<p>Made of densely compacted jungle leaves by the Ekujae jungle elves of the Mwangi, this +1 <Link to="/eq-armor/leaf_armor">leaf armor</Link> has been delicately inscribed with elven script. Prized by druids who venture out of the jungle, this armor counts as a plant for the purposes of an <em>entangle</em> spell, allowing the spell to originate from the position of the wearer.</p>
<p>Ekujae jungle armor is uniquely suited to jungle terrain, keeping out the elements and granting the wearer a +5 competence bonus on Stealth checks in such terrain. This armor also allows the wearer to ignore the effects of a hot climate as if under the effects of <em>endure elements.</em></p>
<h3 id="magic-armor-ekujae_jungle_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/endure_elements">endure elements</Link>, <Link to="/spell/entangle">entangle</Link>, creator must be a druid; <strong>Price</strong> 2,275 gp</p>
</>};
const _half_plate_of_the_dark_prince = {title: "Half-Plate of the Dark Prince", jsx: <><h2 id="magic-armor-half_plate_of_the_dark_prince-half-plate-of-the-dark-prince">Half-Plate of the Dark Prince</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 252</Link><br/><strong>Aura</strong> faint conjuration and enchantment; <strong>CL</strong> 3rd<br/><strong>Slot</strong> armor; <strong>Price</strong> 3,910 gp; <strong>Weight</strong> 50 lbs.</p>
<p>This regal-looking +1 <Link to="/eq-armor/half_plate">half-plate</Link> is a status symbol in the church of <Link to="/faith/asmodeus">Asmodeus</Link>, and is decorated with red infernal symbols and an inverted pentagram. The wearer can use <em>charm person</em> and <em>infernal healing</em> each once per day.</p>
<h3 id="magic-armor-half_plate_of_the_dark_prince-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/charm_person">charm person</Link>, <Link to="/spell/infernal_healing">infernal healing</Link>; <strong>Price</strong> 2,330 gp</p>
</>};
const _toilers_armor = {title: "Toiler's Armor", jsx: <><h2 id="magic-armor-toilers_armor-toilers-armor">Toiler's Armor</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 253</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> armor; <strong>Price</strong> 3,920 gp; <strong>Weight</strong> 40 lbs.</p>
<p>This +1 <Link to="/eq-armor/chainmail">chainmail</Link> looks like something a talentless dwarven apprentice would make - ugly, asymmetrical, and finished quickly rather than with care. The wearer gains a luck bonus or penalty equal to 1d6-3 on Craft checks to make armor or weapons while wearing it. This bonus or penalty is determined the first time the wearer attempts such a Craft check to determine a day's progress. If the wearer removes the armor, this bonus or penalty persists for an additional 24 hours. Once per day, the wearer can use <em>magic weapon.</em></p>
<h3 id="magic-armor-toilers_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/crafters_curse">crafter's curse</Link>, <Link to="/spell/crafters_fortune">crafter's fortune</Link>, <Link to="/spell/magic_weapon">magic weapon</Link>; <strong>Price</strong> 2,110 gp</p>
</>};
const _painspike_armor = {title: "Painspike Armor", jsx: <><h2 id="magic-armor-painspike_armor-painspike-armor">Painspike Armor</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 252</Link><br/><strong>Aura</strong> faint necromancy [evil]; <strong>CL</strong> 5th<br/><strong>Slot</strong> armor; <strong>Price</strong> 4,145 gp; <strong>Weight</strong> 20 lbs.</p>
<p>This black +1 <Link to="/eq-armorenh/armor_spikes">spiked</Link> <Link to="/eq-armor/studded_leather">studded leather</Link> armor is outfitted with dozens of intimidating barbs, wicked chains, and leather straps that look to have been soaked in blood. Often worn by Kuthite torturers, painspike armor allows the wearer to use <em>bleed</em> at will and <em>interrogation</em> once per day.</p>
<h3 id="magic-armor-painspike_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/bleed">bleed</Link>, <Link to="/spell/interrogation">interrogation</Link>; <strong>Price</strong> 2,160 gp</p>
</>};
const _forgefathers_half_plate = {title: "Forgefather's Half-Plate", jsx: <><h2 id="magic-armor-forgefathers_half_plate-forgefathers-half-plate">Forgefather's Half-Plate</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 251</Link><br/><strong>Aura</strong> faint abjuration, divination, evocation, and transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> armor; <strong>Price</strong> 4,180 gp; <strong>Weight</strong> 50 lbs.</p>
<p>This +1 <Link to="/eq-armor/half_plate">half-plate</Link> is usually sized for a dwarf and decorated with one or more sacred hammer symbols of <Link to="/faith/torag">Torag</Link>. Once per day, the wearer may use <em>mending, protection from evil,</em> and <em>spark.</em> Once per day as a full-round action, the wearer can attempt a Knowledge check (with a +10 bonus) to identify a creature he is currently in combat with, even if he possesses no ranks in the appropriate Knowledge skill.</p>
<h3 id="magic-armor-forgefathers_half_plate-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/know_the_enemy">know the enemy</Link>, <Link to="/spell/mending">mending</Link>, <Link to="/spell/protection_from_evil">protection from evil</Link>, <Link to="/spell/spark">spark</Link>; <strong>Price</strong> 2,465 gp</p>
</>};
const _veiled_chain = {title: "Veiled Chain", jsx: <><h2 id="magic-armor-veiled_chain-veiled-chain">Veiled Chain</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 253</Link><br/><strong>Aura</strong> faint illusion; <strong>CL</strong> 3rd<br/><strong>Slot</strong> armor; <strong>Price</strong> 4,490 gp; <strong>Weight</strong> 25 lbs.</p>
<p>Narrow strips of brilliant silk cloth are woven through the rings of this +1 <Link to="/eq-armor/chain_shirt">chain shirt</Link> that cause the armor's colors to shift and shimmer as its wearer moves. The wearer can use <em>disguise self</em> and <em>vanish</em> each once per day.</p>
<h3 id="magic-armor-veiled_chain-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/disguise_self">disguise self</Link>, <Link to="/spell/vanish">vanish</Link>; <strong>Price</strong> 2,370 gp</p>
</>};
const _armor_of_the_unquenchable_fire = {title: "Armor of the Unquenchable Fire", jsx: <><h2 id="magic-armor-armor_of_the_unquenchable_fire-armor-of-the-unquenchable-fire">Armor of the Unquenchable Fire</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 250</Link><br/><strong>Aura</strong> moderate conjuration and enchantment; <strong>CL</strong> 8th<br/><strong>Slot</strong> armor; <strong>Price</strong> 4,840 gp; <strong>Weight</strong> 40 lbs.</p>
<p>This blue-black +1 <Link to="/magic-enh/defiant">defiant</Link> <Link to="/eq-armor/chainmail">chainmail</Link> has a metal badge depicting <Link to="/faith/calistria">Calistria's</Link> three-dagger symbol fused to it. Each of these suits of armor is crafted with a particular type of foe in mind for the defiant property, as appropriate for the vengeance the original crafter sought. Once per day, the wearer can use <em>charm person</em> (lasting 1 hour).</p>
<h3 id="magic-armor-armor_of_the_unquenchable_fire-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/charm_person">charm person</Link>, <Link to="/spell/summon_monster_i">summon monster I</Link>; <strong>Price</strong> 2,570 gp</p>
</>};
const _lucky_drunks_mail = {title: "Lucky Drunk's Mail", jsx: <><h2 id="magic-armor-lucky_drunks_mail-lucky-drunks-mail">Lucky Drunk's Mail</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 252</Link><br/><strong>Aura</strong> faint enchantment and evocation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> armor; <strong>Price</strong> 4,840 gp; <strong>Weight</strong> 40 lbs.</p>
<p>This +1 <Link to="/eq-armor/chainmail">chainmail</Link> is decorated with a row of small metal disks, each stamped with a tankard symbol. The wearer gains a +1 luck bonus on all saving throws and can use <em>moment of greatness</em> once per day.</p>
<h3 id="magic-armor-lucky_drunks_mail-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/divine_favor">divine favor</Link>, <Link to="/spell/moment_of_greatness">moment of greatness</Link>; <strong>Price</strong> 2,570 gp</p>
</>};
const _eternal_iron_breastplate = {title: "Eternal Iron Breastplate", jsx: <><h2 id="magic-armor-eternal_iron_breastplate-eternal-iron-breastplate">Eternal Iron Breastplate</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 251</Link><br/><strong>Aura</strong> moderate enchantment and conjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> armor; <strong>Price</strong> 4,890 gp; <strong>Weight</strong> 30 lbs.</p>
<p>This +1 <Link to="/magic-enh/stanching">stanching</Link> <Link to="/eq-armor/breastplate">breastplate</Link> is battle-scarred but polished with great care, and has a small sword-and-mountain symbol of <Link to="/faith/gorum">Gorum</Link> hammered just below the gorget. Once per day, the wearer can use <em>compel hostility;</em> if an adjacent ally is reduced to negative hit points or killed, the wearer may activate this as an immediate action instead of a standard action.</p>
<h3 id="magic-armor-eternal_iron_breastplate-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/compel_hostility">compel hostility</Link>, <Link to="/spell/stabilize">stabilize</Link>, either <Link to="/spell/cure_critical_wounds">cure critical wounds</Link> or <Link to="/spell/lesser_restoration">lesser restoration</Link>; <strong>Price</strong> 2,620 gp</p>
</>};
const _fangtide_scale_mail = {title: "Fangtide Scale Mail", jsx: <><h2 id="magic-armor-fangtide_scale_mail-fangtide-scale-mail">Fangtide Scale Mail</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 251</Link><br/><strong>Aura</strong> moderate enchantment, evocation, and illusion; <strong>CL</strong> 10th<br/><strong>Slot</strong> armor; <strong>Price</strong> 4,890 gp; <strong>Weight</strong> 30 lbs.</p>
<p>This +1 <Link to="/magic-enh/glamered">glamered</Link> <Link to="/eq-armor/scale_mail">scale mail</Link> is decorated with fangs and is usually made from the hide of a reptilian beast such as a basilisk. The wearer can use <em>burst bonds</em> and <em>wrath</em> each once per day; as a full-round action, the wearer can activate both of these abilities at the same time.</p>
<h3 id="magic-armor-fangtide_scale_mail-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/burst_bonds">burst bonds</Link>, <Link to="/spell/disguise_self">disguise self</Link>, <Link to="/spell/wrath">wrath</Link>; <strong>Price</strong> 2,590 gp</p>
</>};
const _thanatotic_visage = {title: "Thanatotic Visage", jsx: <><h2 id="magic-armor-thanatotic_visage-thanatotic-visage">Thanatotic Visage</h2>
<p><strong>Sources</strong> <Link to="/source/book_of_the_damned">Book of the Damned pg. 197</Link><br/><strong>Aura</strong> strong conjuration; <strong>CL</strong> 15th<br/><strong>Slot</strong> head; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This jet-black helm completely masks the wearer's face above the mouth, giving him a grim aspect. A thanatotic visage has no effect unless worn with <Link to="/magic-armor/thanatotic_plate">thanatotic plate</Link>. When the wearer would be reduced to 0 hp or fewer, the visage casts <em>breath of life</em> on her; this does not require an action or even conscious effort. Casting <em>breath of life</em> this way destroys the thanatotic visage.</p>
<h3 id="magic-armor-thanatotic_visage-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/breath_of_life">breath of life</Link>; <strong>Price</strong> 2,500 gp</p>
</>};
const _waverider_breastplate = {title: "Waverider Breastplate", jsx: <><h2 id="magic-armor-waverider_breastplate-waverider-breastplate">Waverider Breastplate</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_monster_codex">Inner Sea Monster Codex pg. 29</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> armor; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 30 lbs.</p>
<p>This flat, gray +1 <Link to="/eq-armor/breastplate">breastplate</Link> is embossed with the iron fin symbol of the Wave Riders (Absalom's sea cavalry), and is enchanted to make it lighter in water. The armor imposes no armor check penalty on Swim checks, but still contributes to the wearer's <Link to="/rule/encumbrance">encumbrance</Link> and applies all other armor check penalties as normal. Once per day, the wearer can speak a command word even if submerged to cause the armor - and the wearer if the armor is worn - to float as per the <em>buoyancy</em> spell.</p>
<h3 id="magic-armor-waverider_breastplate-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/buoyancy">buoyancy</Link>, <Link to="/spell/water_walk">water walk</Link>; <strong>Price</strong> 2,500 gp</p>
</>};
const _golden_judges_breastplate = {title: "Golden Judge's Breastplate", jsx: <><h2 id="magic-armor-golden_judges_breastplate-golden-judges-breastplate">Golden Judge's Breastplate</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 251</Link><br/><strong>Aura</strong> faint abjuration, enchantment, and transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> armor; <strong>Price</strong> 5,110 gp; <strong>Weight</strong> 30 lbs.</p>
<p>This gold-colored +1 <Link to="/eq-armor/breastplate">breastplate</Link> has a large, ornate symbol of a vault key on one side of the chest. The wearer gains a +4 competence bonus on Sense Motive checks. The wearer can use <em>command</em> and <em>peacebond</em> each once per day.</p>
<h3 id="magic-armor-golden_judges_breastplate-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/command">command</Link>, <Link to="/spell/owls_wisdom">owl's wisdom</Link>, <Link to="/spell/peacebond">peacebond</Link>; <strong>Price</strong> 2,730 gp</p>
</>};
const _rhino_hide = {title: "Rhino Hide", jsx: <><h2 id="magic-armor-rhino_hide-rhino-hide">Rhino Hide</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 129</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 464</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> armor; <strong>Price</strong> 5,165 gp; <strong>Weight</strong> 25 lbs.</p>
<p>This +2 <Link to="/eq-armor/hide">hide</Link> armor is made from rhinoceros hide. In addition to granting a +2 enhancement bonus to AC, it has a -1 armor check penalty and deals an additional 2d6 points of damage on any successful <Link to="/rule/charge">charge</Link> attack made by the wearer, including a mounted charge.</p>
<h3 id="magic-armor-rhino_hide-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>; <strong>Price</strong> 2,665 gp</p>
</>};
const _akhentepis_armor = {title: "Akhentepi's Armor", jsx: <><h2 id="magic-armor-akhentepis_armor-akhentepis-armor">Akhentepi's Armor</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_79_the_half_dead_city">Pathfinder #79: The Half-Dead City pg. 60</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> armor; <strong>Price</strong> 5,235 gp; <strong>Weight</strong> 10 lbs.</p>
<p>This suit of +1 <Link to="/magic-enh/stanching">stanching</Link> <Link to="/eq-armor/padded">padded</Link> armor is of traditional Osirian design, consisting of a quilted cuirass of lightweight, breathable linen; a linen kilt; and a teardrop-shaped groin guard of stiffened linen. Besides its anti-bleeding properties, Akhentepi's armor grants its wearer a sense of impending danger. Once per day as a free action when the wearer attempts an initiative check, the wearer can add a +3 insight bonus on that initiative check.</p>
<h3 id="magic-armor-akhentepis_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/anticipate_peril">anticipate peril</Link>, <Link to="/spell/stabilize">stabilize</Link>, <Link to="/spell/cure_critical_wounds">cure critical wounds</Link> or <Link to="/spell/lesser_restoration">lesser restoration</Link>; <strong>Price</strong> 2,695 gp</p>
</>};
const _blackfingers_apron = {title: "Blackfingers Apron", jsx: <><h2 id="magic-armor-blackfingers_apron-blackfingers-apron">Blackfingers Apron</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 250</Link><br/><strong>Aura</strong> faint conjuration and transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> armor; <strong>Price</strong> 5,240 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This +1 <Link to="/magic-enh/bitter">bitter</Link> <Link to="/eq-armor/leather">leather</Link> armor looks much like a blacksmith's apron or an alchemist's smock, and has many small pockets suitable for holding extracts, potions, or poisons. Once per day, the wearer can use <em>negate aroma</em> (lasting 1 hour). This effect suspends the armor's bitter special ability if used on the wearer. Once per day, the wearer can pull a <Link to="/eq-weapon/tanglefoot_bag">tanglefoot bag</Link> from one of the apron's pockets, although the bag crumbles into dust if it is not used within 1 minute.</p>
<h3 id="magic-armor-blackfingers_apron-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/negate_aroma">negate aroma</Link>, <Link to="/spell/stinking_cloud">stinking cloud</Link>, <Link to="/spell/web">web</Link>; <strong>Price</strong> 2,700 gp</p>
</>};
const _gravewatcher_chainmail = {title: "Gravewatcher Chainmail", jsx: <><h2 id="magic-armor-gravewatcher_chainmail-gravewatcher-chainmail">Gravewatcher Chainmail</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 251</Link><br/><strong>Aura</strong> moderate divination, evocation, and necromancy; <strong>CL</strong> 7th<br/><strong>Slot</strong> armor; <strong>Price</strong> 5,380 gp; <strong>Weight</strong> 40 lbs.</p>
<p>This blue-white +1 <Link to="/magic-enh/deathless">deathless</Link> <Link to="/eq-armor/chainmail">chainmail</Link> is made of an intricate pattern of light and dark links that form the shape of <Link to="/faith/pharasma">Pharasma's</Link> spiral on the armor's chest. The wearer can use <em>detect undead, disrupt undead,</em> and <em>light</em> each once per day.</p>
<h3 id="magic-armor-gravewatcher_chainmail-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/death_ward">death ward</Link>, <Link to="/spell/detect_undead">detect undead</Link>, <Link to="/spell/disrupt_undead">disrupt undead</Link>, <Link to="/spell/light">light</Link>; <strong>Price</strong> 2,840 gp</p>
</>};
const _deadeye_leather = {title: "Deadeye Leather", jsx: <><h2 id="magic-armor-deadeye_leather-deadeye-leather">Deadeye Leather</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 251</Link><br/><strong>Aura</strong> faint divination and illusion; <strong>CL</strong> 5th<br/><strong>Slot</strong> armor; <strong>Price</strong> 5,425 gp; <strong>Weight</strong> 20 lbs.</p>
<p>This mottled green-and-brown +1 <Link to="/magic-enh/shadow">shadow</Link> <Link to="/eq-armor/studded_leather">studded leather</Link> has the symbol of <Link to="/faith/erastil">Erastil</Link> burned into the shoulder. Once per day as a standard action, the wearer can prepare a perfectly aimed shot; as long as the wearer's next attack roll is made before the end of the next round, this attack ignores the target's miss chance and AC bonus from <Link to="/rule/cover">cover</Link> and <Link to="/rule/concealment">concealment</Link> (but not total concealment).</p>
<h3 id="magic-armor-deadeye_leather-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/invisibility">invisibility</Link>, <Link to="/spell/silence">silence</Link>, <Link to="/spell/true_strike">true strike</Link>; <strong>Price</strong> 2,800 gp</p>
</>};
const _all_seeing_armor = {title: "All-Seeing Armor", jsx: <><h2 id="magic-armor-all_seeing_armor-all-seeing-armor">All-Seeing Armor</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 250</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 3rd<br/><strong>Slot</strong> armor; <strong>Price</strong> 5,570 gp; <strong>Weight</strong> 25 lbs.</p>
<p>This +1 <Link to="/eq-armor/chain_shirt">chain shirt</Link> is made of shiny, bright rings on the left side and dull, dark rings on the right. The church of <Link to="/faith/nethys">Nethys</Link> uses suits of all-seeing armor to help Nethysians explore and catalog ancient libraries. At will, the wearer can use <em>detect magic</em> and <em>read magic.</em> Once per day, the wearer can use <em>comprehend languages.</em></p>
<h3 id="magic-armor-all_seeing_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/comprehend_languages">comprehend languages</Link>, <Link to="/spell/detect_magic">detect magic</Link>, <Link to="/spell/read_magic">read magic</Link>; <strong>Price</strong> 2,910 gp</p>
</>};
const _gray_masters_leathers = {title: "Gray Master's Leathers", jsx: <><h2 id="magic-armor-gray_masters_leathers-gray-masters-leathers">Gray Master's Leathers</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 251</Link><br/><strong>Aura</strong> faint conjuration, evocation, illusion, and transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> armor; <strong>Price</strong> 5,720 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This +1 <Link to="/magic-enh/shadow">shadow</Link> <Link to="/eq-armor/leather">leather</Link> armor is usually a neutral brown or gray color and is tight-fitting so it can be worn under bulky clothing or a disguise. The wearer can use <em>acid splash, dancing lights,</em> and <em>mage hand</em> each once per day.</p>
<h3 id="magic-armor-gray_masters_leathers-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/acid_splash">acid splash</Link>, <Link to="/spell/dancing_lights">dancing lights</Link>, <Link to="/spell/invisibility">invisibility</Link>, <Link to="/spell/mage_hand">mage hand</Link>, <Link to="/spell/silence">silence</Link>; <strong>Price</strong> 2,940 gp</p>
</>};
const _shifting_jerkin = {title: "Shifting Jerkin", jsx: <><h2 id="magic-armor-shifting_jerkin-shifting-jerkin">Shifting Jerkin</h2>
<p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 25</Link><br/><strong>Aura</strong> faint illusion and transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> armor; <strong>Price</strong> 5,965 gp; <strong>Weight</strong> 8 lbs.</p>
<p>This +1 <Link to="/eq-armor/lamellar_cuirass">lamellar cuirass</Link> grants its wearer shapeshifting. On command, the wearer of a shifting jerkin can change her appearance at will as per <em>disguise self.</em> If the wearer has a talents class feature (investigator talents, ninja tricks, rogue talents, or slayer talents), once per day she can spend 1 hour to swap out one talent for another for which she qualifies. She can't swap a talent that is a prerequisite for other talents or feats she has.</p>
<h3 id="magic-armor-shifting_jerkin-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/disguise_self">disguise self</Link>, <Link to="/spell/foxs_cunning">fox's cunning</Link>; <strong>Price</strong> 3,065 gp</p>
</>};
const _arachnid_harness = {title: "Arachnid Harness", jsx: <><h2 id="magic-armor-arachnid_harness-arachnid-harness">Arachnid Harness</h2>
<p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 25</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 4th<br/><strong>Slot</strong> armor; <strong>Price</strong> 6,160 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This form-fitting black +1 <Link to="/eq-armor/leather">leather</Link> features eight ridged support ribs along the back. On command, the arachnid harness sprouts eight enormous spidery legs from these ribs. These legs allow the armor's wearer to attempt Climb checks at full speed without needing to use her hands or feet. Additionally, while the legs are deployed, the armor's wearer doesn't lose her Dexterity bonus to AC while climbing, and need not succeed at a Climb check to avoid falling if she takes damage while climbing.</p>
<h3 id="magic-armor-arachnid_harness-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/spider_climb">spider climb</Link>; <strong>Price</strong> 3,160 gp</p>
</>};
const _raiment_of_chains = {title: "Raiment of Chains", jsx: <><h2 id="magic-armor-raiment_of_chains-raiment-of-chains">Raiment of Chains</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_temples">Inner Sea Temples pg. 12</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> armor; <strong>Price</strong> 6,250 gp; <strong>Weight</strong> 25 lbs.</p>
<p>While unattended, this +1 <Link to="/eq-armor/chain_shirt">chain shirt</Link> takes the shape of a heap of rusty chains, but when a creature picks up the armor, the shirt immediately starts to assume its true form. The chains eagerly wrap or willingly loosen around the wearer's body, allowing the wearer to don or remove the armor as a move action. A raiment of chains can't be "donned hastily."</p>
<p>Three times per day as a standard action, the wearer can command chains to shoot out from the raiment of chains and attempt a <Link to="/rule/reposition">reposition</Link> or <Link to="/rule/trip">trip</Link> combat maneuver check against a single target within 20 feet. The wearer is considered proficient with the chains and uses her own CMB with a +1 enhancement bonus on the check. The combat maneuver provokes attacks of opportunity as normal. The chains immediately retract back into the armor once the combat maneuver check has been attempted.</p>
<h3 id="magic-armor-raiment_of_chains-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/animate_objects">animate objects</Link>, <Link to="/spell/chain_of_perdition">chain of perdition</Link>; <strong>Price</strong> 3,250 gp</p>
</>};
const _locust_cuirass = {title: "Locust Cuirass", jsx: <><h2 id="magic-armor-locust_cuirass-locust-cuirass">Locust Cuirass</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_81_shifting_sands">Pathfinder #81: Shifting Sands pg. 58</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 6th<br/><strong>Slot</strong> armor; <strong>Price</strong> 6,565 gp; <strong>Weight</strong> 8 lbs.</p>
<p>The overlapping leather plates of this +2 <Link to="/eq-armor/lamellar_cuirass">lamellar cuirass</Link> oddly feel more like insect chitin than the supple leather they are crafted from. This armor's lightweight construction gives it a maximum Dexterity bonus of +6.</p>
<p>The wearer of a locust cuirass can take 10 on Acrobatics checks to jump even if distracted or in danger. Once per day as an immediate action, the wearer can summon a swarm of locusts that surround her and support her weight during a fall, causing her to drift slowly down to the ground, similar to <Link to="/spell/feather_fall">feather fall</Link>. While falling, the wearer can move up to 5 feet in any horizontal direction for every 1 foot she falls, at a speed of 60 feet per round. The wearer takes no damage upon landing. The effect ends as soon as the wearer touches the ground or after 6 rounds, whichever comes first. If the effect expires while the wearer is still in the air, she falls the remaining distance as normal.</p>
<h3 id="magic-armor-locust_cuirass-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/cape_of_wasps">cape of wasps</Link>; <strong>Price</strong> 3,365 gp</p>
</>};
const _dawnflower_chain_vest = {title: "Dawnflower Chain Vest", jsx: <><h2 id="magic-armor-dawnflower_chain_vest-dawnflower-chain-vest">Dawnflower Chain Vest</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 250</Link><br/><strong>Aura</strong> strong conjuration and evocation; <strong>CL</strong> 12th<br/><strong>Slot</strong> armor; <strong>Price</strong> 6,950 gp; <strong>Weight</strong> 25 lbs.</p>
<p>This red-and-gold +1 <Link to="/magic-enh/spell_storing_a">spell storing</Link> <Link to="/eq-armor/chain_shirt">chain shirt</Link> is designed to be worn over or between multiple layers of clothing such as garments suited for desert-traveling. At will, the wearer can use <em>light</em> and <em>stabilize.</em> Members of <Link to="/faith/sarenrae">Sarenrae's</Link> church often store a <em>cure</em> spell in the armor, allowing the wearer to strike an undead creature with positive energy or heal an ally.</p>
<h3 id="magic-armor-dawnflower_chain_vest-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/light">light</Link>, <Link to="/spell/stabilize">stabilize</Link>, creator must be a caster of at least 12th level; <strong>Price</strong> 3,600 gp</p>
</>};
const _truefaith_vestments = {title: "Truefaith Vestments", jsx: <><h2 id="magic-armor-truefaith_vestments-truefaith-vestments">Truefaith Vestments</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 53</Link><br/><strong>Aura</strong> moderate illusion; <strong>CL</strong> 10th<br/><strong>Slot</strong> armor; <strong>Price</strong> 6,950 gp; <strong>Weight</strong> 1 lb.</p>
<p>Worn by enforcers and acolytes of the living god Razmir, this +1 <Link to="/eq-armor/chain_shirt">chain shirt</Link> appears as a fine hooded robe made of silk of a color appropriate to the wearer's rank within the church as if it had the <Link to="/magic-enh/glamered">glamered</Link> special ability (it appears white when worn by anyone who doesn't follow Razmir). Used primarily as a means of appearing to be protected by the false god's power, the armor is treated as a +3 <Link to="/eq-armor/breastplate">breastplate</Link> against attacks made by any enemy who has not seen through the illusion. Unlike with standard glamered armor, any creature that successfully hits the target with a melee weapon is considered to have interacted with the illusion, and can see the armor's true form with a successful DC 16 Will save.</p>
<h3 id="magic-armor-truefaith_vestments-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/disguise_self">disguise self</Link>; <strong>Price</strong> 3,600 gp</p>
</>};
const _featherleaf_barding = {title: "Featherleaf Barding", jsx: <><h2 id="magic-armor-featherleaf_barding-featherleaf-barding">Featherleaf Barding</h2>
<p><strong>Sources</strong> <Link to="/source/familiar_folio">Familiar Folio pg. 21</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> armor; <strong>Price</strong> 7,310 gp; <strong>Weight</strong> 1 lb.</p>
<p>This enchanted sleeve is made of tiny, feather-shaped leaves and is designed to fit birds. Once fitted over the body of a Tiny or smaller avian creature, featherleaf barding automatically shrinks to snugly fit the creature's torso and neck, serving as +1 <Link to="/eq-armor/leather">leather</Link> armor (granting a total bonus to AC of +2). The maximum fly speed of a creature wearing featherleaf barding is 60 feet with average maneuverability. In forests, jungles, and thickly wooded areas, the wearer can fly through branches, brush, and even whole tree trunks as if they weren't there, though its fly speed and maneuverability remain the same.</p>
<h3 id="magic-armor-featherleaf_barding-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/fly">fly</Link>, <Link to="/spell/tree_stride">tree stride</Link>; <strong>Price</strong> 3,660 gp</p>
</>};
const _trained_barding = {title: "Trained Barding", jsx: <><h2 id="magic-armor-trained_barding-trained-barding">Trained Barding</h2>
<p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 27</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> armor; <strong>Price</strong> 8,350 gp; <strong>Weight</strong> 30 lbs.</p>
<p>This suit of Large +2 <Link to="/eq-armor/scale_mail">scale mail</Link> <Link to="/eq-armor/barding">barding</Link> is equipped with leather straps and loops suitable for attaching harnesses and leashes. It can fit any Large animal or magical beast, though not creatures of any other type. When worn by an animal, this armor grants the animal two additional <Link to="/ability/animal_tricks">tricks</Link> or one general purpose (as defined by the <Link to="/skill/handle_animal">Handle Animal</Link> skill), determined at the time the armor is created.</p>
<h3 id="magic-armor-trained_barding-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/awaken">awaken</Link>; <strong>Price</strong> 4,350 gp</p>
</>};
const _stalking = {title: "Stalking", jsx: <><h2 id="magic-armor-stalking-stalking">Stalking</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 211</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 6th<br/><strong>Slot</strong> armor; <strong>Price</strong> 8,575 gp; <strong>Weight</strong> 20 lbs.</p>
<p>This +2 <Link to="/eq-armor/studded_leather">studded leather</Link> armor comes in a number of varieties, each corresponding to a specific type of terrain from the ranger's <Link to="/ability/favored_terrain">favored terrain</Link> list. The armor takes on visual characteristics related to that type of terrain (cold stalking armor might be gray and white with a white fur trim, jungle stalking armor could be lush green with vine patterns, and so on) and makes the wearer blend in more naturally with his surroundings. The stalking armor grants the wearer a +5 competence bonus on Stealth and Perception checks attempted while in that specific terrain.</p>
<h3 id="magic-armor-stalking-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/chameleon_stride">chameleon stride</Link>, <Link to="/spell/perceive_cues">perceive cues</Link>; <strong>Price</strong> 4,375 gp</p>
</>};
const _scouting_leather = {title: "Scouting Leather", jsx: <><h2 id="magic-armor-scouting_leather-scouting-leather">Scouting Leather</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 53</Link><br/><strong>Aura</strong> moderate illusion and transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> armor; <strong>Price</strong> 8,750 gp; <strong>Weight</strong> 15 lbs.</p>
<p>The Sargavan government often issues this armor to scouts traveling through the jungle. This +1 <Link to="/magic-enh/expeditious">expeditious</Link> <Link to="/magic-enh/glamered">glamered</Link> <Link to="/eq-armor/leather">leather</Link> armor is colored a deep brown and painted with jungle camouflage. Scouts transform the armor to match the armor style and symbology of communities they visit, and use the expeditious special ability if they find they're unwelcome. In its true form, the armor grants a +3 competence bonus on Stealth checks. When transformed to fit a culture's style of dress, it instead grants a +3 competence bonus on Diplomacy checks against people of that culture.</p>
<h3 id="magic-armor-scouting_leather-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/disguise_self">disguise self</Link>, <Link to="/spell/expeditious_retreat">expeditious retreat</Link>; <strong>Price</strong> 4,450 gp</p>
</>};
const _snakescale_armor = {title: "Snakescale Armor", jsx: <><h2 id="magic-armor-snakescale_armor-snakescale-armor">Snakescale Armor</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_42_sanctum_of_the_serpent_god">Pathfinder #42: Sanctum of the Serpent God pg. 39</Link><br/><strong>Aura</strong> faint illusion; <strong>CL</strong> 5th<br/><strong>Slot</strong> armor; <strong>Price</strong> 8,900 gp; <strong>Weight</strong> 20 lbs.</p>
<p>This +1 <Link to="/eq-armor/scale_mail">scale mail</Link> is made from hardened, reinforced snakeskin scales. The armor has an arcane spell failure chance of 15%, a maximum Dexterity bonus of +5, and a -2 armor check penalty. It also grants its wearer a +5 competence bonus on Climb and Stealth checks. Snakescale armor is considered light armor.</p>
<h3 id="magic-armor-snakescale_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/invisibility">invisibility</Link>, <Link to="/spell/silence">silence</Link>, <Link to="/spell/spider_climb">spider climb</Link>; <strong>Price</strong> 4,450 gp</p>
</>};
const _morlock_hide = {title: "Morlock Hide", jsx: <><h2 id="magic-armor-morlock_hide-morlock-hide">Morlock Hide</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 128</Link><br/><strong>Aura</strong> moderate illusion and transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> armor; <strong>Price</strong> 8,910 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This +1 <Link to="/magic-enh/shadow">shadow</Link> <Link to="/eq-armor/leather">leather</Link> armor causes the wearer's skin to warp and distort into a welter of horrid scarification. The armor itself disappears from view under this coat of scars and the wearer's face appears as a loathsome, eyeless veil of flesh. This change is illusory, similar to <Link to="/magic-enh/glamered">glamered</Link> armor; however, morlock hide does cause the wearer's arms and legs to extend and her posture to become hunched. She gains a +2 circumstance bonus on Acrobatics, Climb, and Escape Artist checks, and she can move through narrow spaces while <Link to="/misc/squeezing">squeezing</Link> at normal speed and with no penalty to AC or on attack rolls.</p>
<h3 id="magic-armor-morlock_hide-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/alter_self">alter self</Link>, <Link to="/spell/invisibility">invisibility</Link>; <strong>Price</strong> 4,535 gp</p>
</>};
const _stone_eater_armor = {title: "Stone-eater Armor", jsx: <><h2 id="magic-armor-stone_eater_armor-stone-eater-armor">Stone-eater Armor</h2>
<p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 29</Link><br/><strong>Aura</strong> moderate abjuration and evocation; <strong>CL</strong> 10th<br/><strong>Slot</strong> armor; <strong>Price</strong> 8,950 gp; <strong>Weight</strong> 75 lbs.</p>
<p>This suit of +1 <Link to="/eq-armor/stoneplate">stoneplate</Link> bears a horned <Link to="/monster/gorgon">gorgon's</Link> head on each shoulder and the screaming face of a <Link to="/monster/medusa">medusa</Link> on its breastplate. The first suits of stone-eater armor found in the Inner Sea region were brought by explorers from faraway Casmaron, along with wild tales of a lost city destroyed by a powerful medusa.</p>
<p>Whenever the wearer of stone-eater armor is subject to a petrifying effect, such as that caused by a <Link to="/spell/flesh_to_stone">flesh to stone</Link> spell, the effect is negated and the stone-eater armor's enhancement bonus increases by 1 for 1 minute as the armor grows thicker and bulkier, covering more of the wearer's body without hindering her movement.</p>
<h3 id="magic-armor-stone_eater_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/stone_to_flesh">stone to flesh</Link>; <strong>Price</strong> 5,450 gp</p>
</>};
const _giants_nail_scale_mail = {title: "Giant's Nail Scale Mail", jsx: <><h2 id="magic-armor-giants_nail_scale_mail-giants-nail-scale-mail">Giant's Nail Scale Mail</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_93_forge_of_the_giant_god">Pathfinder #93: Forge of the Giant God pg. 16</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 7th<br/><strong>Slot</strong> armor; <strong>Price</strong> 9,200 gp; <strong>Weight</strong> 30 lbs.</p>
<p>This thick coat of +2 <Link to="/eq-armor/scale_mail">scale mail</Link> is crafted from waxy scales of varying sizes with a sickly, jaundiced color - the grime-stained fingernails of dead hill giants. Any creature of the giant subtype who comes within 30 feet of giant's nail scale mail must succeed at a DC 16 Will save or take a -4 penalty on attack rolls and saving throws for 1d4 rounds. This ability functions as a <Link to="/umr/gaze">gaze</Link> effect. It is a mind-affecting fear effect, but it does not stack with other fear effects to create stronger fear conditions. A giant who succeeds at the saving throw is immune to this effect for 24 hours. If a giant rolls a natural 20 on its saving throw, it becomes enraged by the sight of the armor. The giant gains the effects of the <em>rage</em> spell for 1d4 rounds and is compelled to attack the armor's wearer for the duration of this effect.</p>
<h3 id="magic-armor-giants_nail_scale_mail-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/fear">fear</Link>, <Link to="/spell/rage">rage</Link>; <strong>Price</strong> 4,700 gp</p>
</>};
const _writhing_armor = {title: "Writhing Armor", jsx: <><h2 id="magic-armor-writhing_armor-writhing-armor">Writhing Armor</h2>
<p><strong>Sources</strong> <Link to="/source/melee_tactics_toolbox">Melee Tactics Toolbox pg. 23</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 6th<br/><strong>Slot</strong> armor; <strong>Price</strong> 9,480 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This elaborate +2 <Link to="/eq-armor/silken_ceremonial">silken ceremonial</Link> armor is made of layers of silken braids and is often worn by diplomats and royalty when more drab or utilitarian armor is socially inappropriate. The wearer of writhing armor can cause it to unravel long braids of silk that twist and lash out of their own accord. The wearer can use one such braid to make attacks as a +1 <Link to="/eq-weapon/whip">whip</Link>. The constant writhing of the braids also grants the wearer a +4 dodge bonus to AC for 1 round when taking the <Link to="/rule/withdraw">withdraw</Link> action as a full-round action.</p>
<h3 id="magic-armor-writhing_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/animate_rope">animate rope</Link>; <strong>Price</strong> 4,980 gp</p>
</>};
const _windstrider_mail = {title: "Windstrider Mail", jsx: <><h2 id="magic-armor-windstrider_mail-windstrider-mail">Windstrider Mail</h2>
<p><strong>Sources</strong> <Link to="/source/down_the_blighted_path">Down the Blighted Path pg. 63</Link><br/><strong>Aura</strong> faint evocation and transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> armor; <strong>Price</strong> 10,100 gp; <strong>Weight</strong> 10 lbs.</p>
<p>Sleek dull gray stripes line the sides of this +1 <Link to="/eq-material/mithral">mithral</Link> <Link to="/eq-armor/chain_shirt">chain shirt</Link>, slightly marring the otherwise shining metal. When worn, the wearer's clothing and hair dance about as though caught in a faint breeze, no matter the prevailing weather conditions.</p>
<p>Three times per day as a standard action, the wearer can momentarily transform into a surge of living wind, moving up to 60 feet in a straight line. This line need not be horizontal; the effect can be used to traverse hazards or reach elevated platforms. All creatures in the line between the wearer's starting point and destination are blasted by the squall. The wearer attempts a <Link to="/rule/trip">trip</Link> combat maneuver against every creature in the area, with a +5 circumstance bonus on those checks. Failed trip attempts do not stop the wearer's movement, and these maneuvers and movement do not provoke any attacks of opportunity. Any flying creature in the area must succeed at a DC 15 Fly check or fall 20 feet, taking appropriate damage and <Link to="/rule/falling">falling</Link> <Link to="/rule/prone">prone</Link> if it reaches a solid surface.</p>
<p>Creatures more than one size category larger than the wearer are not affected by a wearer taking advantage of a suit of windstrider mail's living wind effect, but they do not inhibit the wearer's movement. If the wearer's path is blocked by an object, such as a door, she may continue moving forward with a successful Strength check to break the obstacle as a free action. If this check fails, her movement is halted and she takes damage as if she had fallen the distance that she traveled. If the wearer's movement does not end on a surface that can support her weight, she falls to the ground upon transforming back.</p>
<h3 id="magic-armor-windstrider_mail-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/gaseous_form">gaseous form</Link>, <Link to="/spell/gust_of_wind">gust of wind</Link>; <strong>Price</strong> 4,100 gp</p>
</>};
const _soothsayers_raiment = {title: "Soothsayer's Raiment", jsx: <><h2 id="magic-armor-soothsayers_raiment-soothsayers-raiment">Soothsayer's Raiment</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 129</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 286</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 5th<br/><strong>Slot</strong> armor; <strong>Price</strong> 10,300 gp; <strong>Weight</strong> 40 lbs.</p>
<p>This +1 <Link to="/eq-armor/chainmail">chainmail</Link> is attuned to a particular oracular <Link to="/ability/mystery">mystery</Link> and contains a revelation associated with that mystery. Its design and coloration are typically suggestive of its related mystery. While wearing the armor, an <Link to="/class/oracle">oracle</Link> has access to that revelation and may use it as if she had it as a normal class feature. The oracle must have the appropriate mystery to use the armor; for example, a soothsayer's raiment (battlecry) is only usable by an oracle of <Link to="/mystery/battle">battle</Link>. If the wearer already has that revelation and the revelation grants an ability with a limited number of uses per day, the oracle can use that ability one additional time per day. This ability has no effect if the armor is worn by a non-oracle.</p>
<p>For divination spells with a percentage-based chance of success (such as <em>augury</em> and <Link to="/spell/divination">divination</Link>), the wearer's chance increases by +5.</p>
<h3 id="magic-armor-soothsayers_raiment-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/augury">augury</Link>, creator must be an oracle with the desired revelation; <strong>Price</strong> 5,300 gp</p>
</>};
const _equestrian_plate = {title: "Equestrian Plate", jsx: <><h2 id="magic-armor-equestrian_plate-equestrian-plate">Equestrian Plate</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 126</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> armor; <strong>Price</strong> 10,650 gp; <strong>Weight</strong> 50 lbs. (full plate), 35 lbs. (banded mail), 70 lbs. (barding)</p>
<p>Shined to a mirror finish, this suit of +2 <Link to="/eq-armor/full_plate">full plate</Link> is decorated with gold inlay. As a move action when the wearer is mounted, the plates of the armor expand and reposition to protect the wearer's mount. In this form, the armor becomes a suit of +2 <Link to="/eq-armor/banded_mail">banded mail</Link> for the wearer and a suit of +1 banded mail <Link to="/eq-armor/barding">barding</Link> worn by the mount. A second move action merges it back into +2 full plate. Equestrian plate cannot transform and protect a mount more than one size larger than its wearer or a creature that cannot wear barding. It can create exotic barding, however, such as for a griffon or dragon.</p>
<p>If extra enhancements or spells are placed upon equestrian plate in full plate form, they affect only the wearer's armor when the suit is split. Effects on the barding are suppressed when it is merged into the armor. If either suit of armor is <Link to="/misc/broken">broken</Link> while separated, the other half immediately gains the broken condition as well. Destroying one suit destroys the other as well.</p>
<h3 id="magic-armor-equestrian_plate-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/fabricate">fabricate</Link>; <strong>Price</strong> 6,150 gp</p>
</>};
const _enchanted_eelskin = {title: "Enchanted Eelskin", jsx: <><h2 id="magic-armor-enchanted_eelskin-enchanted-eelskin">Enchanted Eelskin</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 126</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> armor; <strong>Price</strong> 11,160 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This +1 <Link to="/magic-enh/slick">slick</Link> <Link to="/eq-armor/leather">leather</Link> armor is made of shining, slippery eelskin that allows the wearer to move with deadly grace and sudden swiftness, especially underwater. When immersed in water, enchanted eelskin gains the <Link to="/magic-enh/shadow">shadow</Link> property and grants the wearer a swim speed of 30 feet and the ability to breathe water. In addition, during a surprise round the wearer can act as if she had a full round of actions, rather than a single standard action, as long as those actions do not require leaving the water. If she does leave the water, her surprise round turn immediately ends.</p>
<h3 id="magic-armor-enchanted_eelskin-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/grease">grease</Link>, <Link to="/spell/invisibility">invisibility</Link>, <Link to="/spell/touch_of_the_sea">touch of the sea</Link>; <strong>Price</strong> 5,660 gp</p>
</>};
const _tireless_tracking_hide = {title: "Tireless Tracking Hide", jsx: <><h2 id="magic-armor-tireless_tracking_hide-tireless-tracking-hide">Tireless Tracking Hide</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 212</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> armor; <strong>Price</strong> 11,165 gp; <strong>Weight</strong> 25 lbs.</p>
<p>This +1 <Link to="/eq-armor/hide">hide</Link> armor is always made from the pelt of a migratory herd animal. Anyone wearing this armor can maintain a <Link to="/rule/hustle">hustle</Link> for a full 8 hours without growing fatigued, doubling her normal daily overland movement rate. After that, the wearer begins to take nonlethal damage each hour, per the hustle rules. This armor does not increase tactical movement during combat. The benefits of this armor aren't replenished until the character has had a full night's rest.</p>
<h3 id="magic-armor-tireless_tracking_hide-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/bears_endurance">bear's endurance</Link>; <strong>Price</strong> 5,665 gp</p>
</>};
const _gnome_scrap_armor_gnome = {title: "Gnome Scrap Armor (Gnome)", jsx: <><h2 id="magic-armor-gnome_scrap_armor_gnome-gnome-scrap-armor-gnome">Gnome Scrap Armor (Gnome)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 224</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> armor; <strong>Price</strong> 11,175 gp; <strong>Weight</strong> 10 lbs.</p>
<blockquote>
<p><em>The following suit of armor is generally available only to members of the indicated race or ethnicity.</em></p>
</blockquote>
<p>A suit of gnome scrap armor protects its wearer as +2 <Link to="/eq-armor/studded_leather">studded leather</Link> armor, but myriad metal trinkets festoon it in place of studs. A number of these badges bear a special dweomer; each such badge can be removed as a move action, at which point it turns into a full-sized version of the trinket. The wearer automatically recognizes which badges have this property, and only the wearer can detach them.</p>
<p>A fully stocked suit of gnome scrap armor holds 20 badges representing the following gear: a flask of <Link to="/eq-weapon/acid">acid</Link>, two flasks of <Link to="/eq-weapon/alchemists_fire">alchemist's fire</Link>, a <Link to="/eq-misc/block_and_tackle">block and tackle</Link>, a buckler, a <Link to="/eq-misc/crowbar">crowbar</Link>, a <Link to="/eq-weapon/heavy_pick">heavy pick</Link>, a folded <Link to="/eq-weapon/net">net</Link>, a potion of <Link to="/spell/invisibility">invisibility</Link>, a potion of <Link to="/spell/lesser_restoration">lesser restoration</Link>, a <Link to="/eq-misc/shovel">shovel</Link>, two lit <Link to="/eq-misc/sunrod">sunrods</Link>, two <Link to="/eq-weapon/tanglefoot_bag">tanglefoot bags</Link>, a <Link to="/eq-weapon/throwing_axe">throwing axe</Link>, a <Link to="/eq-weapon/thunderstone">thunderstone</Link>, a <Link to="/eq-weapon/warhammer">warhammer</Link>, a <Link to="/eq-misc/bottle_of_fine_wine">bottle of fine wine</Link>, and a <Link to="/eq-misc/blanket">winter blanket</Link>. When the armor has 10 or fewer badges remaining, it is reduced to +1 studded leather armor until sufficient badges are returned. If all the patches are removed, the armor becomes nonmagical <Link to="/rule/masterwork_a">masterwork</Link> studded leather armor.</p>
<p>While the armor retains any magic, the wearer can return badges to the armor by casting <em>shrink item</em> on the appropriate object while wearing the armor and touching the object to the armor. This can even convert appropriate potions into badges, despite <em>shrink item</em> not normally working on magic items. Only items exactly corresponding to missing badges can be merged with the armor. Merging a potion reduces the potion's caster level to the minimum caster level for that spell. Items produced by gnome scrap armor match the size of the armor, so the typical <Link to="/race/gnome">gnome</Link>-sized version of the suit produces items sized for Small creatures.</p>
<h3 id="magic-armor-gnome_scrap_armor_gnome-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/shrink_item">shrink item</Link>, creator must be a gnome; <strong>Price</strong> 5,675 gp</p>
</>};
const _breastplate_of_the_planes = {title: "Breastplate of the Planes", jsx: <><h2 id="magic-armor-breastplate_of_the_planes-breastplate-of-the-planes">Breastplate of the Planes</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 47</Link><br/><strong>Aura</strong> strong evocation; <strong>CL</strong> 15th<br/><strong>Slot</strong> armor; <strong>Price</strong> 11,350 gp; <strong>Weight</strong> 30 lbs.</p>
<p>This sturdy, unadorned <Link to="/eq-armor/breastplate">breastplate</Link> has a +1 enhancement bonus on the Material Plane. On any Elemental Plane, or against attacks made by creatures native to any Elemental Plane, its enhancement bonus increases to +2. On the Astral Plane or the Ethereal Plane, or against attacks made by creatures native to either of those planes, its enhancement bonus increases to +3. On any other plane, or against attacks made by any outsider, its enhancement bonus increases to +4.</p>
<h3 id="magic-armor-breastplate_of_the_planes-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/plane_shift">plane shift</Link>; <strong>Price</strong> 5,580 gp</p>
</>};
const _emissarys_breastplate = {title: "Emissary's Breastplate", jsx: <><h2 id="magic-armor-emissarys_breastplate-emissarys-breastplate">Emissary's Breastplate</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets pg. 15</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> armor; <strong>Price</strong> 11,350 gp; <strong>Weight</strong> 30 lbs.</p>
<p>When not being worn, this simple steel +1 <Link to="/eq-armor/breastplate">breastplate</Link> appears to be typical magic armor. When worn by a <Link to="/class/cavalier">cavalier</Link> with the banner class feature, an emissary's breastplate automatically displays the cavalier's heraldry and counts as his banner. As long as the cavalier is not in disguise, he is considered to be displaying his banner while wearing the armor. Additionally, the wearer can expend a use of his challenge ability to speak on behalf of himself, his lord, or other agent who has given him the authority to do so. This allows him to use <em>tongues</em> (as per the spell) and issue a single <em>command</em> (as per the spell).</p>
<h3 id="magic-armor-emissarys_breastplate-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/arcane_mark">arcane mark</Link>, <Link to="/spell/command">command</Link>, <Link to="/spell/tongues">tongues</Link>, creator must have 5 ranks in Knowledge (nobility); <strong>Price</strong> 5,850 gp</p>
</>};
const _uskroths_armor = {title: "Uskroth's Armor", jsx: <><h2 id="magic-armor-uskroths_armor-uskroths-armor">Uskroth's Armor</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_91_battle_of_bloodmarch_hills">Pathfinder #91: Battle of Bloodmarch Hills pg. 55</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> armor; <strong>Price</strong> 11,350 gp; <strong>Weight</strong> 100 lbs.</p>
<p>This battered, well-used suit of +1 <Link to="/eq-armor/half_plate">half-plate</Link> automatically resizes itself to match the size of its wearer. Once per day on command, the armor can bestow upon its wearer the effects of <em>righteous might</em> for 5 rounds. The wearer's alignment determines the DR gained from this ability. A good wearer gains DR 5/evil, an evil wearer gains DR 5/good, and a wearer who is neither good nor evil chooses which DR to gain the first time she activates this ability - once chosen, it cannot be changed.</p>
<h3 id="magic-armor-uskroths_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/righteous_might">righteous might</Link>; <strong>Price</strong> 6,350 gp</p>
</>};
const _mosswater_stained_leather = {title: "Mosswater Stained Leather", jsx: <><h2 id="magic-armor-mosswater_stained_leather-mosswater-stained-leather">Mosswater Stained Leather</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 52</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 14th<br/><strong>Slot</strong> armor; <strong>Price</strong> 11,575 gp; <strong>Weight</strong> 20 lbs.</p>
<p>This set of +2 <Link to="/eq-armor/studded_leather">studded leather</Link> glows eerily in darkness. Tinted using rare dyes from the lost town of Mosswater in the River Kingdoms, this leather suit gives its wearer a ghostly appearance in areas of <Link to="/rule/dim_light">dim light</Link> or darker. While in such areas, the wearer gains a +4 circumstance bonus on <Link to="/skill/bluff">Bluff</Link> checks to pretend to be undead.</p>
<p>On command, the armor makes its wearer ethereal (as the <em>ethereal jaunt</em> spell). The effect is <Link to="/misc/dismissible">dismissible</Link>. The armor can be used in this manner for a total of up to 10 rounds per day. This duration doesn't need to be continuous, but must be used in 1-round increments.</p>
<h3 id="magic-armor-mosswater_stained_leather-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/ethereal_jaunt">ethereal jaunt</Link>; <strong>Price</strong> 5,875 gp</p>
</>};
const _bilgewater_coat = {title: "Bilgewater Coat", jsx: <><h2 id="magic-armor-bilgewater_coat-bilgewater-coat">Bilgewater Coat</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 25</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 11,655 gp; <strong>Weight</strong> 10 lbs.</p>
<p>This +1 <Link to="/magic-enh/putrid">putrid</Link> <Link to="/eq-armor/padded">padded</Link> armor is made up of colorful silks, complete with a ruffled collar that is accented with a brass button. Whenever a creature that is adjacent to the wearer confirms a critical hit against her, slimy bilgewater gushes from inside the coat onto the ground, landing in the attacking creature's space. Each creature touching the ground in this space when this effect activates must succeed at a DC 13 Reflex saving throw or fall <Link to="/rule/prone">prone</Link>. For the next 5 minutes, the bilgewater replicates the effects of <em>grease</em> in that square, and any creatures that move through it, including the wearer of the coat, must attempt Acrobatics checks as the <em>grease</em> spell requires.</p>
<h3 id="magic-armor-bilgewater_coat-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/grease">grease</Link>, <Link to="/spell/stinking_cloud">stinking cloud</Link>; <strong>Price</strong> 6,405 gp</p>
</>};
const _boneless_leather = {title: "Boneless Leather", jsx: <><h2 id="magic-armor-boneless_leather-boneless-leather">Boneless Leather</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 124</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 284</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> armor; <strong>Price</strong> 12,160 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This suit of +1 <Link to="/eq-armor/leather">leather</Link> gives its wearer the ability to twist and contort her body in virtually any direction. She gains a +5 bonus on Escape Artist checks, a +5 bonus on Acrobatics checks to reduce damage from <Link to="/rule/falling">falls</Link>, a +5 bonus to CMD, and DR 5/piercing or slashing.</p>
<h3 id="magic-armor-boneless_leather-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/alter_self">alter self</Link>, creator must have 5 ranks in Acrobatics and Escape Artist; <strong>Price</strong> 6,160 gp</p>
</>};
const _lupine_rageskin = {title: "Lupine Rageskin", jsx: <><h2 id="magic-armor-lupine_rageskin-lupine-rageskin">Lupine Rageskin</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 214</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> armor; <strong>Price</strong> 12,160 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This +1 <Link to="/eq-armor/leather">leather</Link> armor consists of wolf skins sewn together with sinew. When the wearer rages, he automatically turns into a Medium wolf, as if using <Link to="/umr/change_shape">change shape</Link> <em>(beast shape I).</em> The armor melds with his new form as normal, but the armor's enhancement bonus changes into a +1 enhancement bonus to her natural armor. When the rage ends, the wearer reverts to his own form.</p>
<h3 id="magic-armor-lupine_rageskin-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/beast_shape_i">beast shape I</Link>; <strong>Price</strong> 6,160 gp</p>
</>};
const _elemental_bulwark = {title: "Elemental Bulwark", jsx: <><h2 id="magic-armor-elemental_bulwark-elemental-bulwark">Elemental Bulwark</h2>
<p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 27</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 3rd<br/><strong>Slot</strong> armor; <strong>Price</strong> 12,300 gp; <strong>Weight</strong> 40 lbs.</p>
<p>This +2 <Link to="/eq-armor/chainmail">chainmail</Link> is attuned to a specific kind of element when created (acid, cold, electricity, or fire) and takes on a colored sheen based on the elemental type (green for acid, blue for cold, silver for electricity, or red for fire.) On command, the wearer of an elemental bulwark can create an effect identical to <em>fire shield,</em> except its effects apply to the type of elemental damage chosen when the armor was crafted. This effect lasts for up to 10 rounds per day, but these rounds need not be used consecutively. Ending this effect is a free action.</p>
<h3 id="magic-armor-elemental_bulwark-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/fire_shield">fire shield</Link>; <strong>Price</strong> 6,300 gp</p>
</>};
const _murderers_blackcloth = {title: "Murderer's Blackcloth", jsx: <><h2 id="magic-armor-murderers_blackcloth-murderers-blackcloth">Murderer's Blackcloth</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 128</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 285</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 9th<br/><strong>Slot</strong> armor; <strong>Price</strong> 12,405 gp; <strong>Weight</strong> 10 lbs.</p>
<p>This silk +1 <Link to="/magic-enh/shadow">shadow</Link> <Link to="/eq-armor/padded">padded</Link> armor is as dark as night and stitched with thread the color of dried blood. When worn by a rogue with the <Link to="/talent/bleeding_attack">bleeding attack</Link> talent, it increases the bleed damage of the rogue's sneak attacks by +1.</p>
<h3 id="magic-armor-murderers_blackcloth-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/bleed">bleed</Link>, <Link to="/spell/invisibility">invisibility</Link>, <Link to="/spell/silence">silence</Link>; <strong>Price</strong> 6,280 gp</p>
</>};
const _honors_panoply = {title: "Honor's Panoply", jsx: <><h2 id="magic-armor-honors_panoply-honors-panoply">Honor's Panoply</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_104_wrath_of_thrune">Pathfinder #104: Wrath of Thrune pg. 59</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> armor; <strong>Price</strong> 12,550 gp; <strong>Weight</strong> 50 lbs.</p>
<p>This immaculate set of +1 <Link to="/eq-armor/full_plate">full plate</Link> adorned with gilt flourishes and imagery of lions, and embossed red accents. When worn, the armor grants its wearer a +2 sacred bonus on all saves against spells with the evil descriptor or cast by evil creatures.</p>
<p>Once per day as a swift action, the wearer of honor's panoply can call upon <Link to="/faith/iomedae">Iomedae</Link> for protection. For the next 5 minutes, the armor glows with an aura of golden light, and any hostile creature within 20 feet of the wearer must succeed at a DC 14 Will save or take a -2 penalty to its Armor Class and on attack rolls and saving throws for the duration, or until it hits the wearer with an attack. The wearer can dismiss this effect before the duration expires as a swift action on his turn to heal itself of 3d8+5 points of damage in a burst of healing energy.</p>
<p>A creature with the Craft Magic Arms and Armor feat and at least 5 ranks in the Craft (armor) skill can perform a ritual to corrupt <em>honor's panoply,</em> shifting its dedication to an evil deity. This ritual takes 6 days to complete, costs 2,000 gp in incense and materials, and requires a successful DC 19 Craft (armor) check. If the magic warhammer <Link to="/magic-weapon/sinderbos">Sinderbos</Link> is used during the ritual, the cost of the ritual is reduced by 1,000 gp and requires only a successful DC 10 Craft (armor) check to complete. Once performed, the ritual transforms the armor into <strong>infamy's panoply;</strong> the armor turns black, the lions become animals sacred to the evil deity to which the armor is dedicated, and the red accents turn the crimson of fresh blood. The ritual also inverts the armor's effects: the save bonus is now profane and applies to spells with the good descriptor or cast by good creatures, and the armor now emanates a palpable aura of horror, causing non-allies to be <Link to="/misc/shaken">shaken</Link> on a failed save. Dismissing this effect now grants the wearer <Link to="/umr/fast_healing">fast healing</Link> 2 for 1 minute.</p>
<h3 id="magic-armor-honors_panoply-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/archons_aura">archon's aura</Link>, <Link to="/spell/veil_of_positive_energy">veil of positive energy</Link>, creator must worship Iomedae; <strong>Price</strong> 7,100 gp</p>
</>};
const _folding_plate = {title: "Folding Plate", jsx: <><h2 id="magic-armor-folding_plate-folding-plate">Folding Plate</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 126</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 284</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 10th<br/><strong>Slot</strong> armor; <strong>Price</strong> 12,650 gp; <strong>Weight</strong> 50 lbs.</p>
<p>This item normally looks like a heavy steel brooch or cloak clasp, often depicting a heavy helm or sturdy shield. On command, the brooch transforms in a clatter of metallic plates and panels to instantly cover the wearer in a complete suit of +1 <Link to="/eq-armor/full_plate">full plate</Link>, with the design of the brooch displayed on the armor's breastplate. The same command word causes the armor to transform into the brooch. The brooch only transforms if the wearer's armor slot is unoccupied, thus it won't work if the wearer is already armored. The brooch associated with this armor weighs less than a pound and occupies the neck slot when in this form.</p>
<h3 id="magic-armor-folding_plate-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/instant_summons">instant summons</Link>; <strong>Price</strong> 7,650 gp</p>
</>};
const _hallowed_chain_varisian = {title: "Hallowed Chain (Varisian)", jsx: <><h2 id="magic-armor-hallowed_chain_varisian-hallowed-chain-varisian">Hallowed Chain (Varisian)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 225</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> armor; <strong>Price</strong> 12,800 gp; <strong>Weight</strong> 40 lbs.</p>
<blockquote>
<p><em>The following suit of armor is generally available only to members of the indicated race or ethnicity.</em></p>
</blockquote>
<p>Most often forged in Ustalav and Varisia as protection against the unquiet dead, this suit of +2 <Link to="/eq-armor/chainmail">chainmail</Link> amplifies the effect of <Link to="/ability/channel_positive_energy">channeled positive energy</Link>. When its wearer is healed by positive energy (even if not currently wounded) or is in the area of positive energy channeled to harm undead, the armor absorbs 1 point of positive energy per 2 dice of healing, with a minimum of 1 point and a maximum of 5 points. This does not reduce the effect of the positive energy on any of its targets. Until the end of the wearer's next turn, any creature that would be harmed by positive energy (such as an undead) that strikes the wearer with a natural weapon or an unarmed strike or that succeeds at a <Link to="/rule/grapple">grapple</Link> combat maneuver check against the wearer takes an amount of damage equal to the amount of positive energy stored in the armor.</p>
<p>If multiple effects charge the armor, only the strongest effect applies. Fixed amounts of healing (such as that granted by the <Link to="/spell/heal">heal</Link> spell) have no effect on the armor.</p>
<h3 id="magic-armor-hallowed_chain_varisian-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/cure_moderate_wounds">cure moderate wounds</Link>, creator must be a Varisian; <strong>Price</strong> 6,550 gp</p>
</>};
const _legion_armor = {title: "Legion Armor", jsx: <><h2 id="magic-armor-legion_armor-legion-armor">Legion Armor</h2>
<p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 29</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 7th<br/><strong>Slot</strong> armor; <strong>Price</strong> 13,400 gp; <strong>Weight</strong> 35 lbs.</p>
<p>This gilded suit of +2 <Link to="/eq-armor/banded_mail">banded mail</Link> is decorated with images of celestial beings holding their weapons high. Legion armor is typically worn by high-ranking <Link to="/family/angel">angels</Link> and <Link to="/family/archon">archons</Link> directly combating the forces of evil on the Material Plane.</p>
<p>Once per day as a standard action, the wearer of a suit of legion armor can cast the spell <em>spiritual ally</em> with a duration of 1 minute. This ally typically takes on the appearance of an imposing angelic warrior. At any time while the armor's <em>spiritual ally</em> is conjured, the wearer of a suit of legion armor can dismiss the effect as a standard action, causing the <em>spiritual ally</em> to explode with a thunderous choir of voices and blaring trumpets. This effect causes each evil-aligned creatures within 100 feet to become <Link to="/misc/shaken">shaken</Link> unless it succeeds at a DC 20 Will save.</p>
<h3 id="magic-armor-legion_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/cause_fear">cause fear</Link>, <Link to="/spell/spiritual_ally">spiritual ally</Link>; <strong>Price</strong> 6,900 gp</p>
</>};
const _armor_of_the_sands = {title: "Armor of the Sands", jsx: <><h2 id="magic-armor-armor_of_the_sands-armor-of-the-sands">Armor of the Sands</h2>
<p><strong>Sources</strong> <Link to="/source/melee_tactics_toolbox">Melee Tactics Toolbox pg. 22</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> armor; <strong>Price</strong> 14,160 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This +2 <Link to="/eq-armor/leather">leather</Link> armor is made of camel hide and has been worn smooth as if blasted by sand. The wearer is protected from mundane extremes of cold and heat (as the <Link to="/spell/endure_elements">endure elements</Link> spell), and can see normally in sandstorms, dust storms, and similar conditions. Once per day as a swift or immediate action, the wearer can briefly turn to sand when hit by an attack but before damage is determined. For the purposes of resolving the damage, the wearer is treated as an incorporeal creature. Only a single attack is affected by each use of this ability.</p>
<h3 id="magic-armor-armor_of_the_sands-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/stoneskin">stoneskin</Link>; <strong>Price</strong> 7,160 gp</p>
</>};
const _armor_of_grim_triumph_orc = {title: "Armor of Grim Triumph (Orc)", jsx: <><h2 id="magic-armor-armor_of_grim_triumph_orc-armor-of-grim-triumph-orc">Armor of Grim Triumph (Orc)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 224</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 7th<br/><strong>Slot</strong> armor; <strong>Price</strong> 14,300 gp; <strong>Weight</strong> 40 lbs.</p>
<blockquote>
<p><em>The following suit of armor is generally available only to members of the indicated race or ethnicity.</em></p>
</blockquote>
<p>Spikes of impractical length adorn this +1 <Link to="/eq-armorenh/armor_spikes">spiked</Link> <Link to="/eq-armor/breastplate">breastplate</Link>. The armor's enhancement bonus applies on attack rolls and damage rolls for attacks made with the armor spikes, as well as to its armor bonus to AC.</p>
<p>As a full-round action, the wearer can claim a trophy from a slain foe and mount it on the armor's spikes, gaining a +1 competence bonus on Intimidate checks and a +1 morale bonus on Will saves against fear. Each additional trophy mounted on the armor's spikes increases these bonuses by 1. As an immediate action before rolling to confirm a critical hit, the wearer can call upon the armor to gain a morale bonus on the attack roll to confirm the critical hit equal to the total number of trophies on the armor. Doing so consumes one of the trophies.</p>
<p>The armor can hold up to four trophies. To provide any benefit, trophies must be from creatures that were slain by the wearer and whose Hit Dice were equal to at least half of the wearer's total Hit Dice. The armor's magic keeps the trophies from rotting away completely, but does nothing to keep them fresh or hide the stench of rotting flesh.</p>
<p>Suits of armor of grim triumph find use mainly among the <Link to="/race/orc">orcs</Link> of Belkzen and the Darklands. In the Mwangi Expanse, orcs use the similar <em>hide of grim triumph,</em> which is +1 spiked <Link to="/eq-armor/hide">hide</Link> armor crafted from tanned animal hides and foot-long thorns. Reduce the cost and price of a hide of grim triumph by 185 gp and the weight by 10 pounds.</p>
<h3 id="magic-armor-armor_of_grim_triumph_orc-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/fear">fear</Link>, <Link to="/spell/gentle_repose">gentle repose</Link>, creator must be an orc; <strong>Price</strong> 7,500 gp</p>
</>};
const _mammoth_hide = {title: "Mammoth Hide", jsx: <><h2 id="magic-armor-mammoth_hide-mammoth-hide">Mammoth Hide</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 134</Link>, <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 52</Link>, <Link to="/source/melee_tactics_toolbox">Melee Tactics Toolbox pg. 23</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 11th<br/><strong>Slot</strong> armor; <strong>Price</strong> 14,665 gp; <strong>Weight</strong> 25 lbs.</p>
<p>Made of tattered mammoth hide and bone, this +3 <Link to="/eq-armor/hide">hide</Link> armor is similar to <Link to="/magic-armor/rhino_hide">rhino hide</Link>, but is fashioned in the harsh lands of the Realm of the Mammoth Lords using beasts common to that region. In addition to granting a +3 enhancement bonus to AC, it has a -1 armor check penalty and grants the wearer 4d6 additional points of damage on the first successful <Link to="/rule/charge">charge</Link> attack she makes in a round, including a mounted charge.</p>
<h3 id="magic-armor-mammoth_hide-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>; <strong>Price</strong> 7,415 gp</p>
</>};
const _icelink_chainmail = {title: "Icelink Chainmail", jsx: <><h2 id="magic-armor-icelink_chainmail-icelink-chainmail">Icelink Chainmail</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_69_maiden_mother_crone">Pathfinder #69: Maiden, Mother, Crone pg. 61</Link></p>
<p><strong>Aura</strong> moderate evocation; <strong>CL</strong> 6th<br/><strong>Slot</strong> armor; <strong>Price</strong> 15,100 gp; <strong>Weight</strong> 20 lbs.</p>
<p>Carved from a single block of ice birthed from the breath of the great white wyrm Sjohvor, the ice-carved rings of this exquisite suit of +2 <Link to="/eq-armor/chainmail">chainmail</Link> never thaw. If <Link to="/rule/grappled">grappled</Link>, the wearer can command the armor to release an icy blast against the grappler. The armor then glows with a pale blue radiance, deals 4d6 points of cold damage to the target, and causes the target to be <Link to="/misc/staggered">staggered</Link> for 1 round. Once the armor discharges, this ability can't be used until the armor recharges 1 hour later.</p>
<p>Icelink chainmail is considered light armor and has an arcane spell failure chance of 20%, a maximum Dexterity bonus of +4, and an armor check penalty of -3. The armor weighs half as much as standard chainmail and floats in water.</p>
<h3 id="magic-armor-icelink_chainmail-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/frigid_touch">frigid touch</Link>, <Link to="/spell/wall_of_ice">wall of ice</Link>; <strong>Price</strong> 7,700 gp</p>
</>};
const _gale_armor = {title: "Gale Armor", jsx: <><h2 id="magic-armor-gale_armor-gale-armor">Gale Armor</h2>
<p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 25</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> armor; <strong>Price</strong> 15,180 gp; <strong>Weight</strong> -</p>
<p>Gale armor is a suit of +3 <Link to="/eq-armor/silken_ceremonial">silken ceremonial</Link> armor that floats weightlessly when not worn. Gale armor has no weight of its own and confers limited weightlessness on its wearer. The wearer of a suit of gale armor can use <em>air walk</em> up to 10 rounds per day. Activating or deactivating this ability is a free action, and these rounds need not be consecutive. Additionally, the wearer of a suit of gale armor is permanently under the effect of <em>glide,</em> and if he's capable of flying, the armor increases his maneuverability by one category.</p>
<h3 id="magic-armor-gale_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/air_walk">air walk</Link>, <Link to="/spell/glide">glide</Link>; <strong>Price</strong> 7,680 gp</p>
</>};
const _breastplate_of_vanishing = {title: "Breastplate of Vanishing", jsx: <><h2 id="magic-armor-breastplate_of_vanishing-breastplate-of-vanishing">Breastplate of Vanishing</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 124</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> armor; <strong>Price</strong> 15,200 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This battered +1 <Link to="/eq-material/mithral">mithral</Link> <Link to="/eq-armor/breastplate">breastplate</Link> bears a resemblance to a stylized turtle shell. On command, its wearer can vanish inside the armor, leaving the breastplate behind while she stays safely hidden in an extradimensional space. This space is barely large enough for the wearer to sit comfortably, but does provides breathable air and light to see by. The wearer cannot perceive the environs around the armor while inside. A second command word returns the wearer to the armor's location, wearing the armor. If the wearer can't return to the space the armor is in, she is instead shunted to the nearest empty space that can contain her, but no longer wearing the armor.</p>
<p>If the breastplate is destroyed, the wearer immediately returns to the square the armor was in when it was destroyed. Successfully <Link to="/spell/dispel">dispelling</Link> the armor likewise returns the wearer, though in this case still wearing the armor.</p>
<h3 id="magic-armor-breastplate_of_vanishing-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/rope_trick">rope trick</Link>; <strong>Price</strong> 9,700 gp</p>
</>};
const _coat_of_shells_gillmen_merfolk = {title: "Coat of Shells (Gillmen, Merfolk)", jsx: <><h2 id="magic-armor-coat_of_shells_gillmen_merfolk-coat-of-shells-gillmen-merfolk">Coat of Shells (Gillmen, Merfolk)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 224</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> armor; <strong>Price</strong> 15,350 gp; <strong>Weight</strong> 20 lbs.</p>
<blockquote>
<p><em>The following suit of armor is generally available only to members of the indicated race or ethnicity.</em></p>
</blockquote>
<p>Overlapping scallop shells form this suit of +2 <Link to="/eq-armor/scale_mail">scale mail</Link>. While the wearer is swimming in water, the coat of shells restricts her movement speed as light armor instead of as medium armor. Whether worn in or out of water, a coat of shells requires medium armor proficiency.</p>
<p>When out of the water, a coat of shells keeps its wearer's skin wet and cool. This provides the wearer resist fire 5 and the benefits of the <em>endure elements</em> spell against hot temperatures only, and it doubles the amount of time a wearer with the water dependent racial trait or <Link to="/umr/water_dependency">water dependency</Link> can spend out of water without harm. None of these benefits apply in water.</p>
<h3 id="magic-armor-coat_of_shells_gillmen_merfolk-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/create_water">create water</Link>, <Link to="/spell/endure_elements">endure elements</Link>, <Link to="/spell/freedom_of_movement">freedom of movement</Link>, creator must be either a gillman or a merfolk; <strong>Price</strong> 7,850 gp</p>
</>};
const _elven_vengeance = {title: "Elven Vengeance", jsx: <><h2 id="magic-armor-elven_vengeance-elven-vengeance">Elven Vengeance</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 115</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 12th<br/><strong>Slot</strong> armor; <strong>Price</strong> 16,150 gp; <strong>Weight</strong> 20 lbs.</p>
<p>This set of +2 <Link to="/eq-armor/elven_chain">elven chain</Link> grants its wearer a +4 <em>resistance</em> bonus on saving throws against spells, spell-like abilities, and other effects created by worshipers and minions of a specific demon lord, chosen when the armor is created. Against such foes, the armor's enhancement bonus increases to +4. The first suit of this armor was created quite recently by Perelir for her close friend Malindil as part of the ranger's vengeful crusade against <Link to="/faith/abraxas">Abraxas</Link>; since then, many other suits focused against other powerful demons (particularly the nascent demon lord <Link to="/monster/treerazer">Treerazer</Link>) have been crafted.</p>
<h3 id="magic-armor-elven_vengeance-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/detect_evil">detect evil</Link>, <Link to="/spell/resistance">resistance</Link>; <strong>Price</strong> 10,650 gp</p>
</>};
const _armor_of_insults = {title: "Armor of Insults", jsx: <><h2 id="magic-armor-armor_of_insults-armor-of-insults">Armor of Insults</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 124</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 283</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 7th<br/><strong>Slot</strong> armor; <strong>Price</strong> 16,175 gp; <strong>Weight</strong> 20 lbs.</p>
<p>Each metal bit of this suit of +1 <Link to="/eq-armor/studded_leather">studded leather</Link> looks more like a tiny sneering face than a simple stud. Once per day the wearer of the armor may command the mouths to unleash a torrent of verbal abuse directed against every hostile creature within 60 feet who can see and hear the wearer. Each such creature must make a DC 16 Will saving throw to avoid suffering an overwhelming compulsion to attack the wearer for the next 7 rounds. If the creature is unable to attack the wearer on its next turn, or attacking the wearer would put the creature at risk (moving through a threatened square, charging into a pit, and so on) it can act normally that turn. This is a mind-affecting sonic effect, and has no effect on creatures that do not use a spoken language.</p>
<h3 id="magic-armor-armor_of_insults-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/confusion">confusion</Link>; <strong>Price</strong> 7,675 gp</p>
</>};
const _skin_of_klendar_the_troll_king = {title: "Skin of Klendar the Troll King", jsx: <><h2 id="magic-armor-skin_of_klendar_the_troll_king-skin-of-klendar-the-troll-king">Skin of Klendar the Troll King</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_27_what_lies_in_dust">Pathfinder #27: What Lies in Dust pg. 58</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 8th<br/><strong>Slot</strong> armor; <strong>Price</strong> 16,315 gp; <strong>Weight</strong> 25 lbs.</p>
<p>This suit of mottled, greenish hide armor has no seams, as if it were made from a single large, disgusting skin. When worn, it tightens to fit snugly against the body. The skin acts as a suit of +2 <Link to="/eq-armor/hide">hide</Link> armor and grants the wearer 5 temporary hit points. These hit points regenerate at a rate of 1 hp per round. If the wearer is damaged by fire or acid, the temporary hit points do not regenerate, but may be restored by magical healing.</p>
<p>In addition, while wearing the armor, the bearer finds that he can speak Giant with a commanding voice. The wearer gains a +2 bonus on all Diplomacy or Intimidate skill checks made to influence any creature with the giant subtype. This bonus extends to all giants except trolls, which prove utterly offended by the armor, which all too readily resembles the flayed flesh of one of their kind. Any <Link to="/family/troll">troll</Link> treats the wearer of the armor one step less favorably than it otherwise would. In addition, even the most charismatic can never improve a troll's attitude any higher than indifferent while wearing the armor.</p>
<h3 id="magic-armor-skin_of_klendar_the_troll_king-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/aid">aid</Link>, <Link to="/spell/regenerate">regenerate</Link>; <strong>Price</strong> 8,157 gp</p>
</>};
const _numerian_resistance_plate = {title: "Numerian Resistance Plate", jsx: <><h2 id="magic-armor-numerian_resistance_plate-numerian-resistance-plate">Numerian Resistance Plate</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 52</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 6th<br/><strong>Slot</strong> armor; <strong>Price</strong> 16,350 gp; <strong>Weight</strong> 30 lbs.</p>
<p>Numerians who oppose the Technic League have developed many forms of protection from the tyrannical organization's technology-infused weaponry. This +2 <Link to="/eq-armor/breastplate">breastplate</Link> is made of scrap metal from one of the alien ruins that pepper the landscape, remnants of the crashed spaceship now known as Silver Mount. Specifically designed to provide additional defense against beam weapons, Numerian resistance plate grants its wearer a +4 bonus to touch AC against ray attacks.</p>
<p>Three times per day, when a ray attack targeting the plate's wearer misses by 4 or less, the wearer can deflect the ray back at its source as an immediate action. The ray uses the original attack roll to determine whether it hits its new target.</p>
<h3 id="magic-armor-numerian_resistance_plate-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/deflection">deflection</Link>, <Link to="/spell/shield">shield</Link>; <strong>Price</strong> 8,700 gp</p>
</>};
const _heros_hauberk = {title: "Hero's Hauberk", jsx: <><h2 id="magic-armor-heros_hauberk-heros-hauberk">Hero's Hauberk</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 211</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 13th<br/><strong>Slot</strong> armor; <strong>Price</strong> 16,600 gp; <strong>Weight</strong> 25 lbs.</p>
<p>The damage reduction of this dull gray +1 <Link to="/eq-material/adamantine">adamantine</Link> <Link to="/eq-armor/chain_shirt">chain shirt</Link> stacks with any other damage reduction the wearer possesses. For example, a wearer with DR 5/magic would reduce damage from nonmagical attacks by 6, and magical attacks by 1. While the wearer rages or maintains a <Link to="/ability/raging_song">raging song</Link>, the armor emits a low droning sound and grants the benefits of <Link to="/magic-enh/light_fortification">light fortification</Link>.</p>
<p>While the wearer maintains a <Link to="/ability/bardic_performance">bardic performance</Link>, the armor's links jangle in harmony with his song or movements, aiding his focus. The wearer receives a +1 luck bonus on all ability checks and skill checks he attempts during such a performance. In addition, any penalties applied to his attack rolls, ability checks, skill checks, and saving throws are reduced by 1. If a die roll has multiple penalties, the total of the penalties is reduced by 1, not each individual penalty.</p>
<h3 id="magic-armor-heros_hauberk-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/limited_wish">limited wish</Link> or <Link to="/spell/miracle">miracle</Link>, creator must have the raging song class feature; <strong>Price</strong> 11,850 gp</p>
</>};
const _abrogalian_corset = {title: "Abrogalian Corset", jsx: <><h2 id="magic-armor-abrogalian_corset-abrogalian-corset">Abrogalian Corset</h2>
<p><strong>Sources</strong> <Link to="/source/cheliax_empire_of_devils">Cheliax, Empire of Devils pg. 20</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 9th<br/><strong>Slot</strong> armor; <strong>Price</strong> 17,175 gp; <strong>Weight</strong> 10 lbs.</p>
<p>Devised by Her Infernal Majestrix, Abrogail I, this +3 <Link to="/eq-armor/studded_leather">studded leather</Link> armor is lavishly adorned with a bound <Link to="/monster/swarm_of_hellwasps">swarm of hellwasps</Link>. Once ranking among the most spectacular pieces of clothing in Cheliax, the discomfort caused by during the creation of this corset is as legendary as the protection it offers.</p>
<p>The wasps bound to the corset prevent the first 20 points of damage you take each day (resetting at midnight). Once the wasps have prevented 20 points of damage for the day, they angrily animate and swarm around you, and you must make a DC 18 Fortitude save or be <Link to="/misc/nauseated">nauseated</Link> for 1 round. After 1 round of activity, the swarm then returns to the corset and goes dormant, and this ability to prevent damage does not function until it recovers at midnight.</p>
<p>The swarm cannot be targeted separately from the armor and cannot be killed unless the armor is destroyed (not just broken).</p>
<h3 id="magic-armor-abrogalian_corset-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/lesser_planar_ally">lesser planar ally</Link>, <Link to="/spell/summon_swarm">summon swarm</Link>, caster level 9th; <strong>Price</strong> 8,675 gp</p>
</>};
const _backbreaker_mail = {title: "Backbreaker Mail", jsx: <><h2 id="magic-armor-backbreaker_mail-backbreaker-mail">Backbreaker Mail</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 50</Link><br/><strong>Aura</strong> moderate illusion and transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> armor; <strong>Price</strong> 17,650 gp; <strong>Weight</strong> 45 lbs.</p>
<p>This +2 <Link to="/eq-armorenh/armor_spikes">spiked</Link> <Link to="/eq-armor/splint_mail">splint mail</Link> is fashioned from hacked-off chunks of tanned hide and held together by humanoid spines. Used by orcs of the Broken Spine clan in Belkzen, these sets of armor are seen as a status symbol, and are adorned with trophies from slain foes, such as <Link to="/magic-wondrous/wayfinder">wayfinders</Link>. This armor grants its wearer the <Link to="/umr/constrict">constrict</Link> ability, dealing an amount of damage equal to 1d6 + the wearer's Strength modifier.</p>
<p>The vertebrae of the spines adorning the backbreaker mail are sharpened, acting as +1 human-<Link to="/magic-enh/bane">bane</Link> armor spikes.</p>
<h3 id="magic-armor-backbreaker_mail-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/beast_shape_i">beast shape I</Link>, <Link to="/spell/disguise_self">disguise self</Link>, <Link to="/spell/summon_monster_i">summon monster I</Link>; <strong>Price</strong> 9,025 gp</p>
</>};
const _hide_of_the_hagfish = {title: "Hide of the Hagfish", jsx: <><h2 id="magic-armor-hide_of_the_hagfish-hide-of-the-hagfish">Hide of the Hagfish</h2>
<p><strong>Sources</strong> <Link to="/source/seers_of_the_drowned_city">Seers of the Drowned City pg. 54</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> armor; <strong>Price</strong> 18,165 gp; <strong>Weight</strong> 25 lbs.</p>
<p>With the coming of the Eye of Abendego and the permanent change to the coastline's environs, its inhabitants have been forced to look to strange new places for resources. Hagfish hide may well be one of the most unusual replacement materials. This suit of +1 <Link to="/magic-enh/slick">slick</Link> <Link to="/eq-armor/hide">hide</Link> armor appears to constantly drip a viscous ooze. When immersed in water, the wearer gains a swim speed of 20 feet and the ability to breathe underwater. The slime exuded by the armor is particularly unpleasant and foul-tasting - the first time a creature successfully bites a character wearing hide of the hagfish in a 24 hour period, that creature must succeed at a DC 14 Fortitude saving throw to avoid being <Link to="/misc/nauseated">nauseated</Link> by the slime for 1 round.</p>
<h3 id="magic-armor-hide_of_the_hagfish-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/grease">grease</Link>, <Link to="/spell/water_breathing">water breathing</Link>; <strong>Price</strong> 9,165 gp</p>
</>};
const _eagle_knight_dress_uniform = {title: "Eagle Knight Dress Uniform", jsx: <><h2 id="magic-armor-eagle_knight_dress_uniform-eagle-knight-dress-uniform">Eagle Knight Dress Uniform</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 76</Link>, <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 50</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 6th<br/><strong>Slot</strong> armor; <strong>Price</strong> 18,175 gp; <strong>Weight</strong> 20 lbs.</p>
<p>This set of fine +2 <Link to="/eq-armor/parade">parade</Link> armor matches the dress uniform of Andoran's <Link to="/rule/eagle_knights">Eagle Knights</Link>. If the wearer is ever grappled or restrained, she can attempt an Escape Artist check to get free as an immediate action. The wearer gains a +2 competence bonus on this check. Once per day as a standard action, the wearer of an Eagle Knight dress uniform can call forth shimmering plates of golden light to reinforce the armor. This effect increases the armor's enhancement bonus to AC from +2 to +5 for the next 10 minutes.</p>
<h3 id="magic-armor-eagle_knight_dress_uniform-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/liberating_command">liberating command</Link>, <Link to="/spell/mage_armor">mage armor</Link>; <strong>Price</strong> 9,175 gp</p>
</>};
const _lifecollar_coat = {title: "Lifecollar Coat", jsx: <><h2 id="magic-armor-lifecollar_coat-lifecollar-coat">Lifecollar Coat</h2>
<p><strong>Sources</strong> <Link to="/source/undead_slayers_handbook">Undead Slayer's Handbook pg. 29</Link><br/><strong>Aura</strong> moderate abjuration and necromancy; <strong>CL</strong> 7th<br/><strong>Slot</strong> chest and neck (see text); <strong>Price</strong> 18,200 gp; <strong>Weight</strong> 10 lbs.</p>
<p>The tall, silver collar on this +2 <Link to="/eq-material/mithral">mithral</Link> <Link to="/eq-armor/armored_coat">armored coat</Link> is attractively set off by the coat's deep navy hues and ivory silk trim. A lifecollar coat occupies both the chest and the neck magic item slots. The wearer receives a +2 circumstance bonus to AC and CMD against attacks or maneuvers that specifically target the wearer's neck or throat (such as a vampire's check to establish or maintain a <Link to="/rule/pinned">pin</Link> or the roll to confirm a critical hit with a <Link to="/magic-enh/vorpal">vorpal</Link> weapon).</p>
<p>Additionally, when struck by an attack that would bestow a <Link to="/rule/negative_level">negative level</Link>, the wearer has a 50% chance of avoiding the negative level. The wearer may not avoid more than 1 negative level per round in this fashion. This effect does not mitigate any other damage or remove negative levels previously gained.</p>
<p>The silver collar can be collapsed and lowered as a full-round action. Doing so frees up the wearer's neck slot for other items, but the wearer loses the circumstance bonus to AC and CMD against attacks and maneuvers targeting the neck or throat.</p>
<h3 id="magic-armor-lifecollar_coat-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/death_ward">death ward</Link>, <Link to="/spell/shield_of_faith">shield of faith</Link>; <strong>Price</strong> 9,200 gp</p>
</>};
const _armor_of_the_pure_legion = {title: "Armor of the Pure Legion", jsx: <><h2 id="magic-armor-armor_of_the_pure_legion-armor-of-the-pure-legion">Armor of the Pure Legion</h2>
<p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 27</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 15th<br/><strong>Slot</strong> armor; <strong>Price</strong> 18,300 gp; <strong>Weight</strong> 30 lbs.</p>
<p>The plates of this suit of +1 <Link to="/eq-armor/steel_lamellar">steel lamellar</Link> armor are etched with the complete Laws of Man from the secular nation of Rahadoum. Suits of armor of the Pure Legion are created for high-ranking members in the eponymous organization and grant protection against the two most common scourges of Rahadoum: divine magic and desert heat. Such armor grants its wearer spell resistance against divine spells equal to 5 + the wearer's base attack bonus. It also protects the wearer from <Link to="/rule/heat_dangers">heat dangers</Link> as if she were affected by a continuous <em>endure elements</em> spell. Additionally, once per day when the wearer of a suit of armor of the Pure Legion fails a Will save against a mind-affecting spell cast by a divine spellcaster, she can attempt another save as a free action on the following round to end the spell.</p>
<h3 id="magic-armor-armor_of_the_pure_legion-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/endure_elements">endure elements</Link>, <Link to="/spell/mind_blank">mind blank</Link>; <strong>Price</strong> 9,300 gp</p>
</>};
const _hide_of_the_dragonrider = {title: "Hide of the Dragonrider", jsx: <><h2 id="magic-armor-hide_of_the_dragonrider-hide-of-the-dragonrider">Hide of the Dragonrider</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_70_the_frozen_stars">Pathfinder #70: The Frozen Stars pg. 63</Link><br/><strong>Aura</strong> moderate abjuration and enchantment; <strong>CL</strong> 8th<br/><strong>Slot</strong> armor; <strong>Price</strong> 18,480 gp; <strong>Weight</strong> 25 lbs.</p>
<p>Crafted from the scaled hide of a <Link to="/family/black_dragon">black dragon</Link> and lined with <Link to="/monster/wolliped">wolliped</Link> fur for warmth, this suit of +1 <Link to="/magic-enh/bolstering">bolstering</Link> black <Link to="/eq-material/dragonhide">dragonhide</Link> armor was designed to protect and aid dragonriders of the Dragon Legion in their battles against the evil dragons of the Drakelands. Hide of the dragonrider grants its wearer a +5 competence bonus on <Link to="/skill/ride">Ride</Link> checks, and the wearer does not take an armor penalty from the armor on Ride checks. In addition, when mounted, the wearer can transfer some or all of the armor's armor bonus (including its enhancement bonus) to his mount as a bonus that stacks with all others. As a free action at the start of his turn, the wearer chooses how to allocate the armor's armor bonus, and that allocation lasts until the wearer's next turn. Once per day, the wearer can imbue hide of the dragonrider with resistance against one type of energy, as the energy resistance armor special ability. This resistance lasts for 10 minutes. Hide of the dragonrider functions as a <Link to="/eq-misc/cold_weather_outfit">cold weather outfit</Link>, granting its wearer a +5 circumstance bonus on Fortitude saves against the effects of cold weather.</p>
<h3 id="magic-armor-hide_of_the_dragonrider-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/heroism">heroism</Link>, <Link to="/spell/resist_energy">resist energy</Link>, <Link to="/spell/shield">shield</Link> or <Link to="/spell/shield_of_faith">shield of faith</Link>, creator must have 5 ranks in the Ride skill; <strong>Price</strong> 9,405 gp</p>
</>};
const _arboreal_armor = {title: "Arboreal Armor", jsx: <><h2 id="magic-armor-arboreal_armor-arboreal-armor">Arboreal Armor</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_wild">Heroes of the Wild pg. 28</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> armor; <strong>Price</strong> 18,670 gp; <strong>Weight</strong> 25 lbs.</p>
<p>The oaken plates of this +1 <Link to="/magic-enh/wild">wild</Link> <Link to="/eq-armor/wooden">wooden</Link> armor are rough with untreated bark. The wearer can activate the armor with a command word, causing her flesh to become tree-like in appearance and resilience. This grants the wearer a +4 enhancement bonus to her existing natural armor bonus and removes her need to breathe, but reduces her speed by half and imposes a -2 penalty on Reflex saves. This effect remains until dismissed as a free action. The wearer can use this ability for up to 10 rounds per day, though the rounds need not be consecutive.</p>
<h3 id="magic-armor-arboreal_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/baleful_polymorph">baleful polymorph</Link>, <Link to="/spell/barkskin">barkskin</Link>; <strong>Price</strong> 9,420 gp</p>
</>};
const _banded_mail_of_luck = {title: "Banded Mail of Luck", jsx: <><h2 id="magic-armor-banded_mail_of_luck-banded-mail-of-luck">Banded Mail of Luck</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 124</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 464</Link><br/><strong>Aura</strong> strong enchantment; <strong>CL</strong> 12th<br/><strong>Slot</strong> armor; <strong>Price</strong> 18,900 gp; <strong>Weight</strong> 35 lbs.</p>
<p>Ten 100-gp gems adorn this +3 <Link to="/eq-armor/banded_mail">banded mail</Link>. Once per week, the armor allows its wearer to require that an attack roll made against him be rerolled. He must take whatever consequences come from the second roll. The wearer's player must decide whether to have the attack roll rerolled before damage is rolled.</p>
<h3 id="magic-armor-banded_mail_of_luck-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/bless">bless</Link>; <strong>Price</strong> 9,650 gp</p>
</>};
const _catskin_leather = {title: "Catskin Leather", jsx: <><h2 id="magic-armor-catskin_leather-catskin-leather">Catskin Leather</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 125</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 13th<br/><strong>Slot</strong> armor; <strong>Price</strong> 18,910 gp; <strong>Weight</strong> 15 lbs.</p>
<p>Rather than the hide of a cat, this extremely supple suit of jet-black +1 <Link to="/magic-enh/shadow">shadow</Link> <Link to="/eq-armor/leather">leather</Link> armor grants a portion of the grace and fortune of a feline. It has no armor check penalty or maximum Dexterity bonus. The wearer receives a +5 competence bonus on Acrobatics checks and takes only half normal damage from falling. When the wearer's hit points would be reduced to a negative amount equal to her Constitution score from an attack or spell, the armor falls to pieces and is destroyed, and the wearer takes only half damage from the attack or spell.</p>
<h3 id="magic-armor-catskin_leather-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/cats_grace">cat's grace</Link>, <Link to="/spell/feather_fall">feather fall</Link>, and <Link to="/spell/limited_wish">limited wish</Link>, <Link to="/spell/wish">wish</Link>, or <Link to="/spell/miracle">miracle</Link>; <strong>Price</strong> 9,535 gp</p>
</>};
const _infiltrators_mail = {title: "Infiltrator's Mail", jsx: <><h2 id="magic-armor-infiltrators_mail-infiltrators-mail">Infiltrator's Mail</h2>
<p><strong>Sources</strong> <Link to="/source/magical_marketplace">Magical Marketplace pg. 7</Link><br/><strong>Aura</strong> moderate transmutation (see text); <strong>CL</strong> 7th<br/><strong>Slot</strong> armor; <strong>Price</strong> 19,650 gp; <strong>Weight</strong> 30 lbs.</p>
<p>This dull black suit of +2 <Link to="/eq-armor/scale_mail">scale mail</Link> does not impose an armor check penalty on the wearer's Stealth checks, though other armor check penalties apply as normal. Additionally, infiltrator's mail reacts to <Link to="/spell/detect_magic">detect magic</Link> as though it were nonmagical and, when worn, extends this effect to all other magic items worn or held by the wearer unless the viewer uses <Link to="/spell/identify">identify</Link> or a similar effect while examining the items.</p>
<h3 id="magic-armor-infiltrators_mail-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/cats_grace">cat's grace</Link>, <Link to="/spell/magic_aura">magic aura</Link>; <strong>Price</strong> 13,650 gp</p>
</>};
const _ursine_rageskin = {title: "Ursine Rageskin", jsx: <><h2 id="magic-armor-ursine_rageskin-ursine-rageskin">Ursine Rageskin</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 214</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> armor; <strong>Price</strong> 20,165 gp; <strong>Weight</strong> 25 lbs.</p>
<p>This +1 <Link to="/eq-armor/hide">hide</Link> armor is stitched together from grizzly bear hides. When the wearer rages, she automatically turns into a Large brown bear, as if using <Link to="/umr/change_shape">change shape</Link> <em>(beast shape II).</em> The armor melds with her new form as normal, but the armor's enhancement bonus changes into a +1 enhancement bonus to her natural armor. When the rage ends, the wearer reverts to her own form.</p>
<h3 id="magic-armor-ursine_rageskin-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/beast_shape_ii">beast shape II</Link>; <strong>Price</strong> 10,165 gp</p>
</>};
const _the_forbidden_name = {title: "The Forbidden Name", jsx: <><h2 id="magic-armor-the_forbidden_name-the-forbidden-name">The Forbidden Name</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_113_what_grows_within">Pathfinder #113: What Grows Within pg. 42</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> armor; <strong>Price</strong> 20,175 gp; <strong>Weight</strong> 20 lbs.</p>
<p>Each of the yellow ribbons that spill from the joints of this jaundiced suit of +3 <Link to="/eq-armor/studded_leather">studded leather</Link> armor bears one or more haunting runes. Three times per day, a cleric (or other class with cleric domains) with the Rune domain can use her blast rune domain power to mark one of the ribbons rather than a square. Such blast runes last until the next time the cleric prepares spells and cannot benefit from other domain abilities such as spell rune. As a swift action while wearing this armor, the cleric can cause one of the ribbons to lash out and touch an adjacent creature, triggering the blast rune as if the target had entered the warded square. When marking a ribbon with a blast rune, the cleric can instead expend two daily uses of The Forbidden Name's ability to also apply the benefits of another Rune domain (or subdomain) power such as spell rune or warding rune to the blast rune.</p>
<p>Alternatively, any wearer can expend two daily uses when casting <em>glyph of warding</em> or <Link to="/spell/explosive_runes">explosive runes</Link> - or three uses when casting greater <em>glyph of warding</em> - on a ribbon to treat it much like a blast rune. As a swift action while wearing the armor, she can trigger the glyph as though she had stepped on it; however, she takes half damage from the effect on a failed Reflex saving throw or no damage if successful.</p>
<h3 id="magic-armor-the_forbidden_name-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/glyph_of_warding">glyph of warding</Link>, <Link to="/spell/secret_page">secret page</Link>, creator must possess the <Link to="/domain/rune">Rune</Link> domain; <strong>Price</strong> 10,175 gp</p>
</>};
const _howling_skull_armor = {title: "Howling Skull Armor", jsx: <><h2 id="magic-armor-howling_skull_armor-howling-skull-armor">Howling Skull Armor</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_59_the_price_of_infamy">Pathfinder #59: The Price of Infamy pg. 60</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 7th<br/><strong>Slot</strong> armor; <strong>Price</strong> 20,375 gp; <strong>Weight</strong> 20 lbs.</p>
<p>This suit of +3 <Link to="/eq-armor/studded_leather">studded leather</Link> armor is decorated with metal skulls. Once per day as a standard action, the wearer can command the skulls to unleash a cacophonous chorus of howls, causing all creatures within a 30-foot <Link to="/misc/spread">spread</Link> to make a DC 16 Will save to avoid becoming <Link to="/misc/frightened">frightened</Link> for 1d4 rounds. The wearer can choose up to three targets (plus himself) in the area of effect to be exempt from the effect. The wearer of a suit of howling skull armor gains a +4 bonus on all saving throws against fear effects. Each time the wearer of howling skull armor succeeds at a saving throw against a fear effect created by someone other than himself, he gains a +2 bonus on Will saves for 1 round.</p>
<h3 id="magic-armor-howling_skull_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/fear">fear</Link>; <strong>Price</strong> 10,275 gp</p>
</>};
const _do_maru_of_broken_flesh = {title: "Do-Maru of Broken Flesh", jsx: <><h2 id="magic-armor-do_maru_of_broken_flesh-do-maru-of-broken-flesh">Do-Maru of Broken Flesh</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_52_forest_of_spirits">Pathfinder #52: Forest of Spirits pg. 60</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 9th<br/><strong>Slot</strong> armor; <strong>Price</strong> 20,550 gp; <strong>Weight</strong> 30 lbs.</p>
<p>Once per day as a standard action, the wearer of this +2 <Link to="/eq-armor/do_maru">do-maru</Link> armor can activate the armor to heal 4d8+9 points of damage and end any and all of the following conditions affecting the wearer: <Link to="/rule/ability_damage">ability damage</Link>, blinded, confused, dazzled, deafened, diseased, exhausted, fatigued, nauseated, poisoned, and sickened. In addition, this effect functions as <Link to="/spell/break_enchantment">break enchantment</Link> upon a single additional effect of the wearer's choice that is affecting the wearer and that can be legally affected by this effect. Such healing, however, comes at a cost. The do-maru of broken flesh creates vivid, ugly scars on the wearer, who takes 1d4 points of <Link to="/rule/charisma_damage">Charisma damage</Link> each time this ability is used.</p>
<p>Do-maru is medium armor that provides a +5 armor bonus. The armor has an arcane spell failure chance of 25%, a maximum Dexterity bonus of +4, and an armor check penalty of -4. Do-maru costs 200 gp and weighs 30 lbs.</p>
<h3 id="magic-armor-do_maru_of_broken_flesh-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/cleanse">cleanse</Link>; <strong>Price</strong> 10,450 gp</p>
</>};
const _raiment_of_the_shining_crusade = {title: "Raiment of the Shining Crusade", jsx: <><h2 id="magic-armor-raiment_of_the_shining_crusade-raiment-of-the-shining-crusade">Raiment of the Shining Crusade</h2>
<p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 29</Link><br/><strong>Aura</strong> moderate abjuration and evocation; <strong>CL</strong> 7th<br/><strong>Slot</strong> armor; <strong>Price</strong> 20,750 gp; <strong>Weight</strong> 50 lbs.</p>
<p>This +1 <Link to="/eq-armor/half_plate">half-plate</Link> is emblazoned with holy script and religious iconography. Raiment of the shining crusade was first crafted by the holy warriors serving under General Arnisant. The wearer of raiment of the shining crusade gains a +2 sacred bonus on saving throws against <Link to="/ability/channel_negative_energy">channeled negative energy</Link> and to resist <Link to="/rule/negative_levels">negative levels</Link>. When worn by a character with the smite evil class feature, the armor sheds light like a torch at all times.</p>
<p>A wearer with the smite evil class feature can expend one use of this ability as an immediate action to create a defensive ward around an adjacent creature, granting the target a deflection bonus to AC and a resistance bonus on saves equal to the wearer's Charisma bonus against attacks and effects originating from creatures with an evil alignment. This effect lasts for 1 round.</p>
<h3 id="magic-armor-raiment_of_the_shining_crusade-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/holy_smite">holy smite</Link>, <Link to="/spell/protection_from_evil">protection from evil</Link>; <strong>Price</strong> 10,750 gp</p>
</>};
const _war_commanders_field_plate = {title: "War Commander's Field Plate", jsx: <><h2 id="magic-armor-war_commanders_field_plate-war-commanders-field-plate">War Commander's Field Plate</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 53</Link><br/><strong>Aura</strong> moderate abjuration and enchantment; <strong>CL</strong> 6th<br/><strong>Slot</strong> armor; <strong>Price</strong> 21,600 gp; <strong>Weight</strong> 50 lbs.</p>
<p>This immaculate +2 <Link to="/magic-enh/champion">champion</Link> <Link to="/eq-armor/field_plate">field plate</Link> is commonly used by military commanders in Lastwall, Mendev, and Taldor. A sturdy metal bracket is built onto the back of the armor, located just under the shoulder blades; if the wielder has personal heraldry, this slot can hold a banner or flag bearing that heraldry (such as a <Link to="/class/cavalier">cavalier's</Link> banner).</p>
<p>If the wearer of the war commander's field plate takes to the battlefield as an army commander, he gains the Hold the Line <Link to="/rule/boons">boon</Link> if he prominently displays his heraldry. If the wearer already possesses this boon, he instead gains an additional +1 bonus on Morale checks as army commander.</p>
<h3 id="magic-armor-war_commanders_field_plate-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/heroism">heroism</Link>, <Link to="/spell/protection_from_evil">protection from evil</Link>; <strong>Price</strong> 11,475 gp</p>
</>};
const _armor_of_fragmenting_stone = {title: "Armor of Fragmenting Stone", jsx: <><h2 id="magic-armor-armor_of_fragmenting_stone-armor-of-fragmenting-stone">Armor of Fragmenting Stone</h2>
<p><strong>Sources</strong> <Link to="/source/monster_summoners_handbook">Monster Summoner's Handbook pg. 20</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> armor; <strong>Price</strong> 21,650 gp; <strong>Weight</strong> 60 lbs.</p>
<p>This imposing suit of armor, first forged by Jistkan elemental binders, is covered in large, jagged stones and functions as +2 <Link to="/eq-armor/full_plate">full plate</Link>. Once per day as an immediate action, when a bludgeoning or slashing attack strikes the wearer, the wearer can will a chunk of the stone to break off, summoning a Medium earth elemental as <em>summon monster IV.</em> The elemental fights as the wearer directs (and understands the wearer, even if the two do not share a language) for 7 rounds, or until it is destroyed.</p>
<h3 id="magic-armor-armor_of_fragmenting_stone-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/summon_monster_iv">summon monster IV</Link> or <Link to="/spell/summon_natures_ally_iv">summon nature's ally IV</Link>, creator must have visited the Elemental Plane of Earth; <strong>Price</strong> 11,650 gp</p>
</>};
const _gug_hide = {title: "Gug Hide", jsx: <><h2 id="magic-armor-gug_hide-gug-hide">Gug Hide</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 47</Link><br/><strong>Aura</strong> strong abjuration and transmutation; <strong>CL</strong> 13th<br/><strong>Slot</strong> armor; <strong>Price</strong> 22,165 gp; <strong>Weight</strong> 25 lbs.</p>
<p>This grotesque suit of +1 <Link to="/eq-armor/hide">hide</Link> armor is stitched together from the hides of <Link to="/monster/gug">gugs</Link> from the underworld of the <Link to="/rule/dreamlands">Dreamlands</Link> and the nightmare realm of <Link to="/rule/leng">Leng</Link>. The wearer of a suit of gug hide gains the benefits of Leng's <Link to="/feat/planar_infusion">basic infusion</Link> when in an underground environment. Once per day as a standard action, the wearer can cause his arms to each split into two arms at the elbow, each bearing a furred hand like that of a horrid subterranean gug. The wearer must designate one hand as his primary hand; all others are considered off hands. He can use any of his hands for other purposes that require free hands. A user who has <Link to="/feat/two_weapon_fighting">Two Weapon Fighting</Link> is treated as if he had <Link to="/feat/multiweapon_fighting">Multiweapon Fighting</Link> while these extra arms are activated. This ability lasts for 10 minutes and has no effect if the wearer already has more than two arms.</p>
<h3 id="magic-armor-gug_hide-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/alter_self">alter self</Link>, <Link to="/spell/limited_wish">limited wish</Link>; <strong>Price</strong> 11,165 gp</p>
</>};
const _stalwart_breastplate = {title: "Stalwart Breastplate", jsx: <><h2 id="magic-armor-stalwart_breastplate-stalwart-breastplate">Stalwart Breastplate</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 143</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 13th<br/><strong>Slot</strong> armor; <strong>Price</strong> 22,350 gp; <strong>Weight</strong> 40 lbs.</p>
<p>The burden of this weighty +1 <Link to="/magic-enh/light_fortification">light fortification</Link> <Link to="/eq-armor/breastplate">breastplate</Link> gives it an armor check penalty of -5. As an immediate action, the wearer can negate the effects of a successful combat maneuver made to <Link to="/rule/bull_rush">bull rush</Link>, <Link to="/rule/overrun">overrun</Link>, or <Link to="/rule/trip">trip</Link> her. As a swift action, the wearer can expend one use of mythic power to gain immunity to <Link to="/rule/ability_damage_drain">ability damage, ability drain</Link>, critical hits, and <Link to="/ability/sneak_attack">sneak attacks</Link>. This effect lasts for 1 round per mythic tier the wearer possesses.</p>
<h3 id="magic-armor-stalwart_breastplate-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/spell/iron_body">iron body</Link>, either <Link to="/spell/limited_wish">limited wish</Link> or <Link to="/spell/miracle">miracle</Link>; <strong>Price</strong> 11,350 gp</p>
</>};
const _celestial_armor = {title: "Celestial Armor", jsx: <><h2 id="magic-armor-celestial_armor-celestial-armor">Celestial Armor</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 125</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 464</Link><br/><strong>Aura</strong> faint transmutation [good]; <strong>CL</strong> 5th<br/><strong>Slot</strong> armor; <strong>Price</strong> 22,400 gp; <strong>Weight</strong> 20 lbs.</p>
<p>This +3 <Link to="/eq-armor/chainmail">chainmail</Link> is so fine and light that it can be worn under normal clothing without betraying its presence. It has a maximum Dexterity bonus of +8, an armor check penalty of -2, and an arcane spell failure chance of 15%. It is considered light armor and allows the wearer to use <em>fly</em> on command (as the spell) once per day.</p>
<h3 id="magic-armor-celestial_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/fly">fly</Link>, creator must be good; <strong>Price</strong> 11,350 gp</p>
</>};
const _deaths_preservation_banded_mail = {title: "Death's Preservation Banded Mail", jsx: <><h2 id="magic-armor-deaths_preservation_banded_mail-deaths-preservation-banded-mail">Death's Preservation Banded Mail</h2>
<p><strong>Sources</strong> <Link to="/source/dragonslayers_handbook">Dragonslayer's Handbook pg. 30</Link></p>
<p><strong>Aura</strong> strong conjuration and divination; <strong>CL</strong> 18th<br/><strong>Slot</strong> armor; <strong>Price</strong> 22,400 gp; <strong>Weight</strong> 35 lbs.</p>
<p>This +2 <Link to="/magic-enh/light_fortification">light fortification</Link> <Link to="/eq-armor/banded_mail">banded mail</Link> has a small, ovoid stone set in the left shoulder. The armor monitors the wearer's hit point total as the spell <Link to="/spell/status">status</Link>. If an attack against the wearer does enough damage to kill him outright, he and his gear are teleported to a specific location determined at the time of the armor's creation. This effect acts in all other ways as the spell <em>word of recall,</em> with the predetermined location considered the place of sanctuary. The wearer's body is protected from decomposition for 18 days as per the <em>gentle repose</em> spell. Once this ability has been used, the stone set into the armor crumbles to dust and the armor reverts to being a suit of +2 light fortification banded mail.</p>
<h3 id="magic-armor-deaths_preservation_banded_mail-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/contingency">contingency</Link>, <Link to="/spell/gentle_repose">gentle repose</Link>, <Link to="/spell/limited_wish">limited wish</Link> or <Link to="/spell/miracle">miracle</Link>, <Link to="/spell/word_of_recall">word of recall</Link>; <strong>Price</strong> 11,200 gp</p>
</>};
const _armigers_armor = {title: "Armiger's Armor", jsx: <><h2 id="magic-armor-armigers_armor-armigers-armor">Armiger's Armor</h2>
<p><strong>Sources</strong> <Link to="/source/melee_tactics_toolbox">Melee Tactics Toolbox pg. 22</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 13th<br/><strong>Slot</strong> armor; <strong>Price</strong> 22,500 gp; <strong>Weight</strong> 50 lbs.</p>
<p>This +1 <Link to="/eq-material/adamantine">adamantine</Link> <Link to="/magic-enh/light_fortification">light fortification</Link> <Link to="/eq-armor/full_plate">full plate</Link> is crafted from tightly fitted smooth, dull plates trimmed in gold. As adamantine heavy armor, it grants its wearer DR 3/-. When the armor is not worn, a creature can touch the armor and speak a command word to cause the armor to leap up and fit itself to that creature. The armor is considered properly donned when put on in this way. The wearer can speak the command word to have the armor remove itself and, if not restrained, stack itself neatly nearby or arrange itself on an appropriate armor rack, if one is adjacent.</p>
<h3 id="magic-armor-armigers_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/animate_objects">animate objects</Link>, <Link to="/spell/limited_wish">limited wish</Link> or <Link to="/spell/miracle">miracle</Link>, creator must be proficient with heavy armor; <strong>Price</strong> 19,500 gp</p>
</>};
const _ghost_mirror_armor = {title: "Ghost Mirror Armor", jsx: <><h2 id="magic-armor-ghost_mirror_armor-ghost-mirror-armor">Ghost Mirror Armor</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_51_the_hungry_storm">Pathfinder #51: The Hungry Storm pg. 62</Link><br/><strong>Aura</strong> strong abjuration and transmutation; <strong>CL</strong> 15th<br/><strong>Slot</strong> armor; <strong>Price</strong> 22,675 gp; <strong>Weight</strong> 45 lbs.</p>
<p>Crafted by Uqtaal spirit-shamans, this ancient +1 <Link to="/magic-enh/ghost_touch_a">ghost touch</Link> <Link to="/eq-armor/four_mirror">four-mirror armor</Link> consists of four polished steel plates harnessed together with leather shoulder straps. Two round plates protect the wearer's front and back, while two smaller rectangular plates cover the sides of the torso. The wearer of ghost mirror armor can cast <em>deathwatch</em> (caster level 1st) three times per day. In addition, when the wearer is attacked by an incorporeal undead creature, the armor automatically casts <em>protection from evil</em> on the wearer as an immediate action up to once per day.</p>
<h3 id="magic-armor-ghost_mirror_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/deathwatch">deathwatch</Link>, <Link to="/spell/etherealness">etherealness</Link>, <Link to="/spell/protection_from_evil">protection from evil</Link>; <strong>Price</strong> 11,435 gp</p>
</>};
const _armor_of_the_pious = {title: "Armor of the Pious", jsx: <><h2 id="magic-armor-armor_of_the_pious-armor-of-the-pious">Armor of the Pious</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_74_sword_of_valor">Pathfinder #74: Sword of Valor pg. 62</Link><br/><strong>Aura</strong> moderate abjuration [good]; <strong>CL</strong> 9th<br/><strong>Slot</strong> armor; <strong>Price</strong> 23,300 gp; <strong>Weight</strong> 25 lbs.</p>
<p>This gold-plated +1 <Link to="/eq-material/mithral">mithral</Link> <Link to="/eq-armor/full_plate">full plate</Link> armor has images of <Link to="/faith/iomedae">Iomedae's</Link> symbol etched into its immaculately gleaming surface. The armor requires 24 hours to attune itself to the wearer and her patron deity, after which point the images on the armor shift to match the symbol of the wearer's patron deity (or remain associated with Iomedae if the wearer doesn't worship a deity). Thereafter, once per day the armor's wearer can offer a <em>prayer</em> to her deity (or Iomedae) as a swift action to increase the armor's enhancement bonus to +2 for 10 rounds. For this duration, the armor also grants a +2 sacred bonus on saving throws. A paladin wearing armor of the pious can use her <Link to="/ability/lay_on_hands">lay on hands</Link> ability one additional time per day; a mythic paladin wearing armor of the pious also gains one additional use of mythic power per day. An evil character who wears armor of the pious gains 2 <Link to="/rule/negative_levels">negative levels</Link>. These negative levels remain as long as the armor is worn and disappear when the armor is removed - they never become permanent but can't be overcome in any way as long as the armor is worn.</p>
<h3 id="magic-armor-armor_of_the_pious-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/prayer">prayer</Link>, <Link to="/spell/sanctify_armor">sanctify armor</Link>; <strong>Price</strong> 16,900 gp</p>
</>};
const _goblin_plate_goblin = {title: "Goblin Plate (Goblin)", jsx: <><h2 id="magic-armor-goblin_plate_goblin-goblin-plate-goblin">Goblin Plate (Goblin)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 224</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 5th<br/><strong>Slot</strong> armor; <strong>Price</strong> 23,650 gp; <strong>Weight</strong> 25 lbs.</p>
<blockquote>
<p><em>The following suit of armor is generally available only to members of the indicated race or ethnicity.</em></p>
</blockquote>
<p>Normally found sized for Small humanoids, this battered and rusted suit of +1 <Link to="/magic-enh/fire_resistance">fire resistance</Link> <Link to="/eq-armor/full_plate">full plate</Link> resists any attempts to polish out its blemishes. When a critical hit is confirmed against the wearer with a manufactured weapon, natural weapon, or unarmed strike, there is a 50% chance that the armor negates the critical hit. Such a blow knocks the armor out of alignment, giving it the <Link to="/misc/broken">broken</Link> condition until the wearer spends 1d4+1 minutes refitting the pieces (or 1 minute if another person assists in the process). This does not otherwise harm the armor. While out of alignment, the goblin plate cannot negate critical hits. Broken armor provides only half the usual AC bonus (rounded down), and any armor check penalty is doubled.</p>
<h3 id="magic-armor-goblin_plate_goblin-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/resist_energy">resist energy</Link>, <Link to="/spell/shatter">shatter</Link>, creator must be a goblin; <strong>Price</strong> 12,650 gp</p>
</>};
const _buccaneers_breastplate = {title: "Buccaneer's Breastplate", jsx: <><h2 id="magic-armor-buccaneers_breastplate-buccaneers-breastplate">Buccaneer's Breastplate</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 124</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 284</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> armor; <strong>Price</strong> 23,850 gp; <strong>Weight</strong> 30 lbs.</p>
<p>This +1 <Link to="/eq-armor/breastplate">breastplate</Link> is made of shining amber metal and decorated with faint motifs of the waves and water. It allows the wearer to continually utilize the effects of the spell <em>water walk.</em> If a creature puts on the armor while underwater, the wearer is borne toward the surface at a rate of 60 feet per round.</p>
<h3 id="magic-armor-buccaneers_breastplate-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/water_walk">water walk</Link>; <strong>Price</strong> 12,100 gp</p>
</>};
const _dragonform_armor = {title: "Dragonform Armor", jsx: <><h2 id="magic-armor-dragonform_armor-dragonform-armor">Dragonform Armor</h2>
<p><strong>Sources</strong> <Link to="/source/dragonslayers_handbook">Dragonslayer's Handbook pg. 30</Link></p>
<p><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 11th<br/><strong>Slot</strong> armor; <strong>Price</strong> 24,120 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This +1 <Link to="/eq-armor/leather">leather</Link> armor is the same color as the dragon type with which it is associated and has been worked to resemble dragon hide. Once per day the wearer can speak the command word and transform into the associated dragon type as the <em>form of the dragon I</em> spell. This effect lasts 11 minutes.</p>
<h3 id="magic-armor-dragonform_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/form_of_the_dragon_i">form of the dragon I</Link>; <strong>Price</strong> 12,060 gp</p>
</>};
const _purgatorys_cowl = {title: "Purgatory's Cowl", jsx: <><h2 id="magic-armor-purgatorys_cowl-purgatorys-cowl">Purgatory's Cowl</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 47</Link><br/><strong>Aura</strong> moderate abjuration and necromancy; <strong>CL</strong> 11th<br/><strong>Slot</strong> armor; <strong>Price</strong> 24,175 gp; <strong>Weight</strong> 30 lbs.</p>
<p>This tattered suit of +1 <Link to="/magic-enh/deathless">deathless</Link> <Link to="/eq-armor/studded_leather">studded leather</Link> has a black leather hood attached to the neck. Although the face of the hood is open and doesn't impair the wearer's senses, the wearer's face is always hidden in deep shadow regardless of the ambient light level. Once per day as an immediate action, when the wearer reduces an undead creature to 0 or fewer hit points, the wearer can draw upon the departed creature's essence to gain treat her level as 2 higher spells and spell-like abilities with the death descriptor and spells and spell-like abilities from the <Link to="/domain/death">Death</Link> and <Link to="/domain/repose">Repose</Link> domains. This effect lasts for 1 hour.</p>
<h3 id="magic-armor-purgatorys_cowl-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/death_ward">death ward</Link>, <Link to="/spell/undeath_to_death">undeath to death</Link>; <strong>Price</strong> 12,175 gp</p>
</>};
const _aldori_dueling_armor = {title: "Aldori Dueling Armor", jsx: <><h2 id="magic-armor-aldori_dueling_armor-aldori-dueling-armor">Aldori Dueling Armor</h2>
<p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 27</Link><br/><strong>Aura</strong> moderate illusion and transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> armor; <strong>Price</strong> 24,200 gp; <strong>Weight</strong> 20 lbs.</p>
<p>These +2 <Link to="/eq-armor/armored_coat">armored coats</Link> are traditionally worn by the Aldori swordlords of Brevoy. The wearer of this armor gains a +2 enhancement bonus on initiative checks and a +2 circumstance bonus on attacks of opportunity if the attacks are made with an <Link to="/eq-weapon/aldori_dueling_sword">Aldori dueling sword</Link>. Once per day when the wearer of Aldori dueling armor is the target of a melee attack, she can make an attack with an Aldori dueling sword as an immediate action. If the result of her attack roll is higher than that of her attacker, the wearer of Aldori dueling armor parries the attack and takes no damage.</p>
<h3 id="magic-armor-aldori_dueling_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/cats_grace">cat's grace</Link>, <Link to="/spell/symbol_of_striking">symbol of striking</Link>; <strong>Price</strong> 12,200 gp</p>
</>};
const _plate_armor_of_the_deep = {title: "Plate Armor of the Deep", jsx: <><h2 id="magic-armor-plate_armor_of_the_deep-plate-armor-of-the-deep">Plate Armor of the Deep</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 128</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 464</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 11th<br/><strong>Slot</strong> armor; <strong>Price</strong> 24,650 gp; <strong>Weight</strong> 50 lbs.</p>
<p>This +1 <Link to="/eq-armor/full_plate">full plate</Link> is decorated with a wave and fish motif and often has tiny fins and scales worked into the design. Although the armor remains as heavy and bulky as normal full plate, the wearer of plate armor of the deep is treated as unarmored for purposes of Swim checks. The wearer can breathe underwater and can converse with any waterbreathing creature with a language.</p>
<h3 id="magic-armor-plate_armor_of_the_deep-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/freedom_of_movement">freedom of movement</Link>, <Link to="/spell/tongues">tongues</Link>, <Link to="/spell/water_breathing">water breathing</Link>; <strong>Price</strong> 13,150 gp</p>
</>};
const _suit_of_inverted_jade = {title: "Suit of Inverted Jade", jsx: <><h2 id="magic-armor-suit_of_inverted_jade-suit-of-inverted-jade">Suit of Inverted Jade</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_139_the_dead_road">Pathfinder #139: The Dead Road pg. 70</Link><br/><strong>Aura</strong> strong necromancy; <strong>CL</strong> 14th<br/><strong>Slot</strong> armor; <strong>Price</strong> 25,000 gp; <strong>Weight</strong> 50 lbs.</p>
<p>Originating in ancient Minkai, the typical jade burial suit consists of several hundred jade plaques joined with gold wire, carefully inscribed with prayers to <Link to="/faith/tsukiyo">Tsukiyo</Link>, the Tian-Min god of the moon, spirits, and preservation. Jade is believed to have preservative properties, and many ancient Tian royals were buried in jade suits.</p>
<p>By disassembling and inverting the plaques and replacing Tsukiyo's name with that of his brother <Link to="/faith/fumeiyoshi">Fumeiyoshi</Link>, god of graves, one clever ru-shi learned how to give the impression of death instead of life. A character wearing a suit of inverted jade gains a +3 profane bonus on saving throws against disease, mind-affecting effects, poison, sleep, and stunning. The wearer has the aura of an undead for the purposes of divination spells and effects, and unintelligent undead perceive the wearer as a fellow undead. The wearer, however, becomes vulnerable to effects that target or deal additional damage to undead (such as <Link to="/spell/searing_light">searing light</Link>). A suit of inverted jade otherwise functions as +3 <Link to="/eq-armor/stone_lamellar">stone lamellar</Link>.</p>
<h3 id="magic-armor-suit_of_inverted_jade-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/undead_anatomy_ii">undead anatomy II</Link>; <strong>Price</strong> 12,500 gp</p>
</>};
const _spiritwalk_armor = {title: "Spiritwalk Armor", jsx: <><h2 id="magic-armor-spiritwalk_armor-spiritwalk-armor">Spiritwalk Armor</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 142</Link><br/><strong>Aura</strong> strong illusion and transmutation; <strong>CL</strong> 11th<br/><strong>Slot</strong> armor; <strong>Price</strong> 25,160 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This +2 <Link to="/magic-enh/improved_shadow">improved shadow</Link> <Link to="/eq-armor/leather">leather</Link> armor is attractive, yet eerie. It grants its wearer the ability to use <em>vanish</em> as a <Link to="/feat/quickened">quickened</Link> spell-like ability five times per day. If a mythic wearer uses the <em>vanish</em> ability, he can expend one use of mythic power to also make himself incorporeal for 1 round.</p>
<h3 id="magic-armor-spiritwalk_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/spell/vanish">vanish</Link>, <Link to="/spell/ethereal_jaunt">ethereal jaunt</Link>; <strong>Price</strong> 12,660 gp</p>
</>};
const _breastplate_of_command = {title: "Breastplate of Command", jsx: <><h2 id="magic-armor-breastplate_of_command-breastplate-of-command">Breastplate of Command</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 124</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 464</Link><br/><strong>Aura</strong> strong enchantment; <strong>CL</strong> 15th<br/><strong>Slot</strong> armor; <strong>Price</strong> 25,400 gp; <strong>Weight</strong> 30 lbs.</p>
<p>This +2 <Link to="/eq-armor/breastplate">breastplate</Link> typically bears the image of a rampant grizzly bear or other impressive predator. It bestows a commanding aura upon its wearer. The wearer gains a +2 competence bonus on all Charisma checks, including Charisma-based skill checks. The wearer also gains a +2 competence bonus to his <Link to="/feat/leadership">Leadership</Link> score. Friendly troops within 360 feet of the user become braver than normal, gaining a +2 resistance bonus on saving throws against fear. Since the effect arises in great part from the distinctiveness of the armor, it does not function if the wearer hides or conceals herself in any way.</p>
<h3 id="magic-armor-breastplate_of_command-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/mass_charm_monster">mass charm monster</Link>; <strong>Price</strong> 12,875 gp</p>
</>};
const _forsaken_banded_mail = {title: "Forsaken Banded Mail", jsx: <><h2 id="magic-armor-forsaken_banded_mail-forsaken-banded-mail">Forsaken Banded Mail</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 126</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 284</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 11th<br/><strong>Slot</strong> armor; <strong>Price</strong> 25,400 gp; <strong>Weight</strong> 35 lbs.</p>
<p>A massive skull adorns the chest piece of this suit of +1 <Link to="/eq-armor/banded_mail">banded mail</Link>, and smaller gilted images of defaced holy symbols cover the other parts of the armor. The wearer of the armor cannot cast divine spells or use any spell-like supernatural ability gained from a connection to a deity. The wearer gains SR 19 against any divine-origin spell, spell-like ability, or supernatural ability (such as a domain granted power or ability from an outsider serving a deity), and treats the armor's enhancement bonus as +2 higher against creatures with these abilities.</p>
<h3 id="magic-armor-forsaken_banded_mail-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, creator cannot be a divine spellcaster; <strong>Price</strong> 12,900 gp</p>
</>};
const _armor_of_the_tireless_warrior = {title: "Armor of the Tireless Warrior", jsx: <><h2 id="magic-armor-armor_of_the_tireless_warrior-armor-of-the-tireless-warrior">Armor of the Tireless Warrior</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_53_tide_of_honor">Pathfinder #53: Tide of Honor pg. 60</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 9th<br/><strong>Slot</strong> armor; <strong>Price</strong> 25,900 gp; <strong>Weight</strong> 15 lbs.</p>
<p>Crafted by shamans of the Yumogu tribe for their mightiest chieftains, this undecorated +3 <Link to="/eq-armor/leather">leather</Link> armor is made from strips of boiled horsehide. While her enemies tire around her, the wearer of this armor can keep fighting. If the wearer is a <Link to="/class/barbarian">barbarian</Link>, the armor of the tireless warrior allows her to rage for 2 additional rounds per day. Once per day on command, the wearer can cause her enemies to become fatigued, as per the <em>waves of fatigue</em> spell. In addition, once per day, the wearer can draw upon the armor's strength to banish her own weariness. For 10 minutes, the wearer takes no penalties from the fatigued or exhausted conditions. This effect is merely an illusion, however, and when it ends, the wearer takes 1d6 points of nonlethal damage and the condition or conditions return.</p>
<h3 id="magic-armor-armor_of_the_tireless_warrior-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/invigorate">invigorate</Link>, <Link to="/spell/rage">rage</Link>, <Link to="/spell/waves_of_fatigue">waves of fatigue</Link>; <strong>Price</strong> 13,030 gp</p>
</>};
const _mail_of_sly_steps_halfling = {title: "Mail of Sly Steps (Halfling)", jsx: <><h2 id="magic-armor-mail_of_sly_steps_halfling-mail-of-sly-steps-halfling">Mail of Sly Steps (Halfling)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 225</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 6th<br/><strong>Slot</strong> armor; <strong>Price</strong> 25,900 gp; <strong>Weight</strong> 5 lbs.</p>
<blockquote>
<p><em>The following suit of armor is generally available only to members of the indicated race or ethnicity.</em></p>
</blockquote>
<p>Thanks to the unusually light and fine links of this halfling-made +2 <Link to="/eq-armor/chain_shirt">chain shirt</Link>, it imposes no armor check penalty and the wearer's maximum Dexterity bonus is +5. After a melee attack hits the wearer, he can take a 5-foot step as an immediate action, even if he already took a 5-foot step during his turn. Taking such a step does not interfere with the wearer's movement during his next turn. A suit of mail of sly steps is usually sized for Small creatures.</p>
<h3 id="magic-armor-mail_of_sly_steps_halfling-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/expeditious_retreat">expeditious retreat</Link>, creator must be a halfling; <strong>Price</strong> 13,400 gp</p>
</>};
const _mithral_full_plate_of_speed = {title: "Mithral Full Plate of Speed", jsx: <><h2 id="magic-armor-mithral_full_plate_of_speed-mithral-full-plate-of-speed">Mithral Full Plate of Speed</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 128</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 464</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> armor; <strong>Price</strong> 26,500 gp; <strong>Weight</strong> 25 lbs.</p>
<p>As a free action, the wearer of this fine set of +1 <Link to="/eq-material/mithral">mithral</Link> <Link to="/eq-armor/full_plate">full plate</Link> can activate it, enabling him to act as though affected by a <em>haste</em> spell for up to 10 rounds each day. The duration of the <em>haste</em> effect need not be consecutive rounds. The armor has an arcane spell failure chance of 25%, a maximum Dexterity bonus of +3, and an armor check penalty of -3. It is considered medium armor, except that you must be proficient in heavy armor to avoid taking nonproficiency penalties.</p>
<h3 id="magic-armor-mithral_full_plate_of_speed-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/haste">haste</Link>; <strong>Price</strong> 18,500 gp</p>
</>};
const _panoply_of_the_fierani_knight_elf = {title: "Panoply of the Fierani Knight (Elf)", jsx: <><h2 id="magic-armor-panoply_of_the_fierani_knight_elf-panoply-of-the-fierani-knight-elf">Panoply of the Fierani Knight (Elf)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 225</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> armor; <strong>Price</strong> 26,500 gp; <strong>Weight</strong> 25 lbs.</p>
<blockquote>
<p><em>The following suit of armor is generally available only to members of the indicated race or ethnicity.</em></p>
</blockquote>
<p>The sigils etched into this +2 <Link to="/eq-material/mithral">mithral</Link> <Link to="/eq-armor/full_plate">full plate</Link> ward against the manipulations of chaos. Its wearer receives a +2 sacred bonus on saves against the spells and abilities of outsiders with the chaotic subtype and against chaotic spells and spell-like abilities. The armor provides the same protection against environmental effects caused by the taint of chaos, such as the taints found in Tanglebriar and the Worldwound, or even in the Abyss and the Maelstrom.</p>
<h3 id="magic-armor-panoply_of_the_fierani_knight_elf-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/dismissal">dismissal</Link>, <Link to="/spell/magic_circle_against_chaos">magic circle against chaos</Link>, creator must be an elf; <strong>Price</strong> 18,500 gp</p>
</>};
const _tunnel_defender_stoneplate = {title: "Tunnel Defender Stoneplate", jsx: <><h2 id="magic-armor-tunnel_defender_stoneplate-tunnel-defender-stoneplate">Tunnel Defender Stoneplate</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 53</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> armor; <strong>Price</strong> 26,700 gp; <strong>Weight</strong> 75 lbs.</p>
<p>Even bulkier than its nonmagical cousins, this set of +3 <Link to="/eq-armor/stoneplate">stoneplate</Link> is crafted from stones of widely differing colors, and is often allocated to <Link to="/rule/ninth_battalion">Ninth Battalion</Link> soldiers assigned to the deepest and most dangerous of the Darklands' tunnels.</p>
<p>Once per day, the wearer can call forth a <em>wall of stone</em> that fills up to nine contiguous 5-foot squares. Unlike with the standard spell, the wall must be a straight line, and the wielder must choose to occupy one 5-foot section of the wall, as the armor merges with the wall around it. While the <em>wall of stone</em> is in effect, the wearer gains a +2 circumstance bonus to AC, but can move only within the wall. The wearer can dismiss the wall as a standard action; otherwise, it dissipates in 10 rounds.</p>
<p>As a full-round action, the wielder can make the wall permanent by allowing himself to be consumed by the stone. In this case, the wearer can be restored to life only by a <Link to="/spell/miracle">miracle</Link> or <Link to="/spell/wish">wish</Link>.</p>
<h3 id="magic-armor-tunnel_defender_stoneplate-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/meld_into_stone">meld into stone</Link>, <Link to="/spell/wall_of_stone">wall of stone</Link>, creator must be a dwarf; <strong>Price</strong> 14,325 gp</p>
</>};
const _vibrant_frog_hide = {title: "Vibrant Frog Hide", jsx: <><h2 id="magic-armor-vibrant_frog_hide-vibrant-frog-hide">Vibrant Frog Hide</h2>
<p><strong>Sources</strong> <Link to="/source/down_the_blighted_path">Down the Blighted Path pg. 63</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> armor; <strong>Price</strong> 28,165 gp; <strong>Weight</strong> 25 lbs.</p>
<p>Cut from the colorful flesh of an enormous frog, this +1 <Link to="/eq-armor/hide">hide</Link> armor squishes thickly and tightly around the body as it is donned. Light sheens brightly off the slippery skin, revealing vivid patterns in myriad hues.</p>
<p>Five times per day as a swift action, the wearer of a vibrant frog hide can cause the armor to ooze a virulent toxin. The next creature that touches the wearer must succeed at a DC 16 Fortitude save or take 1d3 points of <Link to="/rule/wisdom_damage">Wisdom damage</Link> every round for 4 rounds. A poisoned creature can attempt the save again at the beginning of each of its turns, and is cured after one successful save. Successful unarmed strikes and natural weapon attacks made by or against the wearer count as touching. The wearer is immune to his own vibrant frog hide's poison.</p>
<p>After being worn for 24 hours, a suit of vibrant frog hide armor causes the wearer to grow a frog-like tongue. The tongue acts as a <Link to="/eq-weapon/whip">whip</Link> for the purposes of damage, reach, and special features, except that it is a natural weapon with which the wearer is automatically proficient. In addition to its normal trip and disarm weapon features, the tongue may also be used to perform a <Link to="/rule/drag">drag</Link> combat maneuver with a +2 circumstance bonus, but only to pull a creature closer to the wearer (the wearer cannot step back as part of this attack). The wearer cannot speak or cast spells with verbal components for 1 round after he uses his new tongue to attack (including any attacks of opportunity).</p>
<h3 id="magic-armor-vibrant_frog_hide-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/beast_shape_ii">beast shape II</Link>, <Link to="/spell/poison">poison</Link>; <strong>Price</strong> 14,000 gp</p>
</>};
const _blackjacket = {title: "Blackjacket", jsx: <><h2 id="magic-armor-blackjacket-blackjacket">Blackjacket</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 50</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 6th<br/><strong>Slot</strong> armor; <strong>Price</strong> 28,700 gp; <strong>Weight</strong> 20 lbs.</p>
<p>This jet-black uniform is assigned to top agents in Druma's military - the Mercenary League. Wearers of this +3 <Link to="/eq-armor/armored_coat">armored coat</Link> continually benefit from the spell <Link to="/spell/undetectable_alignment">undetectable alignment</Link>. When following the orders of a member of the Kalistocracy, the wearer receives a +2 morale bonus on all attack rolls, saves, and skill checks related to completion of her mission.</p>
<p>Anytime the wearer tries to disregard an order given by a member of the Kalistocracy, she must attempt a Will save with a DC equal to 10 + 1/2 the total Hit Dice of the creature giving the order. If she fails, she must follow the order to the best of her ability. If she succeeds, she can remove the armor as a move action to ignore the command.</p>
<h3 id="magic-armor-blackjacket-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/charm_person">charm person</Link>, <Link to="/spell/heroism">heroism</Link>; <strong>Price</strong> 14,450 gp</p>
</>};
const _warden_of_the_woods = {title: "Warden of the Woods", jsx: <><h2 id="magic-armor-warden_of_the_woods-warden-of-the-woods">Warden of the Woods</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 129</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 11th<br/><strong>Slot</strong> armor; <strong>Price</strong> 29,350 gp; <strong>Weight</strong> 25 lbs.</p>
<p>The warden of the woods is a suit of +3 <Link to="/eq-material/greenwood">greenwood</Link> <Link to="/eq-armor/splint_mail">splint mail</Link> made of strips of laminated greenwood that flex with the wearer's movement but stiffen when struck in battle. This armor is treated in all ways like medium armor, including when determining proficiency. The armor has an arcane spell failure chance of 25%, a maximum Dexterity bonus of +2, and an armor check penalty of -4.</p>
<p>As a move action, the wearer can snap a strip of wood loose from the armor. The strip lengthens into a weapon of a type chosen by the armor's wearer. It can become a +1 greenwood <Link to="/eq-weapon/club">club</Link>, a +1/+1 greenwood <Link to="/eq-weapon/quarterstaff">quarterstaff</Link>, or a +1 <Link to="/magic-enh/keen">keen</Link> greenwood <Link to="/eq-weapon/wooden_stake">wooden stake</Link>. If the wearer creates a club or quarterstaff in this way, it gains the benefits of the <em>shillelagh</em> spell with a duration of 1 minute. Each weapon removed from the warden of the woods reduces the armor's enhancement bonus by 1. Consequently, a maximum of three such weapons can be separated from the armor at any given time. The greenwood weapons keep their enhancement bonuses only while they're in the wearer's hands, though they remain <Link to="/rule/masterwork_weapons">masterwork weapons</Link> for other wielders.</p>
<p>The wearer can reintegrate a weapon back into the warden of the woods as a move action and restore the lost enhancement bonus. Each day at dawn, the armor regenerates any missing strips (regaining its full enhancement bonus), and any weapons still detached from the armor crumble into dust.</p>
<h3 id="magic-armor-warden_of_the_woods-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/ironwood">ironwood</Link>, <Link to="/spell/shillelagh">shillelagh</Link>, <Link to="/spell/wood_shape">wood shape</Link>; <strong>Price</strong> 14,850 gp</p>
</>};
const _dragon_herald_vestments = {title: "Dragon Herald Vestments", jsx: <><h2 id="magic-armor-dragon_herald_vestments-dragon-herald-vestments">Dragon Herald Vestments</h2>
<p><strong>Sources</strong> <Link to="/source/kobolds_of_golarion">Kobolds of Golarion pg. 30</Link></p>
<p><strong>Aura</strong> faint abjuration; <strong>CL</strong> 3rd<br/><strong>Slot</strong> body; <strong>Price</strong> 30,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>A set of dragon herald vestments is covered in scales of one of five different colors, and grants resist energy 5 of one type (as the <em>resist energy</em> spell) to the wearer: acid for black or green, electricity for blue, fire for red, or cold for white. If the wearer is a kobold with scales matching one of those five colors, she can speak a command word in Draconic to change the vestments' scales to the same color as her own, or back to the color chosen when the vestments were constructed. Altering the scales' color is a standard action that provokes attacks of opportunity.</p>
<h3 id="magic-armor-dragon_herald_vestments-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/resist_energy">resist energy</Link>; <strong>Price</strong> 15,000 gp</p>
</>};
const _alchemists_suit = {title: "Alchemist's Suit", jsx: <><h2 id="magic-armor-alchemists_suit-alchemists-suit">Alchemist's Suit</h2>
<p><strong>Sources</strong> <Link to="/source/melee_tactics_toolbox">Melee Tactics Toolbox pg. 22</Link><br/><strong>Aura</strong> varies; <strong>CL</strong> 5th<br/><strong>Slot</strong> armor; <strong>Price</strong> 30,250 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This bizarre +1 <Link to="/eq-armor/quilted_cloth">quilted cloth</Link> armor holds eight small vials that can be filled with potions, poisons, or other alchemical substances, plus numerous decoys. If the wearer is struck by a bludgeoning attack or critical hit, is <Link to="/rule/grappled">grappled</Link>, takes <Link to="/umr/constrict">constrict</Link> damage, or is <Link to="/umr/swallow_whole">swallowed whole</Link>, the wearer can choose one vial to break as an immediate action that does not provoke an attack of opportunity. The wearer must choose himself or his attacker as the target of the vial's contents, which immediately produce their effect. If the wearer is the target, the effect functions at half strength and for half the normal duration (minimum 1 round). For example, a potion of <Link to="/spell/cure_moderate_wounds">cure moderate wounds</Link> broken in this manner cures half as many hit points as normal. If the wearer's opponent is the target, the wearer must attempt a touch attack against the opponent to apply the effect. If the attack is successful, the opponent is affected as if struck by the vial's contents. If the vial contains a substance that would harm the opponent only upon ingestion, the opponent can avoid being affected if she succeeds at a DC 15 Reflex save.</p>
<h3 id="magic-armor-alchemists_suit-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/shrink_item">shrink item</Link>; <strong>Price</strong> 15,250 gp</p>
</>};
const _skyplate_armor = {title: "Skyplate Armor", jsx: <><h2 id="magic-armor-skyplate_armor-skyplate-armor">Skyplate Armor</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_83_the_slave_trenches_of_hakotep">Pathfinder #83: The Slave Trenches of Hakotep pg. 63</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 11th<br/><strong>Slot</strong> armor; <strong>Price</strong> 30,300 gp; <strong>Weight</strong> 20 lbs.</p>
<p>This suit of +1 <Link to="/eq-armor/steel_lamellar">steel lamellar</Link> weighs less than normal steel lamellar (though it is still considered medium armor). Skyplate armor grants its wearer the ability to use <em>wind walk</em> once per day. Furthermore, while clad in skyplate armor, the wearer gains a +4 resistance bonus on all saving throws against electricity effects, wind effects, and all effects associated with magical or mundane weather.</p>
<h3 id="magic-armor-skyplate_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/resist_energy">resist energy</Link>, <Link to="/spell/wind_walk">wind walk</Link>; <strong>Price</strong> 15,300 gp</p>
</>};
const _flowing_fortress_armor = {title: "Flowing Fortress Armor", jsx: <><h2 id="magic-armor-flowing_fortress_armor-flowing-fortress-armor">Flowing Fortress Armor</h2>
<p><strong>Sources</strong> <Link to="/source/down_the_blighted_path">Down the Blighted Path pg. 61</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 10th<br/><strong>Slot</strong> armor; <strong>Price</strong> 30,350 gp; <strong>Weight</strong> 30 lbs.</p>
<p>This pale-blue +2 <Link to="/eq-armor/breastplate">breastplate</Link> is made from flowing ocean water enchanted to retain its shape. The armor check penalty of a suit of flowing fortress armor doesn't apply to Swim checks. When the wearer speaks a command word, the armor flows on or off the wearer, allowing it to be donned or removed with a single move action from up to 10 feet away.</p>
<p>A suit of flowing fortress armor has 3 charges, which refresh automatically every day at sunrise. By spending 1 charge as a standard action, the wearer transforms into water for one of two effects.</p>
<p><strong className="hl">Gush:</strong> The wearer transforms into water and bursts forward like a geyser up to 40 feet in any direction, then returns to her normal form, allowing her to cross chasms or vault obstacles. The wearer may attempt <Link to="/rule/bull_rush">bull rush</Link> combat maneuvers against any creatures and moveable objects along her path, regardless of size. The wearer rolls a single combat maneuver check and applies the result to each creature within the area. This bull rush does not provoke an attack of opportunity. If the wearer encounters an immovable object, she may attempt a Strength check to destroy that object as a free action. On a failed bull rush combat maneuver check or Strength check, the wearer's progress is stopped and she reforms next to the obstacle that blocked her path.</p>
<p><strong className="hl">Melt:</strong> The wearer melts into a puddle, gaining a swim speed of 60 feet, the ability to flow through any space a Tiny creature could <Link to="/misc/squeezing">squeeze</Link> through, and a +8 circumstance bonus on Stealth checks. The wearer can see and hear normally, but can't speak, attack, or cast spells in this form. This transformation lasts up to 10 minutes, but may be dismissed as a free action.</p>
<h3 id="magic-armor-flowing_fortress_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/control_water">control water</Link>, <Link to="/spell/elemental_body_i">elemental body I</Link>; <strong>Price</strong> 15,350 gp</p>
</>};
const _maidens_panoply = {title: "Maiden's Panoply", jsx: <><h2 id="magic-armor-maidens_panoply-maidens-panoply">Maiden's Panoply</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 87</Link><br/><strong>Aura</strong> moderate abjuration and divination; <strong>CL</strong> 11th<br/><strong>Slot</strong> armor; <strong>Price</strong> 30,650 gp; <strong>Weight</strong> 50 lbs.</p>
<p>This set of +3 <Link to="/eq-armor/gray_maiden_plate">Gray Maiden plate</Link> creates a mental link between the wearer and her allies. The wearer can telepathically communicate with allies within 30 feet (although this communication is one-way, unless an ally also has telepathy). If an ally within 30 feet is aware of a threat, the wearer of this armor is aware as well, and the wearer is never <Link to="/rule/flat_footed">flat-footed</Link> unless all allies within 30 feet are also flat-footed. In addition, if the wearer of a maiden's panoply also wields a <Link to="/magic-armor/maidens_aegis">maiden's aegis</Link>, activating that shield's ability does not reduce the maiden's aegis's enhancement bonus, and the bonus it grants increases to +2.</p>
<h3 id="magic-armor-maidens_panoply-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/detect_thoughts">detect thoughts</Link>, <Link to="/spell/telepathy">telepathy</Link>; <strong>Price</strong> 16,150 gp</p>
</>};
const _diviners_blight = {title: "Diviner's Blight", jsx: <><h2 id="magic-armor-diviners_blight-diviners-blight">Diviner's Blight</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 237</Link><br/><strong>Aura</strong> strong illusion; <strong>CL</strong> 13th<br/><strong>Slot</strong> armor; <strong>Price</strong> 31,160 gp; <strong>Weight</strong> 15 lbs.</p>
<p>Aside from its superb craftsmanship, this +4 <Link to="/eq-armor/leather">leather</Link> armor has little to distinguish it from any other armor. Once per week, while a living creature wears a suit of diviner's blight armor, the wearer can recite a command word and spend 1 minute in concentration to have the armor imitate a creature with which the wearer is familiar. The imitated creature must be within one size category of the wearer. Imitating a creature has no visible effect on the armor or the wearer, but instead confounds magical divinations.</p>
<p>Spells such as <Link to="/spell/scrying">scrying</Link> meant to observe the imitated creature instead observe the wearer, who appears to the scryer as the imitated creature; the imitated creature still attempts any necessary saving throw or applies its spell resistance, but if the spell succeeds, diviner's blight redirects any scrying sensor to its wearer. Magical means of detecting a creature's location always consider the location of the wearer as the actual location of the imitated creature, and only 8th-level or higher spells like <Link to="/spell/discern_location">discern location</Link> or <Link to="/spell/greater_prying_eyes">greater prying eyes</Link> can overcome this effect. Spells such as <Link to="/spell/discern_lies">discern lies</Link> or <Link to="/spell/zone_of_truth">zone of truth</Link> react as though the wearer were the imitated target and not himself, but only for the purpose of stating his identity. Diviner's blight would not, for instance, affect a question about the wearer's mother's name.</p>
<p>The imitation remains in place until the wearer chooses a different creature to imitate or spends 1 minute in concentration to end it. The armor resumes its normal form when removed, but the target of its imitative effect remains set - when a character dons the armor (whether the character who dons the armor is the last wearer or a different person), the armor immediately begins imitating the creature it's set to imitate again.</p>
<h3 id="magic-armor-diviners_blight-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/misdirection">misdirection</Link>, <Link to="/spell/project_image">project image</Link>; <strong>Price</strong> 15,660 gp</p>
</>};
const _man_mountain_armor = {title: "Man Mountain Armor", jsx: <><h2 id="magic-armor-man_mountain_armor-man-mountain-armor">Man Mountain Armor</h2>
<p><strong>Sources</strong> <Link to="/source/the_harrow_handbook">The Harrow Handbook pg. 31</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 15th<br/><strong>Slot</strong> armor; <strong>Price</strong> 32,350 gp; <strong>Weight</strong> 75 lbs.</p>
<p>Three times per day, as an immediate action when struck by a melee attack while he is touching the ground, the wearer of this +1 <Link to="/magic-enh/titanic">titanic</Link> <Link to="/eq-armor/stoneplate">stoneplate</Link> can cause the earth around him to shake, turning the area into <Link to="/rule/difficult_terrain">difficult terrain</Link>. The radius of this effect is equal to 1d4 &times; 5 feet, and any creature in the affected area must succeed at a DC 15 Reflex save or fall <Link to="/rule/prone">prone</Link>.</p>
<h3 id="magic-armor-man_mountain_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/earthquake">earthquake</Link>; <strong>Price</strong> 17,150 gp</p>
</>};
const _scarab_breastplate = {title: "Scarab Breastplate", jsx: <><h2 id="magic-armor-scarab_breastplate-scarab-breastplate">Scarab Breastplate</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 129</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> armor; <strong>Price</strong> 32,350 gp; <strong>Weight</strong> 30 lbs.</p>
<p>This +3 <Link to="/eq-armor/breastplate">breastplate</Link> is crafted from the carapace of a giant <Link to="/monster/scarab_beetle">scarab beetle</Link>, enchanted to be as hard and reflective as polished steel. The wearer suffers only half damage from vermin swarms and gains a +2 resistance bonus on saving throws against the extraordinary abilities of vermin swarms.</p>
<p>In addition, once per day on command, the wearer can transform the scarab breastplate into a swarm of scarab beetles that skitter from her chest to attack creatures nearby. This swarm has statistics identical to an <Link to="/monster/army_ant_swarm">army ant swarm</Link> and attacks any creatures within its space. The wearer can command the swarm to move (including changing the shape of the swarm) as a move action, but the swarm must remain adjacent to her. If the swarm is reduced to 0 hit points, if the wearer is forced to move away from the swarm, or if the wearer commands it to return to her as a move action, the swarm crawls back onto the wearer's torso and returns to armor form. While the swarm is active, the wearer is not considered to be wearing the scarab breastplate (except for purposes of commanding the swarm) and gains no defensive benefits from it.</p>
<p>A druid of 6th level wearing a scarab breastplate can use her wild shape ability to duplicate <Link to="/spell/vermin_shape_i">vermin shape I</Link>. At 8th level, she can also use it to duplicate <em>vermin shape II.</em></p>
<h3 id="magic-armor-scarab_breastplate-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/creeping_doom">creeping doom</Link>, <Link to="/spell/spell_turning">spell turning</Link>, <Link to="/spell/vermin_shape_ii">vermin shape II</Link>; <strong>Price</strong> 16,350 gp</p>
</>};
const _advocates_armor = {title: "Advocate's Armor", jsx: <><h2 id="magic-armor-advocates_armor-advocates-armor">Advocate's Armor</h2>
<p><strong>Sources</strong> <Link to="/source/melee_tactics_toolbox">Melee Tactics Toolbox pg. 22</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 11th<br/><strong>Slot</strong> armor; <strong>Price</strong> 33,160 gp; <strong>Weight</strong> 15 lbs.</p>
<p>The papery layers of this robe barely constitute what would be traditionally called armor, yet act as +3 <Link to="/eq-armor/leather">leather</Link> armor. Once per day, when the wearer is struck by a critical hit or sneak attack, he can choose to have his blood splatter across one of the paper layers and form the words of a binding deal between the attacker and the wearer. The wearer can put the opponent under a specific restriction for 24 hours, such as "I will not attack elves," or "I will attack only those who attacked me first." The terms of the contract must be simple enough for the creature to comprehend and spoken in a language it understands. This acts as a <Link to="/spell/lesser_geas">lesser geas</Link> spell, except without a limit to how many Hit Dice the target can have. A successful DC 19 Will save negates this effect.</p>
<h3 id="magic-armor-advocates_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/geas_quest">geas/quest</Link>, creator must make a pact with a devil; <strong>Price</strong> 16,660 gp</p>
</>};
const _clockwork_armor = {title: "Clockwork Armor", jsx: <><h2 id="magic-armor-clockwork_armor-clockwork-armor">Clockwork Armor</h2>
<p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 28</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 11th<br/><strong>Slot</strong> armor; <strong>Price</strong> 33,350 gp; <strong>Weight</strong> 60 lbs.</p>
<p>This suit of +2 <Link to="/eq-armor/field_plate">field plate</Link> is composed of durable plates of steel layered over an intricate framework of gears, springs, and pistons that move with mechanical precision. A suit of clockwork armor requires a special winding key to function; this key is created as part of making a suit of clockwork armor.</p>
<p>In order to function, a suit of clockwork armor must be fully wound as a full-round action. Once fully wound, a suit of clockwork armor functions for 4 hours. If a suit of clockwork armor is not fully wound, its gears grind to a halt and it imposes double its normal armor check penalty and a -2 penalty to its wearer's Strength and Dexterity scores. Donning or removing a suit of unwound clockwork armor requires 10 minutes.</p>
<p>When fully wound, a suit of clockwork armor can be donned or removed as a full-round action that provokes attacks of opportunity. It grants the wearer a +4 temporary enhancement bonus to Strength and Constitution, and its weight does not count against the wearer's total encumbrance. A single crossbow or firearm sized appropriately for the wearer can be added to the armor with a successful DC 20 Craft (armorer) check. Such a weapon can be fired once as a standard action by the wearer, then automatically reloads itself in 2d4 rounds, as long as the wearer has the appropriate ammunition in his gear.</p>
<h3 id="magic-armor-clockwork_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/animate_objects">animate objects</Link>; <strong>Price</strong> 17,350 gp</p>
</>};
const _eel_skin_armor = {title: "Eel Skin Armor", jsx: <><h2 id="magic-armor-eel_skin_armor-eel-skin-armor">Eel Skin Armor</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_58_island_of_empty_eyes">Pathfinder #58: Island of Empty Eyes pg. 60</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 6th<br/><strong>Slot</strong> armor; <strong>Price</strong> 33,810 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This red +2 <Link to="/magic-enh/slick">slick</Link> <Link to="/magic-enh/electricity_resistance">electricity resistance</Link> <Link to="/eq-armor/leather">leather</Link> armor is crafted from the skin of the <Link to="/monster/hagfish">crimson hagfish</Link>, more commonly known as the Shackles slime eel. The armor exudes a slippery slime that grants its wearer a +5 competence bonus on Escape Artist and Swim checks. In addition, as a standard action once per day, the wearer can form an aura of electricity around himself that persists for 5 rounds. Creatures adjacent to the wearer when this power is activated and at the start of the wearer's turn take 2d6 points of electricity damage and are <Link to="/misc/staggered">staggered</Link> for 1 round. A successful DC 14 Reflex save halves the damage and negates the staggering effect. The aura persists for 5 rounds.</p>
<h3 id="magic-armor-eel_skin_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/elemental_aura">elemental aura</Link>, <Link to="/spell/grease">grease</Link>, <Link to="/spell/resist_energy">resist energy</Link>; <strong>Price</strong> 16,985 gp</p>
</>};
const _full_plate_of_the_corpse = {title: "Full Plate of the Corpse", jsx: <><h2 id="magic-armor-full_plate_of_the_corpse-full-plate-of-the-corpse">Full Plate of the Corpse</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 211</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> armor; <strong>Price</strong> 35,650 gp; <strong>Weight</strong> 50 lbs.</p>
<p>This suit of +2 <Link to="/eq-armor/full_plate">full plate</Link> has been etched and stained in such a way that it resembles the form and shape of a decomposed body that is encased in a suit of armor. The wearer is effectively hidden from non-intelligent undead, which can't see, hear, or smell him; even extraordinary or supernatural senses capabilities can't penetrate the magical shroud. An intelligent undead creature can attempt a single Will saving throw (DC 14) to penetrate the ward. All affected undead behave as if the wearer simply isn't there.</p>
<h3 id="magic-armor-full_plate_of_the_corpse-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/hide_from_undead">hide from undead</Link>; <strong>Price</strong> 18,650 gp</p>
</>};
const _snailplate = {title: "Snailplate", jsx: <><h2 id="magic-armor-snailplate-snailplate">Snailplate</h2>
<p><strong>Sources</strong> <Link to="/source/misfit_monsters_redeemed">Misfit Monsters Redeemed pg. 30</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 14th<br/><strong>Slot</strong> armor; <strong>Price</strong> 36,000 gp; <strong>Weight</strong> 30 lbs.</p>
<p>This breastplate made from the shell of a flail snail functions as a +1 <Link to="/magic-enh/reflecting">reflecting</Link> <Link to="/eq-armor/breastplate">breastplate</Link> (even though that shield property cannot normally be added to armor). Once per day, the wearer can cause a spell targeted at him to reflect back at the caster, exactly like <em>spell turning.</em> At the GM's discretion, the wearer can instead expend this one use per day to roll on the flail snail's chart, randomly warping the spell in question.</p>
<h3 id="magic-armor-snailplate-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/spell_turning">spell turning</Link>, one <Link to="/monster/flail_snail">flail snail</Link> shell; <strong>Price</strong> 18,000 gp</p>
</>};
const _phoenix_armor = {title: "Phoenix Armor", jsx: <><h2 id="magic-armor-phoenix_armor-phoenix-armor">Phoenix Armor</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_purity">Champions of Purity pg. 31</Link></p>
<p><strong>Aura</strong> moderate evocation and transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> armor; <strong>Price</strong> 36,130 gp; <strong>Weight</strong> 50 lbs.</p>
<p>This brilliant golden +2 <Link to="/magic-enh/fire_resistance">fire resistance</Link> <Link to="/eq-armor/full_plate">full plate</Link> is decorated with an ornate feather motif curling across its surface and seems to radiate warmth. Once per day, the wearer can invoke the name of the <Link to="/monster/phoenix">phoenix</Link> that blessed the armor and bring the might of that phoenix against the wearer's foe. Activating the armor causes it to ignite, wreathing the wearer in red-gold flames as if under the effects of <em>fire shield.</em> In addition, great golden wings unfold out of the back of the armor, allowing the wearer to <em>fly</em> as per the spell. Both of these effects last for 9 rounds.</p>
<h3 id="magic-armor-phoenix_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/fire_shield">fire shield</Link>, <Link to="/spell/fly">fly</Link>; <strong>Price</strong> 18,890 gp</p>
</>};
const _giant_hide_armor_ogre = {title: "Giant-Hide Armor (ogre)", jsx: <><h2 id="magic-armor-giant_hide_armor_ogre-giant-hide-armor">Giant-Hide Armor</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 127</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 284</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 15th<br/><strong>Slot</strong> armor; <strong>Price</strong> ogre (39,165 gp), hill giant (46,665 gp), stone, fire, or frost giant (54,165 gp), troll (59,165 gp), cloud giant (69,165 gp), storm giant (79,665 gp); <strong>Weight</strong> 25 lbs.</p>
<p>This drooping, many-folded suit of +3 <Link to="/eq-armor/hide">hide</Link> armor is made from the tanned skin of an actual giant. Once per day on command, the wearer can grow to match the size of the appropriate giant, as if using <em>giant form I</em> (ogre, hill giant, stone giant, fire giant, frost giant, or troll) or <em>giant form II</em> (cloud giant or storm giant). This transformation lasts up to 15 minutes, and ends when the wearer commands.</p>
<p>Most good folk consider wearing the skins of intelligent creatures to be abhorrent. Giants gain a +2 morale bonus on attack and damage rolls against the wearer, or +4 if the wearer's armor is made from the same kind of giant as the attacker.</p>
<h3 id="magic-armor-giant_hide_armor_ogre-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/giant_form_i">giant form I</Link> (ogre, hill giant, stone giant, fire giant, frost giant, or troll) or <Link to="/spell/giant_form_ii">giant form II</Link> (cloud giant or storm giant); <strong>Price</strong> 19,600 gp (ogre), 23,415 gp (hill giant), 27,165 gp (stone, fire, or frost giant), 29,665 gp (troll), 34,665 gp (cloud giant), 38,415 gp (storm giant)</p>
</>};
const _crag_linnorm_plate = {title: "Crag Linnorm Plate", jsx: <><h2 id="magic-armor-crag_linnorm_plate-crag-linnorm-plate">Crag Linnorm Plate</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 50</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 11th<br/><strong>Slot</strong> armor; <strong>Price</strong> 41,300 gp; <strong>Weight</strong> 50 lbs.</p>
<p>This specialized suit of full plate is made from the tanned hide of a linnorm and acts as +4 <Link to="/eq-armor/dragonhide_plate">dragonhide plate</Link>. If a creature is slain while wearing such armor, its killer is subject to a curse. The cursed creature must succeed at a DC 17 Will save or gain vulnerability to fire until the curse is removed. This curse can be removed only by a <Link to="/spell/break_enchantment">break enchantment</Link>, <Link to="/spell/miracle">miracle</Link>, or <Link to="/spell/wish">wish</Link> spell. This particular suit of armor is made from the hide of a <Link to="/monster/crag_linnorm">crag linnorm</Link>, though others exist, each with a different curse effect similar to the curse of the associated linnorm.</p>
<p>Once per day as a swift action, the wear of this armor can summon forth the uncanny movement powers of a linnorm, gaining the benefits of <em>freedom of movement</em> for 10 minutes.</p>
<h3 id="magic-armor-crag_linnorm_plate-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/form_of_the_dragon_i">form of the dragon I</Link>, <Link to="/spell/freedom_of_movement">freedom of movement</Link>, <Link to="/spell/major_curse">major curse</Link>; <strong>Price</strong> 22,300 gp</p>
</>};
const _hallowed_chain_greater_varisian = {title: "Greater Hallowed Chain (Varisian)", jsx: <><h2 id="magic-armor-hallowed_chain_greater_varisian-greater-hallowed-chain-varisian">Greater Hallowed Chain (Varisian)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 225</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 11th<br/><strong>Slot</strong> armor; <strong>Price</strong> 43,300 gp; <strong>Weight</strong> 40 lbs.</p>
<blockquote>
<p><em>The following suit of armor is generally available only to members of the indicated race or ethnicity.</em></p>
</blockquote>
<p>This armor functions as <Link to="/magic-armor/hallowed_chain_varisian">hallowed chain</Link>, except that it protects as a suit of +3 <Link to="/magic-enh/martyring">martyring</Link> <Link to="/eq-armor/chainmail">chainmail</Link> and can absorb up to 10 points of positive energy.</p>
<h3 id="magic-armor-hallowed_chain_greater_varisian-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/mass_cure_moderate_wounds">mass cure moderate wounds</Link>, creator must be a Varisian; <strong>Price</strong> 21,800 gp</p>
</>};
const _hamatula_hide = {title: "Hamatula Hide", jsx: <><h2 id="magic-armor-hamatula_hide-hamatula-hide">Hamatula Hide</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 127</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> armor; <strong>Price</strong> 44,215 gp; <strong>Weight</strong> 12 lbs.</p>
<p>Crafted from the flayed skin of a <Link to="/monster/barbed_devil">barbed devil</Link>, this imposing +2 <Link to="/eq-armorenh/armor_spikes">spiked</Link> <Link to="/eq-armor/hide">hide</Link> armor weighs half the normal weight. When its wearer rages, the armor's spikes elongate and the hide bonds to her skin, providing fire resistance 10. Any creature that strikes the wearer with a melee weapon, unarmed strike, or a natural weapon while the spikes are elongated takes 1d8+6 points of piercing damage from the armor's barbs (unless using a weapon with reach). While the wearer is enraged, spells that cause additional damage to evil outsiders deal that increased damage to her.</p>
<p>A barbarian with <Link to="/arc-barbarian/totem_rage_power">fiend totem rage powers</Link> gains additional benefits from hamatula hide. If she has the lesser fiend totem rage power, she gains a +1 profane bonus to Armor Class while raging. If she has the fiend totem rage power, the damage caused by her barbs increases to 2d8+6 and stacks with the barbed defense granted by the armor. If she has the greater fiend totem ability, she gains fire resistance 20 when raging.</p>
<h3 id="magic-armor-hamatula_hide-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/polymorph">polymorph</Link>, <Link to="/spell/resist_energy">resist energy</Link> (fire); <strong>Price</strong> 22,215 gp</p>
</>};
const _wizards_mail = {title: "Wizard's Mail", jsx: <><h2 id="magic-armor-wizards_mail-wizards-mail">Wizard's Mail</h2>
<p><strong>Sources</strong> <Link to="/source/melee_tactics_toolbox">Melee Tactics Toolbox pg. 23</Link><br/><strong>Aura</strong> strong conjuration; <strong>CL</strong> 15th<br/><strong>Slot</strong> armor; <strong>Price</strong> 52,100 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This chain armor is so fine it offers protection only because it's enchanted and made of <Link to="/eq-material/mithral">mithral</Link>. It acts as a suit of +4 <Link to="/magic-enh/greater_slick">greater slick</Link> <Link to="/eq-armor/leather">leather</Link> armor. It has a maximum Dexterity bonus to AC of +8 and imposes no chance of arcane spell failure.</p>
<h3 id="magic-armor-wizards_mail-construction">Construction</h3>
<p><strong>Requirements</strong> Armor Proficiency (light), <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/grease">grease</Link>, <Link to="/spell/iron_body">iron body</Link>; <strong>Price</strong> 27,600 gp</p>
</>};
const _demon_armor = {title: "Demon Armor", jsx: <><h2 id="magic-armor-demon_armor-demon-armor">Demon Armor</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 125</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 464</Link><br/><strong>Aura</strong> strong necromancy [evil]; <strong>CL</strong> 13th<br/><strong>Slot</strong> armor; <strong>Price</strong> 52,260 gp; <strong>Weight</strong> 50 lbs.</p>
<p>This plate armor is fashioned to make the wearer appear to be a demon. Glowing red energy emanates from sigils engraved on the armor's key plates and joints, and the runes intermittently surge with fiendish power. This +4 <Link to="/eq-armor/full_plate">full plate</Link> allows the wearer to make claw attacks that deal 1d10 points of damage, strike as +1 weapons, and afflict the target as if she had been struck by a <em>contagion</em> spell (Fortitude DC 14 negates). Use of <em>contagion</em> requires a normal melee attack with the claws. The "claws" are built into the armor's vambraces and gauntlets, and cannot be disarmed.</p>
<p>A suit of demon armor is infused with evil, and as a result it bestows one <Link to="/rule/negative_level">negative level</Link> on any nonevil creature wearing it. This negative level persists as long as the armor is worn and disappears when the armor is removed. The negative level cannot be overcome in any way (including <Link to="/spell/restoration">restoration</Link> spells) while the armor is worn.</p>
<h3 id="magic-armor-demon_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/contagion">contagion</Link>; <strong>Price</strong> 26,955 gp</p>
</>};
const _field_medics_breastplate = {title: "Field Medic's Breastplate", jsx: <><h2 id="magic-armor-field_medics_breastplate-field-medics-breastplate">Field Medic's Breastplate</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_purity">Champions of Purity pg. 31</Link></p>
<p><strong>Aura</strong> moderate abjuration, faint conjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> armor; <strong>Price</strong> 52,900 gp; <strong>Weight</strong> 30 lbs.</p>
<p>This battered yet lovingly polished +1 <Link to="/eq-armor/breastplate">breastplate</Link> is marked by three chipped glass circles set over the heart, each of a different color. Three times per day, the wearer may tap a circle to activate it, enveloping her in a shimmering aura that protects her from harm. The wearer gains DR 10/- and is protected if she were under the effects of a <Link to="/spell/globe_of_invulnerability">globe of invulnerability</Link> spell. The effect ends as soon as the wearer makes an offensive action or casts an offensive spell, or after 1 minute. In addition, whenever the wearer casts a <em>cure</em> spell or administers a <em>cure</em> potion while under this effect, she may add one additional die to the total amount of damage healed.</p>
<h3 id="magic-armor-field_medics_breastplate-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/cure_light_wounds">cure light wounds</Link>, <Link to="/spell/sanctuary">sanctuary</Link>; <strong>Price</strong> 26,450 gp</p>
</>};
const _nightskin = {title: "Nightskin", jsx: <><h2 id="magic-armor-nightskin-nightskin">Nightskin</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_30_the_twice_damned_prince">Pathfinder #30: The Twice-Damned Prince pg. 68</Link><br/><strong>Aura</strong> moderate illusion (evil); <strong>CL</strong> 10th<br/><strong>Slot</strong> armor; <strong>Price</strong> 53,100 gp; <strong>Weight</strong> 25 lbs.</p>
<p>Each of these +2 <Link to="/magic-enh/glamered">glamered</Link> <Link to="/eq-armor/chain_shirt">chain shirts</Link> bears a permanent illusion of being a fantastic ebon gown of peerless design or a royal suit of nighted hues. Yet those who see past the illusion find a strange padding within the armor, stitched skins of macabre origins filled with locks of delicate hair, dyed in devil's blood. Those who wear the armor find that they can see in even the most abysmal darkness as per a devil's ability to <Link to="/umr/see_in_darkness">see in darkness</Link> (seeing through even magical darkness as if it were full light). In addition, the wearer finds that he can understand Infernal perfectly, though the armor does not grant the ability to speak it.</p>
<p>Nightskin is a fundamentally evil armor and any wearer of good alignment is treated as being <Link to="/misc/sickened">sickened</Link> for as long as the armor is worn.</p>
<h3 id="magic-armor-nightskin-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/major_image">major image</Link>, <Link to="/spell/true_seeing">true seeing</Link>; <strong>Price</strong> 26,550 gp</p>
</>};
const _tigers_hide = {title: "Tiger's Hide", jsx: <><h2 id="magic-armor-tigers_hide-tigers-hide">Tiger's Hide</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_moon">Blood of the Moon pg. 23</Link><br/><strong>Aura</strong> moderate abjuration and transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> armor; <strong>Price</strong> 54,115 gp; <strong>Weight</strong> 25 lbs.</p>
<p>This +3 <Link to="/eq-armor/hide">hide</Link> armor is made from tiger skin. It is magically treated to make it easier to move in, reducing its armor check penalty to 0, reducing its arcane spell failure chance to 10%, and increasing its maximum Dexterity bonus to +6. It grants DR 5/- against natural weapon attacks. In addition, the wearer can use the <Link to="/umr/pounce">pounce</Link> special attack, but only during the first round she can act in any combat.</p>
<h3 id="magic-armor-tigers_hide-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/beast_shape_iii">beast shape III</Link>; <strong>Price</strong> 29,115 gp</p>
</>};
const _ebon_thorn = {title: "Ebon Thorn", jsx: <><h2 id="magic-armor-ebon_thorn-ebon-thorn">Ebon Thorn</h2>
<p><strong>Sources</strong> <Link to="/source/lost_treasures">Lost Treasures pg. 26</Link><br/><strong>Aura</strong> moderate enchantment and necromancy; <strong>CL</strong> 7th<br/><strong>Slot</strong> armor; <strong>Price</strong> 60,500 gp; <strong>Weight</strong> 6 lbs.</p>
<p>This suit of +4 <Link to="/magic-enh/bolstering">bolstering</Link> <Link to="/magic-enh/grinding">grinding</Link> <Link to="/eq-material/adamantine">adamantine</Link> <Link to="/eq-armor/full_plate">full plate</Link> bristles with long thorns and barbs along the edges of its heavy plates. These are gained from the grinding special ability, and also act as +1 <Link to="/magic-enh/cruel">cruel</Link> <Link to="/eq-armorenh/armor_spikes">armor spikes</Link>. As a swift action whenever Ebon Thorn's spikes damage an opponent, its wearer can attempt a Intimidate check to demoralize that opponent. The wearer doesn't take the normal -4 penalty on Intimidate checks made against larger opponents.</p>
<h3 id="magic-armor-ebon_thorn-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/cause_fear">cause fear</Link>, <Link to="/spell/death_knell">death knell</Link>, <Link to="/spell/heroism">heroism</Link>, <Link to="/spell/keen_edge">keen edge</Link>; <strong>Price</strong> 38,500 gp</p>
</>};
const _gelugon_plate = {title: "Gelugon Plate", jsx: <><h2 id="magic-armor-gelugon_plate-gelugon-plate">Gelugon Plate</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 97</Link>, <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 51</Link><br/><strong>Aura</strong> moderate conjuration and transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> armor; <strong>Price</strong> 60,950 gp; <strong>Weight</strong> 50 lbs.</p>
<p>This iridescent +3 <Link to="/eq-armor/hellknight_plate">Hellknight plate</Link> is cold to the touch, and the fiendish features that swirl across the plates shed gouts of cold mist. The wearer of this armor gains cold resistance 10. Any creature that ends its movement within 5 feet of the wearer must succeed at a DC 16 Fortitude saving throw or be <Link to="/misc/staggered">staggered</Link> for 1 round, numbed by the cold emitted by the armor. A creature that succeeds at its saving throw is immune to the effects of that gelugon plate for 24 hours. The wearer of a suit of gelugon plate can suppress or reactivate this effect as a standard action.</p>
<p>A Hellknight (or Hellknight signifer with heavy armor proficiency) wearing this armor can cast <em>wall of ice</em> three times per day.</p>
<h3 id="magic-armor-gelugon_plate-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/slow">slow</Link>, <Link to="/spell/wall_of_ice">wall of ice</Link>; <strong>Price</strong> 31,550 gp</p>
</>};
const _mail_of_malevolence = {title: "Mail of Malevolence", jsx: <><h2 id="magic-armor-mail_of_malevolence-mail-of-malevolence">Mail of Malevolence</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 127</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 10th<br/><strong>Slot</strong> armor; <strong>Price</strong> 61,300 gp; <strong>Weight</strong> 40 lbs.</p>
<p>Mail of malevolence hangs in rags and tatters and acts as nonmagical chainmail to wearers who lack at least a moderate evil aura. When worn by a sufficiently evil character, it instead functions as +2 <Link to="/magic-enh/unrighteous">unrighteous</Link> <Link to="/eq-armor/chainmail">chainmail</Link>. Mail of malevolence does not bestow a negative level on good wearers.</p>
<p>The wearer of mail of malevolence gains SR 21, but only against spells with the good descriptor. In addition, whenever the wearer <Link to="/ability/channel_negative_energy">channels negative energy</Link> to harm living creatures, she heals a like amount of damage herself regardless of whether she is living or undead.</p>
<h3 id="magic-armor-mail_of_malevolence-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/righteous_might">righteous might</Link>, <Link to="/spell/spell_resistance">spell resistance</Link>; <strong>Price</strong> 30,800 gp</p>
</>};
const _coruscating_raiment = {title: "Coruscating Raiment", jsx: <><h2 id="magic-armor-coruscating_raiment-coruscating-raiment">Coruscating Raiment</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 47</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 13th<br/><strong>Slot</strong> armor; <strong>Price</strong> 63,150 gp; <strong>Weight</strong> 50 lbs.</p>
<p>Originally crafted by <Link to="/monster/jyoti">jyoti</Link> armorsmiths of the Positive Energy Plane, this gleaming suit of +1 <Link to="/magic-enh/radiant">radiant</Link> <Link to="/eq-armor/full_plate">full plate</Link> has a mirror-like sheen that reflects even tiny sparks of light into brilliant ribbons of blazing color. Its ability to shine as brightly as a torch cannot be suppressed unless the wearer is in magical darkness. Once per day as an immediate action while charging, the wearer can transform her body into brilliant light. The wearer becomes incorporeal until she arrives at the end of her charge and makes her physical attacks, and she can charge through any creatures and obstacles that do not hinder incorporeal creatures (although she must have line of sight to her target when she begins her <Link to="/rule/charge">charge</Link>, as normal).</p>
<h3 id="magic-armor-coruscating_raiment-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/sunburst">sunburst</Link>; <strong>Price</strong> 32,400 gp</p>
</>};
const _o_yoroi_of_imperial_rule = {title: "O-Yoroi of Imperial Rule", jsx: <><h2 id="magic-armor-o_yoroi_of_imperial_rule-o-yoroi-of-imperial-rule">O-Yoroi of Imperial Rule</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_54_the_empty_throne">Pathfinder #54: The Empty Throne pg. 60</Link><br/><strong>Aura</strong> strong evocation; <strong>CL</strong> 13th<br/><strong>Slot</strong> armor; <strong>Price</strong> 68,400 gp; <strong>Weight</strong> 45 lbs.</p>
<p>This distinctive +4 <Link to="/eq-material/adamantine">adamantine</Link> <Link to="/magic-enh/glamered">glamered</Link> <Link to="/eq-armor/o_yoroi">o-yoroi</Link> was designed for scions of Minkai's imperial families and their highest-ranking and most loyal samurai, providing its wearer with DR 3/-. In addition, the armor stores the kinetic energy from blows made against it. Once the armor has negated 15 total points of damage, the wearer can release the stored energy as a swift action against a single creature within 10 feet. This energy takes the form of a force effect, and the wearer must make an attack roll at his base attack bonus +10. The energy deals 15 points of force damage to the target, and the target must make a DC 22 Fortitude save or be <Link to="/misc/stunned">stunned</Link> for 1 round. If the wearer chooses not to release this energy, the armor still provides damage reduction but absorbs no more energy until the stored energy is released.</p>
<h3 id="magic-armor-o_yoroi_of_imperial_rule-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/clenched_fist">clenched fist</Link>, <Link to="/spell/disguise_self">disguise self</Link>; <strong>Price</strong> 42,550 gp</p>
</>};
const _daystar_half_plate = {title: "Daystar Half-Plate", jsx: <><h2 id="magic-armor-daystar_half_plate-daystar-half-plate">Daystar Half-Plate</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 125</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 284</Link><br/><strong>Aura</strong> strong evocation; <strong>CL</strong> 15th<br/><strong>Slot</strong> armor; <strong>Price</strong> 81,250 gp; <strong>Weight</strong> 50 lbs.</p>
<p>This glowing +1 <Link to="/eq-armor/half_plate">half-plate</Link> is decorated with various images of the sun and depictions of nature. At will, the wearer can command the armor to shine with a <em>daylight</em> spell for 10 minutes. Once per day, the wearer can command it to shine as per the <em>sunburst</em> spell. The <em>sunburst</em> is centered on the wearer and the wearer is immune to its effects.</p>
<h3 id="magic-armor-daystar_half_plate-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/daylight">daylight</Link>, <Link to="/spell/sunburst">sunburst</Link>; <strong>Price</strong> 41,000 gp</p>
</>};
const _xill_carapace_armor = {title: "Xill Carapace Armor", jsx: <><h2 id="magic-armor-xill_carapace_armor-xill-carapace-armor">Xill Carapace Armor</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 53</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 13th<br/><strong>Slot</strong> armor; <strong>Price</strong> 83,050 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This suit of +1 <Link to="/eq-armorenh/armor_spikes">spiked</Link> <Link to="/eq-armor/half_plate">half-plate</Link> armor is crafted from the hide and carapace of a <Link to="/monster/xill">xill</Link> and includes a xill-skull helmet complete with insect-like mandibles, giving the wearer an otherworldly, bug-like appearance. Once per day, the wearer can shift from the Material Plane to the Ethereal Plane and back again, as the <Link to="/magic-enh/etherealness">etherealness</Link> magic armor special ability. Unlike with standard etherealness armor, however, the transitions to and from planes function exactly like a xill's planewalk ability, save that the wearer cannot take any creatures with it when it switches planes.</p>
<p>Additionally, the spikes along the armor's back, torso, arms, and upper legs are laced with a natural paralytic. The target of a successful critical hit made with these armor spikes is <Link to="/rule/paralyzed">paralyzed</Link> for 1d4 rounds (Fortitude DC 16 negates).</p>
<h3 id="magic-armor-xill_carapace_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/ethereal_jaunt">ethereal jaunt</Link>, <Link to="/spell/hold_monster">hold monster</Link>; <strong>Price</strong> 41,900 gp</p>
</>};
const _empyreal_armor = {title: "Empyreal Armor", jsx: <><h2 id="magic-armor-empyreal_armor-empyreal-armor">Empyreal Armor</h2>
<p><strong>Sources</strong> <Link to="/source/chronicle_of_the_righteous">Chronicle of the Righteous pg. 52</Link></p>
<p><strong>Aura</strong> strong evocation [fire]; <strong>CL</strong> 13th<br/><strong>Slot</strong> armor; <strong>Price</strong> 100,050 gp; <strong>Weight</strong> 50 lbs.</p>
<p>Legend tells that the first suits of empyreal armor were forged from the battered, cast-off breastplates worn by <Link to="/monster/solar">solars</Link> in battle. These suits were gifted to powerful mortal heroes and have since changed hands many times.</p>
<p>Empyreal armor is made of steel forged so that it reflects a golden sheen in the sunlight. This armor functions as a suit of +3 <Link to="/magic-enh/moderate_fortification">moderate fortification</Link> <Link to="/eq-armor/full_plate">full plate</Link>. In addition, three times per day, its wearer can activate a <em>fire shield</em> (warm shield only) that lasts for 13 rounds. Any creature attacking the wearer with its body or a handheld weapon while the <em>fire shield</em> effect is active deals normal damage but takes 1d6+13 points of damage in return. Half this damage is fire damage, but the other half results directly from divine power and is therefore not subject to energy resistance.</p>
<h3 id="magic-armor-empyreal_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/fire_shield">fire shield</Link>, <Link to="/spell/limited_wish">limited wish</Link> or <Link to="/spell/miracle">miracle</Link>; <strong>Price</strong> 50,850 gp</p>
</>};
const _gelugon_armor = {title: "Gelugon Armor", jsx: <><h2 id="magic-armor-gelugon_armor-gelugon-armor">Gelugon Armor</h2>
<p><strong>Sources</strong> <Link to="/source/melee_tactics_toolbox">Melee Tactics Toolbox pg. 23</Link><br/><strong>Aura</strong> strong abjuration and evocation; <strong>CL</strong> 13th<br/><strong>Slot</strong> armor; <strong>Price</strong> 117,650 gp; <strong>Weight</strong> 50 lbs.</p>
<p>This +4 <Link to="/eq-armor/full_plate">full plate</Link> is fashioned to make the wearer appear to be an <Link to="/monster/ice_devil">ice devil</Link>, complete with insectile eyes. Frosty blue energy emanates from the armor's joints, and the helm's eyes intermittently surge with diabolical power. The armor has a long, spear-like tail that can be used to make a single primary natural attack per round as a standard action if the wearer makes no other attacks. This tail attack deals 1d10 points of damage plus 2d6 points of cold damage for a Medium wearer. The tail can also be used to make attacks of opportunity that count against the wearer's maximum number of attacks of opportunity per round.</p>
<h3 id="magic-armor-gelugon_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/resist_energy">resist energy</Link>, creator must be lawful evil; <strong>Price</strong> 59,650 gp</p>
</>};
const _invincible_armor = {title: "Invincible Armor", jsx: <><h2 id="magic-armor-invincible_armor-invincible-armor">Invincible Armor</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 127</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 13th<br/><strong>Slot</strong> armor; <strong>Price</strong> 137,650 gp; <strong>Weight</strong> 50 lbs.</p>
<p>Invincible armor shifts between three different appearances, but always weighs the same and protects as +2 <Link to="/magic-enh/impervious_a">impervious</Link> <Link to="/magic-enh/moderate_fortification">moderate fortification</Link> <Link to="/eq-armor/full_plate">full plate</Link>. As an immediate action, the wearer can change the armor into heavy plate that blocks slashing attacks (DR 10/bludgeoning or piercing), thickly layered chainmail that blocks piercing attacks (DR 10/bludgeoning or slashing), or overlapping metal scales that block bludgeoning attacks (DR 10/piercing or slashing). In addition, invincible armor provides the wearer with 5 points of resistance to acid, cold, electricity, fire, and sonic, and is itself unharmed by damage from any of these energy types.</p>
<h3 id="magic-armor-invincible_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/fabricate">fabricate</Link>, <Link to="/spell/make_whole">make whole</Link>, <Link to="/spell/resist_energy">resist energy</Link>, and <Link to="/spell/limited_wish">limited wish</Link> or <Link to="/spell/miracle">miracle</Link>; <strong>Price</strong> 69,650 gp</p>
</>};
const _thanatotic_plate = {title: "Thanatotic Plate", jsx: <><h2 id="magic-armor-thanatotic_plate-thanatotic-plate">Thanatotic Plate</h2>
<p><strong>Sources</strong> <Link to="/source/book_of_the_damned">Book of the Damned pg. 197</Link><br/><strong>Aura</strong> strong abjuration [evil]; <strong>CL</strong> 15th<br/><strong>Slot</strong> armor; <strong>Price</strong> 141,240 gp; <strong>Weight</strong> 50 lbs.</p>
<p>This jet-black +3 <Link to="/magic-enh/unrighteous">unrighteous</Link> <Link to="/eq-armor/full_plate">full plate</Link> is made in the image of the armor worn by <Link to="/monster/thanatotic_titan">thanatotic titans</Link> and grants the wearer a fragment of their immense power. The wearer of thanatotic plate gains SR 21 against divine spells. In addition, the wearer can speak a command word to gain the benefits of <em>air walk, break enchantment,</em> or <em>spell turning</em> once per day each. Once per week, the wearer can use <em>greater planar ally</em> to call upon a <Link to="/monster/tarry_demodand">tarry demodand</Link>.</p>
<p>A newly created set of thanatotic plate always includes a <Link to="/magic-armor/thanatotic_visage">thanatotic visage</Link>; this is included in the price and weight. A set of thanatotic plate missing its visage has its price reduced by that of the visage.</p>
<p>A nonevil character who dons thanatotic plate immediately gains 4 <Link to="/rule/negative_levels">negative levels</Link>; these negative levels can't be removed or ignored, but they disappear when the armor is removed.</p>
<h3 id="magic-armor-thanatotic_plate-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/air_walk">air walk</Link>, <Link to="/spell/break_enchantment">break enchantment</Link>, <Link to="/spell/breath_of_life">breath of life</Link>, <Link to="/spell/greater_planar_ally">greater planar ally</Link>, <Link to="/spell/heal">heal</Link>, <Link to="/spell/spell_turning">spell turning</Link>, <Link to="/spell/unholy_aura">unholy aura</Link>; <strong>Price</strong> 71,445 gp</p>
</>};
const _prismatic_plate = {title: "Prismatic Plate", jsx: <><h2 id="magic-armor-prismatic_plate-prismatic-plate">Prismatic Plate</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 128</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 13th<br/><strong>Slot</strong> armor; <strong>Price</strong> 160,650 gp; <strong>Weight</strong> 50 lbs.</p>
<p>This resplendent suit of +3 <Link to="/eq-armor/full_plate">full plate</Link> shimmers and shifts between all the colors of the rainbow. A single color dominates the others at any given time. As a swift action, the wearer can change the dominant color. This color remains dominant until the wearer changes it again. When the wearer of prismatic plate is struck by a <em>prismatic spray,</em> or when he passes through a <em>prismatic sphere</em> or <em>prismatic wall,</em> he ignores the effect that matches the dominant armor color. He receives no special protection against the other colors of those spells. In addition to this benefit, each color provides a unique type of protection.</p>
<ScrollContainer id="magic-armor-prismatic_plate--table-0"><table>
<thead>
<tr>
<th>Color</th>
<th>Effect</th>
</tr>
</thead>
<tbody><tr>
<td>Red</td>
<td>Resist fire 30</td>
</tr>
<tr>
<td>Orange</td>
<td>Resist acid 30</td>
</tr>
<tr>
<td>Yellow</td>
<td>Resist electricity 30</td>
</tr>
<tr>
<td>Green</td>
<td>Immunity to poison</td>
</tr>
<tr>
<td>Blue</td>
<td>Immunity to petrification</td>
</tr>
<tr>
<td>Indigo</td>
<td>+8 resistance bonus on saving throws made against mind-affecting effects</td>
</tr>
<tr>
<td>Violet</td>
<td>Protected by <em>dimensional anchor,</em> as the spell</td>
</tr>
</tbody></table></ScrollContainer>
<h3 id="magic-armor-prismatic_plate-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/dimensional_anchor">dimensional anchor</Link>, <Link to="/spell/mind_blank">mind blank</Link>, <Link to="/spell/neutralize_poison">neutralize poison</Link>, <Link to="/spell/resist_energy">resist energy</Link>, <Link to="/spell/stone_to_flesh">stone to flesh</Link>, and <Link to="/spell/prismatic_sphere">prismatic sphere</Link>, <Link to="/spell/prismatic_spray">prismatic spray</Link>, or <Link to="/spell/prismatic_wall">prismatic wall</Link>; <strong>Price</strong> 81,150 gp</p>
</>};
const _zombie_skin_shield = {title: "Zombie Skin Shield", jsx: <><h2 id="magic-armor-zombie_skin_shield-zombie-skin-shield">Zombie Skin Shield</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 133</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> shield; <strong>Price</strong> 2,159 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This +1 <Link to="/eq-armor/light_steel_shield">light steel shield</Link> is wrapped in a layer of gray skin. Once per day, the wearer can animate the skin as a human <Link to="/template/zombie">zombie</Link> under her control, as if she had created it with <em>animate dead,</em> for a period of 5 minutes. When the time expires, the zombie returns to the shield. If the zombie is destroyed or cannot reach the shield by the time it expires, placing the shield on a Medium humanoid corpse for 1 hour recreates the shield's skin.</p>
<h3 id="magic-armor-zombie_skin_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/animate_dead">animate dead</Link>; <strong>Price</strong> 1,159 gp</p>
</>};
const _breach_barrier = {title: "Breach Barrier", jsx: <><h2 id="magic-armor-breach_barrier-breach-barrier">Breach Barrier</h2>
<p><strong>Sources</strong> <Link to="/source/down_the_blighted_path">Down the Blighted Path pg. 60</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 3rd<br/><strong>Slot</strong> none; <strong>Price</strong> 2,370 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This +1 <Link to="/eq-armor/heavy_steel_shield">heavy steel shield</Link> is often stylized by its dwarven crafters to look like a door or archway. Once per day after uttering a command word, the wielder can press this shield against a portal to secure it as per the <em>hold portal</em> spell. The shield remains adhered to the portal for 3 minutes, after which the shield comes free. The wielder can remove the shield from her arm as a move action, leaving the shield attached to the portal for the remainder of the duration. Before the end of the duration, the wielder can pull the shield from the portal, automatically ending the effect.</p>
<h3 id="magic-armor-breach_barrier-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/hold_portal">hold portal</Link>; <strong>Price</strong> 1,270 gp</p>
</>};
const _driftwood_shield = {title: "Driftwood Shield", jsx: <><h2 id="magic-armor-driftwood_shield-driftwood-shield">Driftwood Shield</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 251</Link><br/><strong>Aura</strong> faint divination and transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> shield; <strong>Price</strong> 2,527 gp; <strong>Weight</strong> 10 lbs.</p>
<p>This +1 <Link to="/eq-armor/heavy_wooden_shield">heavy wooden shield</Link> looks like it is made from pieces of driftwood lashed together with seaweed. The bearer may use <em>know direction</em> at will. Once per day when struck by a melee attack, the bearer of a driftwood shield can use <em>warp wood</em> as an immediate action, affecting one Small or smaller wooden object wielded, held, or carried by the opponent who attacked her.</p>
<h3 id="magic-armor-driftwood_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/know_direction">know direction</Link>, <Link to="/spell/warp_wood">warp wood</Link>; <strong>Price</strong> 1,342 gp</p>
</>};
const _casters_shield = {title: "Caster's Shield", jsx: <><h2 id="magic-armor-casters_shield-casters-shield">Caster's Shield</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 130</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 467</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 6th<br/><strong>Slot</strong> shield; <strong>Price</strong> 3,153 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This +1 <Link to="/eq-armor/light_wooden_shield">light wooden shield</Link> has a leather strip on the back on which a spellcaster can scribe a single spell as on a scroll. A spell so scribed requires half the normal cost in raw materials. The strip cannot accommodate spells of higher than 3rd level. The strip is reusable.</p>
<p>A random caster's shield has a 50% chance of having a single medium scroll spell on it. The spell is divine (01-80 on d%) or arcane (81-100). A caster's shield has a 5% arcane spell failure chance. The price of the shield is modified by the value of the scroll spell if one is currently scribed.</p>
<h3 id="magic-armor-casters_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/feat/scribe_scroll">Scribe Scroll</Link>, creator must be at least 6th level; <strong>Price</strong> 1,653 gp</p>
</>};
const _bronze_whisperers_shield = {title: "Bronze Whisperer's Shield", jsx: <><h2 id="magic-armor-bronze_whisperers_shield-bronze-whisperers-shield">Bronze Whisperer's Shield</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 250</Link><br/><strong>Aura</strong> faint evocation and transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> shield; <strong>Price</strong> 4,279 gp; <strong>Weight</strong> 6 lbs.</p>
<p>This +1 <Link to="/eq-armor/light_steel_shield">light steel shield</Link> is decorated with bronze gears and vaguely resembles a feminine metal mask with a rune on its forehead. As a standard action, the wearer can command it to noisily transform into a <Link to="/eq-armor/buckler">buckler</Link> or back into its light shield form. Once per day, the wearer can use it to deliver a <em>shocking grasp.</em></p>
<h3 id="magic-armor-bronze_whisperers_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/minor_creation">minor creation</Link>, <Link to="/spell/shocking_grasp">shocking grasp</Link>; <strong>Price</strong> 2,219 gp</p>
</>};
const _scarab_shield = {title: "Scarab Shield", jsx: <><h2 id="magic-armor-scarab_shield-scarab-shield">Scarab Shield</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_79_the_half_dead_city">Pathfinder #79: The Half-Dead City pg. 61</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 3rd<br/><strong>Slot</strong> shield; <strong>Price</strong> 4,399 gp; <strong>Weight</strong> 6 lbs.</p>
<p>This +1 <Link to="/eq-armor/light_steel_shield">light steel shield</Link> is fashioned in the shape of a <Link to="/monster/scarab_beetle">scarab beetle</Link> - a creature that functions as a psychopomp for <Link to="/faith/pharasma">Pharasma</Link>, guiding the souls of the departed into the afterlife. Scarab shields are especially favored by archaeologists and tomb raiders for the protection they grant against guardians and vermin frequently found in ancient ruins and forgotten tombs.</p>
<p>Once per day on command, a scarab shield grants its wielder a +2 sacred bonus on saving throws against fear and death effects for 3 minutes. At any time while this bonus is in effect, the wielder can end the effect as a swift action for a burst of healing energy. The wielder loses the saving throw bonus, but is healed of 1d8+3 points of damage.</p>
<p>In addition, a scarab shield can protect its wielder from swarms. If a mindless swarm attempts to enter the wielder's space, the swarm must attempt a DC 11 Will save. If the save succeeds, the swarm can enter the wielder's space and attack the wielder normally. If the save fails, the swarm instinctively avoids the space occupied by the wielder, completely ignoring the wielder for 3 rounds. This effect ends if the wielder makes any attacks, but the wielder may use non-attack spells or otherwise act without ending the effect. This ability functions once per day.</p>
<h3 id="magic-armor-scarab_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/blessing_of_courage_and_life">blessing of courage and life</Link>, <Link to="/spell/sanctuary">sanctuary</Link>; <strong>Price</strong> 2,279 gp</p>
</>};
const _burglars_buckler = {title: "Burglar's Buckler", jsx: <><h2 id="magic-armor-burglars_buckler-burglars-buckler">Burglar's Buckler</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 130</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> shield; <strong>Price</strong> 4,655 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This unassuming +1 <Link to="/eq-armor/buckler">buckler</Link> has an array of small tools and implements embedded into the backside of its rim, able to be folded and snapped out for use at a moment's notice to attack, defend, or accomplish roguish tasks. A burglar's buckler grants the wielder a +2 competence bonus on Disable Device and Sleight of Hand checks, combat maneuver checks made to perform dirty tricks, and to CMD against dirty tricks.</p>
<p>Once per day on command, the wielder may transform a burglar's buckler into any mundane tool weighing 1 to 5 pounds, such as a crowbar, hammer, saw, small shovel, grappling hook, artisan's tools, or thieves' tools. The burglar's buckler retains its normal hardness and hit points in this form and can be converted back into shield form on command.</p>
<h3 id="magic-armor-burglars_buckler-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/major_creation">major creation</Link>; <strong>Price</strong> 2,450 gp</p>
</>};
const _challenging_shield = {title: "Challenging Shield", jsx: <><h2 id="magic-armor-challenging_shield-challenging-shield">Challenging Shield</h2>
<p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 31</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 1st<br/><strong>Slot</strong> shield; <strong>Price</strong> 5,170 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This +1 <Link to="/eq-armor/heavy_steel_shield">heavy steel shield</Link> bears the symbol of <Link to="/faith/gorum">Gorum</Link>, the Lord in Iron, on its face. In the hands of a character with the challenge class feature, this shield grants additional abilities. By spending one use of her challenge class feature as an immediate action, the wearer of a challenging shield can apply her Charisma bonus to her shield bonus to AC against a target of her challenge for 1 minute.</p>
<h3 id="magic-armor-challenging_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/nereids_grace">nereid's grace</Link>; <strong>Price</strong> 3,670 gp</p>
</>};
const _spined_shield = {title: "Spined Shield", jsx: <><h2 id="magic-armor-spined_shield-spined-shield">Spined Shield</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 133</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 467</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 6th<br/><strong>Slot</strong> shield; <strong>Price</strong> 5,580 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This +1 <Link to="/eq-armor/heavy_steel_shield">heavy steel shield</Link> is covered in spines. It acts as a normal <Link to="/eq-armorenh/shield_spikes">spiked shield</Link>. On command up to three times per day, the shield's wearer can fire one of the shield's spines. A fired spine has a +1 enhancement bonus, a range increment of 120 feet, and deals 1d10 points of damage (19-20/&times;2). Fired spines regenerate each day.</p>
<h3 id="magic-armor-spined_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/magic_missile">magic missile</Link>; <strong>Price</strong> 2,875 gp</p>
</>};
const _okeno_madu = {title: "Okeno Madu", jsx: <><h2 id="magic-armor-okeno_madu-okeno-madu">Okeno Madu</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 52</Link><br/><strong>Aura</strong> faint enchantment; <strong>CL</strong> 3rd<br/><strong>Slot</strong> shield; <strong>Price</strong> 5,590 gp; <strong>Weight</strong> 5 lbs.</p>
<p>A common sight among the more deplorable slavers of Katapesh, this +1 <Link to="/eq-armor/leather_madu">leather madu</Link> is adorned with body parts - ranging from fingers and toes to severed heads - each one crudely affixed to the shield's spikes. The wielder of the shield gains a +4 competence bonus on Intimidate checks while the shield is visible. The wearer and any associated companions take a -4 penalty on all Diplomacy checks made against good-aligned creatures while the shield is visible.</p>
<p>Once per day as a standard action, the wielder of an Okeno madu can shake the shield, causing the fetishes to rattle uncontrollably for 3 rounds. When he shakes the shield, the wielder can choose one creature within 35 feet to suffer the effects of the spell <em>castigate</em> as long as the fetishes continue shaking.</p>
<h3 id="magic-armor-okeno_madu-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/castigate">castigate</Link>; <strong>Price</strong> 2,890 gp</p>
</>};
const _lockpick_shield = {title: "Lockpick Shield", jsx: <><h2 id="magic-armor-lockpick_shield-lockpick-shield">Lockpick Shield</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 237</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 11th<br/><strong>Slot</strong> shield; <strong>Price</strong> 7,159 gp; <strong>Weight</strong> 6 lbs.</p>
<p>With a command word, the bearer of this +2 <Link to="/eq-armor/light_steel_shield">light steel shield</Link> can cause a series of lockpicks and tiny tools to extend from the front of the shield and begin picking a lock or disabling a detected trap. The shield attempts a Disable Device check with a +10 total skill bonus. The shield is treated as using <Link to="/eq-misc/thieves_tools">thieves' tools</Link>, and can't gain any additional bonuses on the check from spells, the aid another action, or other abilities. The shield performs the work on the wearer's behalf, freeing her to take other actions. She must still remain in contact with the target of the Disable Device attempt for the normal number of rounds, but can move around the target, as long as she never breaks contact. The wearer is still the subject of any effects that result from the success or failure of the Disable Device check.</p>
<p>While picking a lock or disabling a device with the shield, the wearer loses her shield bonus to Armor Class, though the bonus does apply against any result of the Disable Device check that targets Armor Class (such as an attack from a trap triggered by the shield failing its check by 5 or more).</p>
<h3 id="magic-armor-lockpick_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/animate_objects">animate objects</Link>; <strong>Price</strong> 3,659 gp</p>
</>};
const _dragonslayers_shield = {title: "Dragonslayer's Shield", jsx: <><h2 id="magic-armor-dragonslayers_shield-dragonslayers-shield">Dragonslayer's Shield</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 131</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> shield; <strong>Price</strong> 7,170 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This +2 <Link to="/eq-armor/heavy_steel_shield">heavy steel shield</Link> has a distinct curve to its shape and often bears the device of a valiant knight. The wearer of this shield gains a +2 bonus on Reflex saves against effects that originate or <Link to="/misc/burst">burst</Link> from a point outside his own square, as though he had <Link to="/rule/cover">cover</Link>. It does not protect against <Link to="/misc/spread">spread</Link> effects. This bonus does not stack with that granted by actual cover or give cover to any creature other than the wearer. In addition, the dragonslayer's shield grants its wielder a +2 morale bonus on Will saves against the <Link to="/umr/frightful_presence">frightful presence</Link> ability.</p>
<h3 id="magic-armor-dragonslayers_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/remove_fear">remove fear</Link>, <Link to="/spell/shield_of_faith">shield of faith</Link>; <strong>Price</strong> 3,670 gp</p>
</>};
const _shield_of_sunrise = {title: "Shield of Sunrise", jsx: <><h2 id="magic-armor-shield_of_sunrise-shield-of-sunrise">Shield of Sunrise</h2>
<p><strong>Sources</strong> <Link to="/source/undead_slayers_handbook">Undead Slayer's Handbook pg. 29</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 5th<br/><strong>Slot</strong> shield; <strong>Price</strong> 7,659 gp; <strong>Weight</strong> 6 lbs.</p>
<p>This +1 <Link to="/magic-enh/bashing">bashing</Link> <Link to="/eq-armor/light_steel_shield">light steel shield</Link> features a brilliant sun motif, and always seems comfortably warm to the touch. Once per day when the shield's bearer successfully hits a creature with a <Link to="/misc/shield_bash">shield bash</Link> attack, he may activate the shield as a swift action to mark the target with radiant energy. This radiant energy lasts for 1d4 rounds. During this time, the marked creature shines like a <Link to="/eq-misc/sunrod">sunrod</Link>, and the wielder's allies gain a +1 insight bonus on attack rolls against the marked creature as long as they are within 30 feet of it. If the marked creature is vulnerable to light, this insight bonus increases to +3.</p>
<p>When a marked creature is hit by a melee or ranged attack, the radiant energy discharges in a burst of light, dealing 1d6 points of damage to the marked creature and ending the marking effect. If the creature is vulnerable to light, it is also <Link to="/misc/dazed">dazed</Link> for 1 round.</p>
<h3 id="magic-armor-shield_of_sunrise-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/daybreak_arrow">daybreak arrow</Link>, <Link to="/spell/tactical_acumen">tactical acumen</Link>; <strong>Price</strong> 3,909 gp</p>
</>};
const _shield_of_covered_retreat = {title: "Shield of Covered Retreat", jsx: <><h2 id="magic-armor-shield_of_covered_retreat-shield-of-covered-retreat">Shield of Covered Retreat</h2>
<p><strong>Sources</strong> <Link to="/source/magical_marketplace">Magical Marketplace pg. 7</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 8th<br/><strong>Slot</strong> shield; <strong>Price</strong> 8,157 gp; <strong>Weight</strong> 10 lbs.</p>
<p>A <em>shield of covered retreat</em> is a wide wooden kite shield emblazoned with the image of a mighty tree, the original design of which is thought to come from Nirmathas. Three times per day as a swift action, the bearer of this +1 <Link to="/magic-enh/arrow_deflection">arrow deflection</Link> <Link to="/eq-armor/heavy_wooden_shield">heavy wooden shield</Link> can select a single square within 5 feet (including the square occupied by the bearer) and extend a barrier of protective force around the square that lasts for 1d4 rounds. The barrier appears as a shimmer in the air, but it does not impede vision, movement, or other actions. As long as this barrier is in place, the creature occupying the square can stand up from <Link to="/rule/prone">prone</Link> or leave the square without provoking attacks of opportunity, even if the square is threatened by another creature. Other actions provoke attacks of opportunity as normal. Large or larger creatures cannot benefit from this effect. A creature occupying the square is not hindered by the barrier and may make attacks of opportunity normally.</p>
<h3 id="magic-armor-shield_of_covered_retreat-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/shield">shield</Link>; <strong>Price</strong> 4,157 gp</p>
</>};
const _clawhand_shield = {title: "Clawhand Shield", jsx: <><h2 id="magic-armor-clawhand_shield-clawhand-shield">Clawhand Shield</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 211</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 9th<br/><strong>Slot</strong> shield; <strong>Price</strong> 8,158 gp; <strong>Weight</strong> 8 lbs.</p>
<p>This shield is made of bone and ivory, but has been imbued with magic to function as a +2 <Link to="/eq-material/mithral">mithral</Link> <Link to="/eq-armor/heavy_steel_shield">heavy steel shield</Link> (though it is not considered to be made of metal). The shield has stylized animal claws encircling its outer rim. If the wearer is <Link to="/rule/grappled">grappled, pinned</Link>, or <Link to="/umr/swallow_whole">swallowed whole</Link>, as a standard action he can cause the claws to animate and make a single melee attack dealing 1d8 points of damage + the wielder's Strength modifier (1d6 + his Strength modifier for a Small wielder) without requiring a successful combat maneuver check to do so. This is considered a weapon attack with a one-handed weapon the wielder is proficient with, not a <Link to="/misc/shield_bash">shield bash</Link>.</p>
<p>Additionally, the claws can animate to perform the somatic components of a spell as long as the arm holding the shield would be able to provide these components if it weren't carrying a shield. As a result, the shield has no arcane spell failure chance.</p>
<h3 id="magic-armor-clawhand_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/summon_natures_ally_i">summon nature's ally I</Link>; <strong>Price</strong> 4,158 gp</p>
</>};
const _collapsible_tower = {title: "Collapsible Tower", jsx: <><h2 id="magic-armor-collapsible_tower-collapsible-tower">Collapsible Tower</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 131</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 6th<br/><strong>Slot</strong> shield; <strong>Price</strong> 8,170 gp; <strong>Weight</strong> 15 lbs.</p>
<p>Three times per day, this +2 <Link to="/eq-armor/heavy_steel_shield">heavy steel shield</Link> can be commanded to transform into a +2 <Link to="/eq-armor/tower_shield">tower shield</Link>. It can stay in tower shield form for 1 minute or until it is commanded to take its normal form again (a swift action). A collapsible tower's weight does not change when it takes tower shield form.</p>
<h3 id="magic-armor-collapsible_tower-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/shrink_item">shrink item</Link>; <strong>Price</strong> 4,170 gp</p>
</>};
const _lions_shield = {title: "Lion's Shield", jsx: <><h2 id="magic-armor-lions_shield-lions-shield">Lion's Shield</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 132</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 467</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 10th<br/><strong>Slot</strong> shield; <strong>Price</strong> 9,170 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This +2 <Link to="/eq-armor/heavy_steel_shield">heavy steel shield</Link> is fashioned to appear to be a roaring lion's head. Three times per day as a free action, the lion's head can be commanded to attack (independently of the shield wearer), biting with the wielder's base attack bonus (including multiple attacks, if the wielder has them) and dealing 2d6 points of damage. This attack is in addition to any actions performed by the wielder.</p>
<h3 id="magic-armor-lions_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/summon_natures_ally_iv">summon nature's ally IV</Link>; <strong>Price</strong> 4,670 gp</p>
</>};
const _maidens_aegis = {title: "Maiden's Aegis", jsx: <><h2 id="magic-armor-maidens_aegis-maidens-aegis">Maiden's Aegis</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 87</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 6th<br/><strong>Slot</strong> shield; <strong>Price</strong> 9,170 gp; <strong>Weight</strong> 15 lbs.</p>
<p>These +2 <Link to="/eq-armor/heavy_steel_shield">heavy steel shields</Link> were often issued to <Link to="/rule/gray_maidens">Gray Maiden</Link> unit leaders, and many still carry them today. Once per day as a swift action, the wielder of a maiden's aegis can reduce the enhancement bonus of the shield to +1 to grant a +1 enhancement bonus to up to four other shields within a 30-foot radius. This effect persists for 10 minutes, but it ends for any individual shield that moves more than 30 feet from the maiden's aegis that granted the bonus.</p>
<h3 id="magic-armor-maidens_aegis-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/magic_vestment">magic vestment</Link>; <strong>Price</strong> 4,670 gp</p>
</>};
const _brilliant_bulwark = {title: "Brilliant Bulwark", jsx: <><h2 id="magic-armor-brilliant_bulwark-brilliant-bulwark">Brilliant Bulwark</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 21</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 10th<br/><strong>Slot</strong> none; <strong>Price</strong> 9,655 gp; <strong>Weight</strong> 4 lbs.</p>
<p>This +1 <Link to="/magic-enh/blinding">blinding</Link> <Link to="/eq-armor/buckler">buckler</Link> is made from a lustrous glass that is as hard as steel and reflects light like a mirror. The shield glows as a torch, though this light can be suppressed or resumed on command. The shield can be commanded to shine light as per <em>daylight</em> for up to 10 minutes each day. This duration need not be consecutive, but it must be used in 1-minute increments. The wielder can also expend this duration while activating the buckler's blinding ability to increase the save DC by 1 for every 2 minutes of <em>daylight</em> duration expended. The shield must sit in natural bright light for at least 1 hour after its 10 minutes of <em>daylight</em> is expended before the ability can be used again.</p>
<h3 id="magic-armor-brilliant_bulwark-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/daylight">daylight</Link>, <Link to="/spell/light">light</Link>; <strong>Price</strong> 4,975 gp</p>
</>};
const _casters_shield_greater = {title: "Greater Caster's Shield", jsx: <><h2 id="magic-armor-casters_shield_greater-greater-casters-shield">Greater Caster's Shield</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 131</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 11th<br/><strong>Slot</strong> shield; <strong>Price</strong> 10,153 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This +3 <Link to="/eq-armor/light_wooden_shield">light wooden shield</Link> acts in all ways like a <Link to="/magic-armor/casters_shield">caster's shield</Link>, but the strip can accommodate spells of up to 5th level.</p>
<h3 id="magic-armor-casters_shield_greater-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/feat/scribe_scroll">Scribe Scroll</Link>; <strong>Price</strong> 5,153 gp</p>
</>};
const _gunners_buckler = {title: "Gunner's Buckler", jsx: <><h2 id="magic-armor-gunners_buckler-gunners-buckler">Gunner's Buckler</h2>
<p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 31</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 3rd<br/><strong>Slot</strong> shield; <strong>Price</strong> 10,155 gp; <strong>Weight</strong> 2 lbs.</p>
<p>The top edge of this +1 <Link to="/eq-material/mithral">mithral</Link> <Link to="/eq-armor/buckler">buckler</Link> features a notched gun rest. A character wearing a gunner's buckler who uses a firearm while threatened by an opponent in melee does not provoke attacks of opportunity, but takes a -4 penalty on all ranged attack rolls in any round in which he makes a ranged attack while threatened in melee.</p>
<h3 id="magic-armor-gunners_buckler-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/cats_grace">cat's grace</Link>, <Link to="/spell/shield">shield</Link>; <strong>Price</strong> 5,155 gp</p>
</>};
const _stalkers_fang_shoanti = {title: "Stalker's Fang (Shoanti)", jsx: <><h2 id="magic-armor-stalkers_fang_shoanti-stalkers-fang-shoanti">Stalker's Fang (Shoanti)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 225</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> shield; <strong>Price</strong> 11,462 gp; <strong>Weight</strong> 6 lbs.</p>
<blockquote>
<p><em>The following suit of armor is generally available only to members of the indicated race or ethnicity.</em></p>
</blockquote>
<p>The Shoanti craft this +1 <Link to="/magic-enh/keen">keen</Link> <Link to="/eq-armor/klar">klar</Link> from the skull of a horned spirestalker. Its enhancement bonus applies to attack rolls and damage rolls for attacks made with the blade, as well as to its shield bonus to AC. If the wielder confirms a critical hit against a creature that is denied its Dexterity bonus to AC, the target takes an additional 1d6 points of <Link to="/umr/bleed">bleed</Link> damage.</p>
<h3 id="magic-armor-stalkers_fang_shoanti-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/bleed">bleed</Link>, <Link to="/spell/keen_edge">keen edge</Link>, creator must be a Shoanti; <strong>Price</strong> 5,962 gp</p>
</>};
const _celestial_shield = {title: "Celestial Shield", jsx: <><h2 id="magic-armor-celestial_shield-celestial-shield">Celestial Shield</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 131</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 88</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 7th<br/><strong>Slot</strong> shield; <strong>Price</strong> 13,170 gp; <strong>Weight</strong> 7 lbs.</p>
<p>This gold-edged +2 <Link to="/magic-enh/blinding">blinding</Link> <Link to="/eq-armor/heavy_steel_shield">heavy steel shield</Link> is impossibly light and handy despite its size. It has no armor check penalty or arcane spell failure chance, and it allows the wielder to use <em>feather fall</em> on himself once per day. A creature wearing <Link to="/magic-armor/celestial_armor">celestial armor</Link> while wielding a celestial shield may command the armor to provide <em>overland flight</em> rather than <Link to="/spell/fly">fly</Link> once per day.</p>
<h3 id="magic-armor-celestial_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/feather_fall">feather fall</Link>, <Link to="/spell/overland_flight">overland flight</Link>; <strong>Price</strong> 6,670 gp</p>
</>};
const _starsling_buckler = {title: "Starsling Buckler", jsx: <><h2 id="magic-armor-starsling_buckler-starsling-buckler">Starsling Buckler</h2>
<p><strong>Sources</strong> <Link to="/source/seers_of_the_drowned_city">Seers of the Drowned City pg. 55</Link><br/><strong>Aura</strong> moderate evocation and transmutation; <strong>CL</strong> 6th<br/><strong>Slot</strong> none; <strong>Price</strong> 14,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This +2 <Link to="/eq-armor/buckler">buckler</Link> is emblazoned with a swirl of stars and comets. Many of the Saoc Brethren commissioned these bucklers as markers of high social standing; they had them each decorated with unique depictions of constellations, comets, phases of the moon, or other distinctive astronomical sights, and used them as much as decor as for defense.</p>
<p>As a swift action, the user of a starsling buckler can cause the face to illuminate and whirl to life, duplicating the effect of the <em>light</em> spell. The stars, comets, and sun begin to glow as they lift off the shield and spin around in a brilliant display. They can be fired from the spinning celestial vortex as if via a +2 <Link to="/eq-weapon/sling">sling</Link> (the user is considered proficient with the sling for purposes of resolving such attacks from a starsling buckler). All feats and proficiencies related to slings apply to stars fired from a starsling buckler. These sling attacks cannot be made as offhand weapon attacks. The shield contains five sling stars - once all five have been fired, new sling stars are restored to the shield automatically after 1 minute.</p>
<h3 id="magic-armor-starsling_buckler-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/light">light</Link>, <Link to="/spell/magic_stone">magic stone</Link>; <strong>Price</strong> 7,000 gp</p>
</>};
const _phalanx_shield = {title: "Phalanx Shield", jsx: <><h2 id="magic-armor-phalanx_shield-phalanx-shield">Phalanx Shield</h2>
<p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 31</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 7th<br/><strong>Slot</strong> shield; <strong>Price</strong> 14,080 gp; <strong>Weight</strong> 30 lbs.</p>
<p>Once per day as a standard action, the wielder of this +2 <Link to="/eq-material/adamantine">adamantine</Link> <Link to="/eq-armor/tower_shield">tower shield</Link> can conjure two <em>spiritual allies</em> (as per the spell). These conjured allies last for 1 minute and can neither attack nor move beyond spaces that are adjacent to the wielder of the phalanx shield. Both allies gain a +4 enhancement bonus to AC and have the <Link to="/feat/shield_wall">Shield Wall</Link> teamwork feat.</p>
<h3 id="magic-armor-phalanx_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/spiritual_ally">spiritual ally</Link>; <strong>Price</strong> 9,580 gp</p>
</>};
const _maelstrom_shield = {title: "Maelstrom Shield", jsx: <><h2 id="magic-armor-maelstrom_shield-maelstrom-shield">Maelstrom Shield</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 132</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 5th<br/><strong>Slot</strong> shield; <strong>Price</strong> 14,170 gp; <strong>Weight</strong> 10 lbs.</p>
<p>The device of this +1 <Link to="/magic-enh/bashing">bashing</Link> <Link to="/eq-armor/heavy_steel_shield">heavy steel shield</Link> features a magical image of the trackless seas, complete with rolling waves and crashing whitecaps. When used to make a <Link to="/misc/shield_bash">shield bash</Link> attack, the shield's wielder can make a <Link to="/rule/trip">trip</Link> attack as a free action against the same target without provoking an attack of opportunity from the creature being tripped. On command, the wielder can make the shield produce a gallon of fresh drinkable water. Once per day on command, the wielder can use the maelstrom shield to emit a stream of water as the <em>hydraulic push</em> spell.</p>
<h3 id="magic-armor-maelstrom_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>, <Link to="/spell/control_water">control water</Link>, <Link to="/spell/hydraulic_push">hydraulic push</Link>; <strong>Price</strong> 7,170 gp</p>
</>};
const _spiteful_shield = {title: "Spiteful Shield", jsx: <><h2 id="magic-armor-spiteful_shield-spiteful-shield">Spiteful Shield</h2>
<p><strong>Sources</strong> <Link to="/source/book_of_the_damned">Book of the Damned pg. 197</Link><br/><strong>Aura</strong> moderate illusion; <strong>CL</strong> 8th<br/><strong>Slot</strong> shield; <strong>Price</strong> 14,170 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This +2 <Link to="/magic-enh/mirrored">mirrored</Link> <Link to="/eq-armor/heavy_steel_shield">heavy steel shield</Link> is infused with the spite of <Link to="/family/div">divs</Link>, allowing its bearer to terrify and disgust foes with twisted reflections of themselves. As a move action up to three times per day, the wielder can show an adjacent creature its reflection in the shield's mirrored surface. As the creature looks at its mirror image, the image changes to show the creature hideously warped, covered with plague sores, or otherwise twisted. The creature must succeed at a DC 16 Will save or become <Link to="/misc/shaken">shaken</Link> and <Link to="/misc/sickened">sickened</Link> for 2d4 rounds. This is a mind-affecting fear effect, and it can be avoided as though it were a <Link to="/umr/gaze">gaze</Link> attack.</p>
<h3 id="magic-armor-spiteful_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/phantasmal_killer">phantasmal killer</Link>, <Link to="/spell/spell_turning">spell turning</Link>; <strong>Price</strong> 7,170 gp</p>
</>};
const _volcanic_shield = {title: "Volcanic Shield", jsx: <><h2 id="magic-armor-volcanic_shield-volcanic-shield">Volcanic Shield</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 133</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 5th<br/><strong>Slot</strong> shield; <strong>Price</strong> 14,170 gp; <strong>Weight</strong> 10 lbs.</p>
<p>This +1 <Link to="/magic-enh/bashing">bashing</Link> <Link to="/eq-armor/heavy_steel_shield">heavy steel shield</Link> burns with an internal fire upon its boss, gaining the <Link to="/magic-enh/flaming">flaming</Link> weapon special ability when used to make <Link to="/misc/shield_bash">shield bash</Link> attacks. On command, the wielder can make the shield belch forth smoke as a <Link to="/eq-misc/smokestick">smokestick</Link>, but this smoke does not impair the shield user's vision. Once per day, the wielder may cause the volcanic shield to erupt in a cascade of brimstone as the <em>burning hands</em> spell.</p>
<h3 id="magic-armor-volcanic_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>, <Link to="/spell/burning_hands">burning hands</Link>, <Link to="/spell/pyrotechnics">pyrotechnics</Link>; <strong>Price</strong> 7,170 gp</p>
</>};
const _surefooted_shield = {title: "Surefooted Shield", jsx: <><h2 id="magic-armor-surefooted_shield-surefooted-shield">Surefooted Shield</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_94_ice_tomb_of_the_giant_queen">Pathfinder #94: Ice Tomb of the Giant Queen pg. 18</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 6th<br/><strong>Slot</strong> shield; <strong>Price</strong> 14,200 gp; <strong>Weight</strong> 15 lbs.</p>
<p>The face of this +2 <Link to="/eq-armor/heavy_steel_shield">heavy steel shield</Link> is lined with sheets of riveted steel to absorb more impact. A surefooted shield grants its wielder a +2 bonus on his CMD versus awesome blow, <Link to="/rule/bull_rush">bull rush</Link>, and <Link to="/rule/overrun">overrun</Link> combat maneuvers and on Reflex saves against <Link to="/umr/trample">trample</Link> attacks.</p>
<p>Additionally, up to three times per day, whenever an enemy's melee attack misses the wielder, an enemy fails a combat maneuver against the wielder, or the wielder succeeds at a Reflex save against a trample attack, the wielder can move 5 feet as an immediate action; this movement does not provoke attacks of opportunity and does not count as a 5-foot step.</p>
<h3 id="magic-armor-surefooted_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/abjuring_step">abjuring step</Link>; <strong>Price</strong> 7,185 gp</p>
</>};
const _tempest_shield = {title: "Tempest Shield", jsx: <><h2 id="magic-armor-tempest_shield-tempest-shield">Tempest Shield</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 133</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 6th<br/><strong>Slot</strong> shield; <strong>Price</strong> 15,170 gp; <strong>Weight</strong> 10 lbs.</p>
<p>The face of this +1 <Link to="/magic-enh/bashing">bashing</Link> <Link to="/eq-armor/heavy_steel_shield">heavy steel shield</Link> swirls with the image of swirling clouds, driving rain, or falling snow. When used to make a <Link to="/misc/shield_bash">shield bash</Link> attack, the shield's wielder can make a <Link to="/rule/bull_rush">bull rush</Link> maneuver as a free action against her target without provoking an attack of opportunity from the creature being bull rushed. Once per day on command, the wielder can cause the tempest shield to emit a stream of high-powered air as the <em>gust of wind</em> spell.</p>
<h3 id="magic-armor-tempest_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>, <Link to="/spell/gust_of_wind">gust of wind</Link>; <strong>Price</strong> 8,170 gp</p>
</>};
const _battlement_shield = {title: "Battlement Shield", jsx: <><h2 id="magic-armor-battlement_shield-battlement-shield">Battlement Shield</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 130</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 286</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> shield; <strong>Price</strong> 16,180 gp; <strong>Weight</strong> 45 lbs.</p>
<p>Once per day on command, this +2 <Link to="/eq-armor/tower_shield">tower shield</Link> can transform into a solid, 1-foot-thick, 10-foot-by-10-foot wall of masonry with a battlement on top and an arrow slit in each 5-foot length. The wall acts as cover just like any physical wall. The wielder can touch the wall with one hand and command it to revert to a tower shield either resting on the ground and balanced against his hand or strapped to his arm in the normal fashion. The wall has all the characteristics of any other foot-thick wall of masonry (hardness 8, 90 hit points, break DC 35). Attacks sufficient to destroy the wall cause it to immediately transform back into a shield, which loses half its hit points and gains the <Link to="/misc/broken">broken</Link> condition. The shield remains in wall form until destroyed or commanded to return to shield form. The wall cannot appear in a space too small to accommodate it.</p>
<h3 id="magic-armor-battlement_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/wall_of_stone">wall of stone</Link>; <strong>Price</strong> 8,180 gp</p>
</>};
const _shieldmarshals_ward = {title: "Shieldmarshal's Ward", jsx: <><h2 id="magic-armor-shieldmarshals_ward-shieldmarshals-ward">Shieldmarshal's Ward</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_origins">Mythic Origins pg. 18</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> shield; <strong>Price</strong> 17,155 gp; <strong>Weight</strong> 5 lbs.</p>
<p>Crafted from magnetic ore warped by exposure to the Mana Wastes, this +1 <Link to="/magic-enh/arrow_deflection">arrow deflection</Link> <Link to="/eq-armor/buckler">buckler</Link> is thought to be one of the original shields granted by Duke Alkenstar to the first shieldmarshals.</p>
<p>Whenever the bearer of this shield successfully deflects a projectile using the shield, she can, as a free action, expend one use of mythic power to redirect the deflected projectile toward any creature to which she has a clear line of effect, using the original attacker's attack and damage rolls. The range increment penalty on the attack roll of this deflected projectile is calculated from the original point at which the projectile was fired. For example, a foe fires an arrow from his <Link to="/eq-weapon/shortbow">shortbow</Link> (range increment 60 feet) at a mythic character bearing a shieldmarshal's ward who is 100 feet away, taking a -2 penalty on his attack roll. The mythic character deflects the arrow toward the same foe, meaning the arrow has traveled a total of 200 feet, which imposes a -6 penalty on the attack roll to hit the foe (since three range increments of 60 feet equals 180 feet).</p>
<p>A character who possesses levels in the <Link to="/pclass/shieldmarshal">shieldmarshal</Link> prestige class can bear a shieldmarshal's ward without penalty, even if she isn't proficient with it.</p>
<h3 id="magic-armor-shieldmarshals_ward-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/spell/protection_from_arrows">protection from arrows</Link>, <Link to="/spell/shield">shield</Link>, <Link to="/spell/telekinesis">telekinesis</Link>; <strong>Price</strong> 8,655 gp</p>
</>};
const _guard_of_man = {title: "Guard of Man", jsx: <><h2 id="magic-armor-guard_of_man-guard-of-man">Guard of Man</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 51</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 15th<br/><strong>Slot</strong> shield; <strong>Price</strong> 17,180 gp; <strong>Weight</strong> 45 lbs.</p>
<p>This massive, imposing +2 <Link to="/magic-enh/spell_resistance_13">spell resistance (13)</Link> <Link to="/eq-armor/tower_shield">tower shield</Link> is a metal bulwark engraved with the main edicts of the Laws of Man. The spell resistance special ability of this shield works only against divine spells and does not ward the bearer against arcane magic. While held, the shield grants a +4 resistance bonus on Fortitude saving throws against divine spells and spell-like abilities.</p>
<p>Three times per day as a swift action, when the wielder of a guard of man is in the area of <Link to="/ability/channel_energy">channeled energy</Link> (regardless of whether she is excluded by an effect such as <Link to="/feat/selective_channeling">Selective Channeling</Link>), she can rebuke the god powering the ability. Using this ability causes the text on the guard of man to glow and decreases the amount of channeled energy by half (minimum 1). This reduction affects the channeled energy itself, and thus reduces the effect on all targets within its area. The power of the channeled energy can be further reduced with a successful Will saving throw, as normal.</p>
<h3 id="magic-armor-guard_of_man-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/spell_resistance">spell resistance</Link>, creator must be an atheist; <strong>Price</strong> 8,680 gp</p>
</>};
const _winged_shield = {title: "Winged Shield", jsx: <><h2 id="magic-armor-winged_shield-winged-shield">Winged Shield</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 133</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 467</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> shield; <strong>Price</strong> 17,257 gp; <strong>Weight</strong> 10 lbs.</p>
<p>This <Link to="/eq-armor/heavy_wooden_shield">heavy wooden shield</Link> has a +3 enhancement bonus. Arching bird wings are carved into the face of the shield. Once per day, it can be commanded to <em>fly</em> (as the spell), carrying the wielder. The shield can carry up to 133 pounds and move at 60 feet per round, or up to 266 pounds and move at 40 feet per round.</p>
<h3 id="magic-armor-winged_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/fly">fly</Link>; <strong>Price</strong> 8,707 gp</p>
</>};
const _shield_of_the_mazeborn = {title: "Shield of the Mazeborn", jsx: <><h2 id="magic-armor-shield_of_the_mazeborn-shield-of-the-mazeborn">Shield of the Mazeborn</h2>
<p><strong>Sources</strong> <Link to="/source/melee_tactics_toolbox">Melee Tactics Toolbox pg. 23</Link><br/><strong>Aura</strong> faint divination and enchantment; <strong>CL</strong> 5th<br/><strong>Slot</strong> shield; <strong>Price</strong> 18,170 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This +1 <Link to="/magic-enh/bashing">bashing</Link> <Link to="/eq-armor/heavy_steel_shield">heavy steel shield</Link> resembles a bull's head with a complex, maze-like rune inscribed on the creature's forehead. In addition to the shield's bashing ability, the shield allows the wielder to use <em>know direction</em> at will and <em>find the path</em> once per week. As long as the shield is equipped, it also grants the wearer immunity to the <Link to="/spell/maze">maze</Link> spell.</p>
<h3 id="magic-armor-shield_of_the_mazeborn-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>, <Link to="/spell/find_the_path">find the path</Link>, <Link to="/spell/know_direction">know direction</Link>; <strong>Price</strong> 9,170 gp</p>
</>};
const _bloodfeast_shield = {title: "Bloodfeast Shield", jsx: <><h2 id="magic-armor-bloodfeast_shield-bloodfeast-shield">Bloodfeast Shield</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex pg. 237</Link>, <Link to="/source/pathfinder_48_shadows_of_gallowspire">Pathfinder #48: Shadows of Gallowspire pg. 65</Link><br/><strong>Aura</strong> strong necromancy; <strong>CL</strong> 12th<br/><strong>Slot</strong> shield; <strong>Price</strong> 18,770 gp; <strong>Weight</strong> 15 lbs.</p>
<p>Three flensed skulls jut from the face of this +2 <Link to="/eq-armor/heavy_steel_shield">heavy steel shield</Link>. Three times per day as a free action, the shield's wearer can command the heads to attack independently of her, biting with the wearer's base attack bonus (making multiple attacks if the wearer has a high enough base attack bonus). This attack is in addition to any actions performed by the wearer, and deals 1d6 points of damage plus 1 point of <Link to="/rule/constitution_damage">Constitution damage</Link>.</p>
<p>When using the bloodfeast shield's ability, if the wearer is a <Link to="/template/vampire">vampire</Link> (or regains hit points from blood drain in a similar manner), she also heals 5 hit points or gains 5 <Link to="/rule/temporary_hit_points">temporary hit points</Link> for 1 hour.</p>
<h3 id="magic-armor-bloodfeast_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/vampiric_touch">vampiric touch</Link>; <strong>Price</strong> 9,545 gp</p>
</>};
const _broadside_bulwark = {title: "Broadside Bulwark", jsx: <><h2 id="magic-armor-broadside_bulwark-broadside-bulwark">Broadside Bulwark</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 50</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 10th<br/><strong>Slot</strong> shield; <strong>Price</strong> 19,007 gp; <strong>Weight</strong> 10 lbs.</p>
<p>The front of this +2 <Link to="/eq-armor/heavy_wooden_shield">heavy wooden shield</Link> has several small holes that resemble the gun ports on a naval ship. There are seven such holes in total on the front of shield, each varying in size, with an equal number of thin hemp strings on the reverse side. As a standard action, the wielder of the broadside bulwark can pull one of the strings, causing a small red bead to fly out from the associated gun port. This bead travels 30 feet forward and detonates as a <em>fireball</em> spell (Reflex DC 14 half), leaving the wielder outside the blast radius unless it contacts something before reaching 30 feet. After a string is pulled, its associated gun port is permanently closes and can no longer be used.</p>
<p>The gun ports are different sizes, and include three small ports that deal 3d6 points of fire damage, three larger ports that deal 6d6 points of fire damage, and one massive port in the center of the shield that deals 9d6 points of fire damage.</p>
<p>Once all the gun ports have been fired, the shield takes on a blackened, charred look and grants the wielder fire resistance 5.</p>
<h3 id="magic-armor-broadside_bulwark-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/fireball">fireball</Link>, <Link to="/spell/resist_energy">resist energy</Link>; <strong>Price</strong> 9,582 gp</p>
</>};
const _avalanche_shield = {title: "Avalanche Shield", jsx: <><h2 id="magic-armor-avalanche_shield-avalanche-shield">Avalanche Shield</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 130</Link><br/><strong>Aura</strong> strong evocation; <strong>CL</strong> 12th<br/><strong>Slot</strong> shield; <strong>Price</strong> 19,170 gp; <strong>Weight</strong> 10 lbs.</p>
<p>The front of this +1 <Link to="/magic-enh/bashing">bashing</Link> <Link to="/eq-armor/heavy_steel_shield">heavy steel shield</Link> looks as though it is crafted from hundreds of bits of rubble and larger stones. When used to make a <Link to="/misc/shield_bash">shield bash</Link> attack, stones fall from shield and cling to the target of the shield bash. The target must succeed at a DC 14 Fortitude saving throw or be <Link to="/rule/entangled">entangled</Link> for 1d4 rounds. Once per day on command, the target's wielder can choose to petrify the target of a shield bash instead. The target must succeed at a DC 16 Fortitude saving throw or become <Link to="/rule/petrified">petrified</Link> for 1 minute.</p>
<h3 id="magic-armor-avalanche_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>, <Link to="/spell/stone_shape">stone shape</Link>, <Link to="/spell/flesh_to_stone">flesh to stone</Link>; <strong>Price</strong> 9,670 gp</p>
</>};
const _fortress_shield = {title: "Fortress Shield", jsx: <><h2 id="magic-armor-fortress_shield-fortress-shield">Fortress Shield</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 132</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 286</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 11th<br/><strong>Slot</strong> shield; <strong>Price</strong> 19,180 gp; <strong>Weight</strong> 45 lbs.</p>
<p>The wearer of this +1 <Link to="/eq-armor/tower_shield">tower shield</Link> may, as a full-round action, transform the shield into a 1-inch-thick cube of iron that springs into being around him, completely enclosing his space. The cube has hardness 10 and 30 hit points per side. This cube grants the wearer <Link to="/rule/cover">total cover</Link> against everything outside the cube, including (as it is perfectly sealed) swarms and gas attacks. The inside of the cube is dark, and air cannot get in or out so the wearer must <Link to="/misc/hold_his_breath">hold his breath</Link> starting on the third round after activating the cube. Attacks sufficient to destroy one side of the cube cause it to immediately transform back into a shield, which loses half its hit points and gains the broken condition. Otherwise, the cube reverts to shield form upon command, if the wearer moves from his current space, or if the wearer falls unconscious or dies.</p>
<h3 id="magic-armor-fortress_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/wall_of_iron">wall of iron</Link>; <strong>Price</strong> 9,680 gp</p>
</>};
const _mwangi_spirit_shield = {title: "Mwangi Spirit Shield", jsx: <><h2 id="magic-armor-mwangi_spirit_shield-mwangi-spirit-shield">Mwangi Spirit Shield</h2>
<p><strong>Sources</strong> <Link to="/source/sargava_the_lost_colony">Sargava, the Lost Colony pg. 29</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 15th<br/><strong>Slot</strong> shield; <strong>Price</strong> 19,393 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This large wood-and-hide shield is similar to other Mwangi shields, but the totem animal painted on the shield's face seems to move when the shield is carried. Crafted by Mwangi shamans to grant its wielder the power of tribal totem spirits, a Mwangi spirit shield functions as a +1 <Link to="/magic-enh/ghost_touch_a">ghost touch</Link> <Link to="/eq-armor/light_wooden_shield">light wooden shield</Link>. Once per day on command, the shield can grant its bearer <em>bull's strength</em> for 1 minute.</p>
<p>Other versions of the Mwangi spirit shield exist; some are known to grant <Link to="/spell/cats_grace">cat's grace</Link> or <Link to="/spell/bears_endurance">bear's endurance</Link> to their wielders instead of <em>bull's strength.</em></p>
<h3 id="magic-armor-mwangi_spirit_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>, <Link to="/spell/etherealness">etherealness</Link>; <strong>Price</strong> 9,733 gp</p>
</>};
const _lyrune_quah_klar = {title: "Lyrune-Quah Klar", jsx: <><h2 id="magic-armor-lyrune_quah_klar-lyrune-quah-klar">Lyrune-Quah Klar</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 52</Link><br/><strong>Aura</strong> moderate illusion; <strong>CL</strong> 7th<br/><strong>Slot</strong> shield; <strong>Price</strong> 19,912 gp; <strong>Weight</strong> 6 lbs.</p>
<p>Considered the greatest archers among the Shoanti people, the folk of the Lyrune-Quah tribe treasure this +2 <Link to="/eq-armor/klar">klar</Link> shaped from the skull of a lion. The specific shape of the skull allows the wielder to properly hold and shoot a <Link to="/eq-weapon/shortbow">shortbow</Link> (though not a <Link to="/eq-weapon/longbow">longbow</Link>) while still benefiting from the Lyrune-Quah klar's shield bonus.</p>
<p>Up to three times per day as a free action, the wielder of a Lyrune-Quah klar can utter praise to the nature totem of the moon. The next arrow fired after the prayer trails a line of shimmering stars in its wake. If a creature is struck by this arrow, the stars orbit it for the next 8 rounds, negating any <Link to="/rule/concealment">concealment</Link> for the target and causing it to emit light as if it were holding a <Link to="/eq-misc/sunrod">sunrod</Link>.</p>
<h3 id="magic-armor-lyrune_quah_klar-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/wandering_star_motes">wandering star motes</Link>, creator must be proficient with shortbow; <strong>Price</strong> 10,037 gp</p>
</>};
const _wyrmslayers_shield = {title: "Wyrmslayer's Shield", jsx: <><h2 id="magic-armor-wyrmslayers_shield-wyrmslayers-shield">Wyrmslayer's Shield</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 133</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> shield; <strong>Price</strong> 20,170 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This +4 <Link to="/eq-armor/heavy_steel_shield">heavy steel shield</Link> acts in all ways as a <Link to="/magic-armor/dragonslayers_shield">dragonslayer's shield</Link>, except it grants a +6 morale bonus on Will saves against the <Link to="/umr/frightful_presence">frightful presence</Link> ability instead of a +2 morale bonus.</p>
<h3 id="magic-armor-wyrmslayers_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/remove_fear">remove fear</Link>, <Link to="/spell/shield_of_faith">shield of faith</Link>; <strong>Price</strong> 10,170 gp</p>
</>};
const _shield_of_hags = {title: "Shield of Hags", jsx: <><h2 id="magic-armor-shield_of_hags-shield-of-hags">Shield of Hags</h2>
<p><strong>Sources</strong> <Link to="/source/people_of_the_river">People of the River pg. 29</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 7th<br/><strong>Slot</strong> shield; <strong>Price</strong> 20,273 gp; <strong>Weight</strong> 5 lbs.</p>
<p>Found with disturbing frequency amid treasure caches in the wilderness of Loric Fells, this +1 <Link to="/eq-armor/light_wooden_shield">light wooden shield</Link> has what appears to be a human face stretched across its front, with the weathered skin held in place by thick iron studs. Three times per day on command, the open mouth of the face can emit one of the two following effects:</p>
<ul>
<li>A burst of terrified screams that causes creatures in a 30-foot cone to become <Link to="/misc/panicked">panicked</Link> as if by the <em>fear</em> spell. A successful DC 16 Will save causes a creature to become <Link to="/misc/shaken">shaken</Link> for 1 round instead.</li>
<li>A tortured voice pleading for help. Anyone within 60 feet of the shield hears the voice in her own language, spoken as if by a member of her own race.</li>
</ul>
<h3 id="magic-armor-shield_of_hags-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/fear">fear</Link>, <Link to="/spell/tongues">tongues</Link>; <strong>Price</strong> 10,713 gp</p>
</>};
const _elephant_shield = {title: "Elephant Shield", jsx: <><h2 id="magic-armor-elephant_shield-elephant-shield">Elephant Shield</h2>
<p><strong>Sources</strong> <Link to="/source/melee_tactics_toolbox">Melee Tactics Toolbox pg. 23</Link><br/><strong>Aura</strong> moderate evocation and transmutation; <strong>CL</strong> 6th<br/><strong>Slot</strong> shield; <strong>Price</strong> 21,340 gp; <strong>Weight</strong> 10 lbs.</p>
<p>This +2 <Link to="/eq-armor/leather_madu">leather madu</Link> is designed in the form of a bull elephant's head, complete with imposing ivory tusks. The shield provides a +3 circumstance bonus on combat maneuver checks made to <Link to="/rule/bull_rush">bull rush</Link> opponents. If used as a weapon, the elephant shield grants a +1 enhancement bonus on attack rolls and damage rolls and deals damage as if it were one size category larger than it is. Once per day, the bearer of the elephant shield can have the trunk of the shield lash out, allowing the wielder to attempt a <Link to="/rule/grapple">grapple</Link> combat maneuver check against a foe as a swift action. This combat maneuver doesn't provoke attacks of opportunity.</p>
<h3 id="magic-armor-elephant_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/beast_shape_i">beast shape I</Link>, <Link to="/spell/force_punch">force punch</Link>; <strong>Price</strong> 10,840 gp</p>
</>};
const _bastion_of_the_inheritor = {title: "Bastion of the Inheritor", jsx: <><h2 id="magic-armor-bastion_of_the_inheritor-bastion-of-the-inheritor">Bastion of the Inheritor</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 142</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> shield; <strong>Price</strong> 22,170 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This +1 <Link to="/magic-enh/rallying">rallying</Link> <Link to="/eq-armor/heavy_steel_shield">heavy steel shield</Link> prominently displays the sword emblem of the god <Link to="/faith/iomedae">Iomedae</Link>, and functions as a holy symbol for her worshipers. When using this shield, the wearer reduces the extra damage she takes from <Link to="/magic-enh/anarchic">anarchic</Link> weapons, smite good, smite law, and <Link to="/magic-enh/unholy">unholy</Link> weapons by her tier, to a minimum of 0. When its wearer uses the smite evil class feature, she can expend one use of mythic power to extend the deflection bonus to AC she gains against her target to all allies in a 10-foot-radius <Link to="/misc/burst">burst</Link> centered on her. This bonus lasts for 1 minute or until the smite evil ends, whichever comes first.</p>
<h3 id="magic-armor-bastion_of_the_inheritor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/spell/magic_circle_against_evil">magic circle against evil</Link>, <Link to="/spell/remove_fear">remove fear</Link>, <Link to="/spell/sanctify_armor">sanctify armor</Link>; <strong>Price</strong> 11,170 gp</p>
</>};
const _spell_ward_tower_shield = {title: "Spell Ward Tower Shield", jsx: <><h2 id="magic-armor-spell_ward_tower_shield-spell-ward-tower-shield">Spell Ward Tower Shield</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 133</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 15th<br/><strong>Slot</strong> shield; <strong>Price</strong> 25,180 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This +2 <Link to="/magic-enh/spell_resistance_13"><em>spell resistance</em> (13)</Link> <Link to="/eq-armor/tower_shield">tower shield</Link> grants a +4 resistance bonus on Reflex saving throws against spells and spell-like abilities. Once per day, when the wearer succeeds at a saving throw against a spell or spell-like ability that allows a Reflex saving throw for half damage, she may spend an immediate action to instead take no damage from that spell or spell-like ability.</p>
<h3 id="magic-armor-spell_ward_tower_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/cats_grace">cat's grace</Link>, <Link to="/spell/spell_resistance">spell resistance</Link>; <strong>Price</strong> 12,680 gp</p>
</>};
const _icon_of_order = {title: "Icon of Order", jsx: <><h2 id="magic-armor-icon_of_order-icon-of-order">Icon of Order</h2>
<p><strong>Sources</strong> <Link to="/source/divine_anthology">Divine Anthology pg. 6</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> shield; <strong>Price</strong> 26,170 gp; <strong>Weight</strong> 15 lbs.</p>
<p>An icon of order is a +2 <Link to="/eq-armor/heavy_steel_shield">heavy steel shield</Link> that typically displays the sword-and-sunburst holy symbol of <Link to="/faith/iomedae">Iomedae</Link> on a white field. The wielder of an icon of order gains a +2 sacred bonus on saves against spells and effects with the chaotic descriptor. Once per day, the wielder can cast <em>protection from chaos</em> as a swift action.</p>
<h3 id="magic-armor-icon_of_order-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/feat/quicken_spell">Quicken Spell</Link>, <Link to="/spell/protection_from_chaos">protection from chaos</Link>; <strong>Price</strong> 13,170 gp</p>
</>};
const _lens_of_the_dark_tapestry = {title: "Lens of the Dark Tapestry", jsx: <><h2 id="magic-armor-lens_of_the_dark_tapestry-lens-of-the-dark-tapestry">Lens of the Dark Tapestry</h2>
<p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 31</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 7th<br/><strong>Slot</strong> shield; <strong>Price</strong> 29,170 gp; <strong>Weight</strong> 30 lbs.</p>
<p>The matte surface of this +1 <Link to="/eq-material/voidglass">voidglass</Link> <Link to="/eq-armor/heavy_shield">heavy shield</Link> is cold to the touch. The shield's face contains a disorienting field of flickering stars. On command, the wearer of this shield can take 1 point of <Link to="/rule/wisdom_drain">Wisdom drain</Link> to banish a single creature within 30 feet into the Dark Tapestry. The target of this ability must succeed at a DC 16 Will save or be teleported into the airless void of space. The target can attempt a new saving throw as a full-round action each round to return. While banished in this way, the target takes 3d6 points of cold damage per round and must <Link to="/misc/hold_its_breath">hold its breath</Link> or begin to <Link to="/rule/suffocate">suffocate</Link>. If the Wisdom damage is negated or does not occur, the ability does not function. If the Wisdom drain is healed, any banished creature returns, and the shield becomes permanently nonmagical.</p>
<h3 id="magic-armor-lens_of_the_dark_tapestry-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/teleport">teleport</Link>; <strong>Price</strong> 15,670 gp</p>
</>};
const _quick_block_buckler = {title: "Quick Block Buckler", jsx: <><h2 id="magic-armor-quick_block_buckler-quick-block-buckler">Quick Block Buckler</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 132</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 14th<br/><strong>Slot</strong> shield; <strong>Price</strong> 36,155 gp; <strong>Weight</strong> 15 lbs.</p>
<p>Once per round as an immediate action, this +3 <Link to="/magic-enh/arrow_deflection">arrow deflection</Link> <Link to="/eq-armor/buckler">buckler</Link> can be used to block an incoming melee attack. When used in this way, the buckler's enhancement bonus increases by +2 against that attack. The buckler's user must decide to use this ability before the attack roll is made. When the shield's user blocks a melee attack in this way, it cannot use its arrow deflection special ability for 1 round.</p>
<h3 id="magic-armor-quick_block_buckler-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/shield">shield</Link>; <strong>Price</strong> 18,155 gp</p>
</>};
const _belligerent_shield = {title: "Belligerent Shield", jsx: <><h2 id="magic-armor-belligerent_shield-belligerent-shield">Belligerent Shield</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 130</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 12th<br/><strong>Slot</strong> shield; <strong>Price</strong> 36,170 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This +1 <Link to="/magic-enh/animated">animated</Link> <Link to="/magic-enh/bashing">bashing</Link> <Link to="/eq-armor/heavy_steel_shield">heavy steel shield</Link> rattles in anticipation during battle. When loosed into the air to defend its wearer, the belligerent shield attacks as well as defends. Each round starting the round after animation, the shield makes a single <Link to="/misc/shield_bash">shield bash</Link> attack against a foe of its wearer's choice within the wearer's reach. This works as a standard shield bash attack using the wearer's normal attack bonus with the shield, except that the wearer retains the shield bonus to AC, and while the shield's attack is treated as an off-hand attack, the wearer does not take offhand penalties on her own attacks unless she is fighting with two weapons herself. If the wearer has any feats or abilities that benefit shield bashing attacks, they apply to attacks made by the belligerent shield.</p>
<h3 id="magic-armor-belligerent_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>, <Link to="/spell/animate_objects">animate objects</Link>; <strong>Price</strong> 18,170 gp</p>
</>};
const _storvals_fang = {title: "Storval's Fang", jsx: <><h2 id="magic-armor-storvals_fang-storvals-fang">Storval's Fang</h2>
<p><strong>Sources</strong> <Link to="/source/disciples_doctrine">Disciple's Doctrine pg. 30</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 6th<br/><strong>Slot</strong> none; <strong>Price</strong> 38,312 gp; <strong>Weight</strong> 6 lbs.</p>
<p>This metal +1 <Link to="/eq-armor/klar">klar</Link> is shaped like the head of a storm <Link to="/monster/roc">roc</Link>, whose sharp feathers serve as the klar's spikes, and it hums and crackles like a distant stormy sky. When used to make a <Link to="/misc/shield_bash">shield bash</Link> attack, a Storval's fang deals an additional 1d6 points of sonic damage. In addition, the wielder gains electricity resistance 5. When the wielder confirms a critical hit with a Storval's fang, it unleashes a thunderclap, <Link to="/misc/deafened">deafening</Link> the target of the critical hit for 1 minute unless that target succeeds at a DC 16 Fortitude saving throw.</p>
<p>If the wielder of a Storval's fang also wields a Storval's thunder and uses the <Link to="/feat/thunder_and_fang">Thunder and Fang</Link> feat, each weapon deals an additional 1d6 points of electricity damage, the DCs to negate their critical hit effects increase by 2, and a creature that fails such a saving throw is also pushed back 10 feet and knocked <Link to="/rule/prone">prone</Link>.</p>
<h3 id="magic-armor-storvals_fang-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/lightning_bolt">lightning bolt</Link>, <Link to="/spell/resist_energy">resist energy</Link>, <Link to="/spell/sound_burst">sound burst</Link>, creator must be of Shoanti descent; <strong>Price</strong> 19,312 gp</p>
</>};
const _force_tower = {title: "Force Tower", jsx: <><h2 id="magic-armor-force_tower-force-tower">Force Tower</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 132</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 7th<br/><strong>Slot</strong> shield; <strong>Price</strong> 46,030 gp; <strong>Weight</strong> 22 lbs.</p>
<p>This +1 <Link to="/magic-enh/arrow_deflection">arrow deflection</Link> <Link to="/magic-enh/ghost_touch_a">ghost touch</Link> <Link to="/eq-material/mithral">mithral</Link> <Link to="/eq-armor/tower_shield">tower shield</Link> glows with a perpetual bluish radiance. Infused with magical force, a force tower renders its wielder immune to magic missiles and also allows its wielder to use its arrow deflection special ability to deflect magical rays and ranged touch attacks. The Reflex save DC to deflect such attacks is equal to 20 + the level of the spell (or 1/2 the class level or Hit Dice of the creature that created the effect, if a supernatural effect). If a spell or effect creates multiple rays or attacks, the force tower deflects only one of them per round.</p>
<h3 id="magic-armor-force_tower-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/etherealness">etherealness</Link>, <Link to="/spell/resilient_sphere">resilient sphere</Link>, <Link to="/spell/shield">shield</Link>; <strong>Price</strong> 23,530 gp</p>
</>};
const _absorbing_shield = {title: "Absorbing Shield", jsx: <><h2 id="magic-armor-absorbing_shield-absorbing-shield">Absorbing Shield</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 130</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 467</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 17th<br/><strong>Slot</strong> shield; <strong>Price</strong> 50,170 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This +1 <Link to="/eq-armor/heavy_steel_shield">heavy steel shield</Link> is made of metal, but its color is a flat black that seems to absorb light. Once every 2 days, on command, it can <em>disintegrate</em> an object that it touches, as the spell but requiring a melee touch attack. This effect only functions as an attack - it can't be activated to target a creature or weapon as it strikes the shield.</p>
<h3 id="magic-armor-absorbing_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/disintegrate">disintegrate</Link>; <strong>Price</strong> 25,170 gp</p>
</>};
const _elysian_shield = {title: "Elysian Shield", jsx: <><h2 id="magic-armor-elysian_shield-elysian-shield">Elysian Shield</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 132</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 89</Link><br/><strong>Aura</strong> strong conjuration; <strong>CL</strong> 13th<br/><strong>Slot</strong> shield; <strong>Price</strong> 52,620 gp; <strong>Weight</strong> 45 lbs.</p>
<p>This +2 <Link to="/magic-enh/ghost_touch_a">ghost touch</Link> <Link to="/eq-armor/tower_shield">tower shield</Link> is engraved with funerary runes depicting the peaceful rest of the contented dead. The wielder of an elysian shield is immune to the create spawn ability of undead, and once per day as an immediate action can negate a single <Link to="/rule/energy_drain">energy drain</Link>, <Link to="/rule/ability_damage_drain">ability damage, or ability drain</Link> attack by an undead creature. In addition, once per day as a standard action, the wielder can release a wave of positive energy that <Link to="/misc/panicked">panics</Link> undead, as the Turn Undead feat (Will DC 20 negates).</p>
<h3 id="magic-armor-elysian_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/feat/turn_undead">Turn Undead</Link>, <Link to="/spell/death_ward">death ward</Link>, <Link to="/spell/etherealness">etherealness</Link>; <strong>Price</strong> 26,390 gp</p>
</>};
const _saviths_iron = {title: "Savith's Iron", jsx: <><h2 id="magic-armor-saviths_iron-saviths-iron">Savith's Iron</h2>
<p><strong>Sources</strong> <Link to="/source/lost_treasures">Lost Treasures pg. 51</Link><br/><strong>Aura</strong> strong abjuration and transmutation; <strong>CL</strong> 13th<br/><strong>Slot</strong> none; <strong>Price</strong> 59,170 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This large iron shield acts as a +1 <Link to="/magic-enh/animated">animated</Link> <Link to="/magic-enh/light_fortification">light fortification</Link> <Link to="/eq-armor/heavy_steel_shield">heavy steel shield</Link>. The shield's bearer is immune to poison, although poisons in effect before the shield is wielded still run their course. While Savith's Iron is wielded, poisoned attacks instead bolster the bearer: if the bearer is subjected by a foe to a poison that deals ability score damage, the bearer gains a +4 enhancement bonus to the ability score the poison would normally damage. This bonus lasts for 1 minute; each additional dose of the same poison extends the effect for 1 additional minute. The bearer can benefit from only one bonus at a time, but can choose to benefit from a new poison in place of an old one. For example, when the bearer of Savith's Iron is stung by a <Link to="/monster/wyvern">wyvern</Link>, she gains a +4 enhancement bonus to her Constitution score for 1 minute; if she then comes in contact with <Link to="/eq-poison/terinav_root">terinav root</Link>, she must to decide whether to maintain her Constitution bonus or swap it out for a +4 enhancement bonus to her Dexterity. Savith's Iron does not grant the wielder bonuses from poisons she takes willingly or those applied by an ally, and poisons that don't inflict ability score damage have no effect.</p>
<h3 id="magic-armor-saviths_iron-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/animate_objects">animate objects</Link>, <Link to="/spell/limited_wish">limited wish</Link> or <Link to="/spell/miracle">miracle</Link>, <Link to="/spell/neutralize_poison">neutralize poison</Link>; <strong>Price</strong> 29,670 gp</p>
</>};
const _spellbane_shield = {title: "Spellbane Shield", jsx: <><h2 id="magic-armor-spellbane_shield-spellbane-shield">Spellbane Shield</h2>
<p><strong>Sources</strong> <Link to="/source/melee_tactics_toolbox">Melee Tactics Toolbox pg. 23</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 15th<br/><strong>Slot</strong> shield; <strong>Price</strong> 79,180 gp; <strong>Weight</strong> 45 lbs.</p>
<p>This massive iron-covered +2 <Link to="/eq-armor/tower_shield">tower shield</Link> grants the wielder a +3 resistance bonus on saving throws against spells, spell-like abilities and supernatural abilities, and reduces hit point damage taken from such sources by 10 points.</p>
<h3 id="magic-armor-spellbane_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/spell_resistance">spell resistance</Link>; <strong>Price</strong> 39,680 gp</p>
</>};
const _equalizer_shield = {title: "Equalizer Shield", jsx: <><h2 id="magic-armor-equalizer_shield-equalizer-shield">Equalizer Shield</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_purity">Champions of Purity pg. 30</Link></p>
<p><strong>Aura</strong> strong abjuration; <strong>CL</strong> 12th<br/><strong>Slot</strong> shield; <strong>Price</strong> 120,830 gp; <strong>Weight</strong> 23 lbs.</p>
<p>Shined to a mirror finish and fitted with supple leather straps, this +1 <Link to="/eq-material/mithral">mithral</Link> <Link to="/eq-armor/tower_shield">tower shield</Link> displays no decoration or markings on its highly reflective surface. Once per day, the bearer of this shield can issue a challenge to a foe and ring the shield like a gong, resulting in a resonating blast that negates all magic in a 10-foot radius, as per <em>antimagic field.</em> This effect lasts for 1 minute.</p>
<h3 id="magic-armor-equalizer_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/antimagic_field">antimagic field</Link>; <strong>Price</strong> 60,930 gp</p>
</>};
const _shield_of_the_mage = {title: "Shield of the Mage", jsx: <><h2 id="magic-armor-shield_of_the_mage-shield-of-the-mage">Shield of the Mage</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 359</Link></p>
<p><strong>Aura</strong> moderate divination; <strong>CL</strong> 11th<br/><strong>Slot</strong> shield; <strong>Price</strong> 14,500 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This <Link to="/magic-armor/casters_shield">caster's shield</Link> always has one arcane scroll and knows the same arcane spells as the wielder. When the spell on the scroll is cast, another scroll of a spell the wielder knows randomly manifests to replace it. The shield has no arcane spell failure. The shield can also <Link to="/spell/read_magic">read magic</Link>. It will often debate with its wielder for the most devastating course of action, but does what the wielder commands.</p>
<h3 id="magic-armor-shield_of_the_mage-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/feat/scribe_scroll">Scribe Scroll</Link>, creator must be an arcane spellcaster of at least 14th level; <strong>Price</strong> 7,250 gp</p>
<h3 id="magic-armor-shield_of_the_mage-statistics">Statistics</h3>
<p><strong>Alignment</strong> neutral; <strong>Ego</strong> 6<br/><strong>Senses</strong> 30 ft.<br/><strong>Int</strong> 16, <strong>Wis</strong> 10, <strong>Cha</strong> 10<br/><strong>Communication</strong> telepathy (Common and six other languages)</p>
</>};
const _gossamer_shrouds_of_the_clairvoyant = {title: "Gossamer Shrouds of the Clairvoyant", jsx: <><h2 id="magic-armor-gossamer_shrouds_of_the_clairvoyant-gossamer-shrouds-of-the-clairvoyant">Gossamer Shrouds of the Clairvoyant</h2>
<p><strong>Sources</strong> <Link to="/source/magical_marketplace">Magical Marketplace pg. 17</Link><br/><strong>Aura</strong> moderate conjuration and illusion; <strong>CL</strong> 9th<br/><strong>Slot</strong> armor; <strong>Price</strong> 20,150 gp; <strong>Weight</strong> 25 lbs.</p>
<p>This sky-blue suit of mistmail has the <Link to="/magic-enh/glamered">glamered</Link> armor special ability, and can once per day create a dramatic spectacle of twinkling lights, as the <em>rainbow pattern</em> spell. The armor is prone to dramatic soliloquies about its "prophetic visions" and "sight beyond the mystical veils"; however, it lacks actual divinatory powers.</p>
<h3 id="magic-armor-gossamer_shrouds_of_the_clairvoyant-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/disguise_self">disguise self</Link>, <Link to="/spell/obscuring_mist">obscuring mist</Link>, <Link to="/spell/rainbow_pattern">rainbow pattern</Link>; <strong>Price</strong> 10,075 gp</p>
<h3 id="magic-armor-gossamer_shrouds_of_the_clairvoyant-statistics">Statistics</h3>
<p><strong>Alignment</strong> chaotic neutral; <strong>Ego</strong> 7<br/><strong>Senses</strong> 120 ft.<br/><strong>Int</strong> 14, <strong>Wis</strong> 10, <strong>Cha</strong> 14<br/><strong>Communication</strong> speech (Auran, Celestial, Common)</p>
</>};
const _armor_of_the_shadow_lord = {title: "Armor of the Shadow Lord", jsx: <><h2 id="magic-armor-armor_of_the_shadow_lord-armor-of-the-shadow-lord">Armor of the Shadow Lord</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 356</Link></p>
<p><strong>Aura</strong> moderate illusion; <strong>CL</strong> 8th<br/><strong>Slot</strong> armor; <strong>Price</strong> 117,160 gp; <strong>Weight</strong> 15 lbs.</p>
<p>This suit of +4 <Link to="/magic-enh/greater_shadow">greater shadow</Link> <Link to="/magic-enh/greater_slick">greater slick</Link> <Link to="/eq-armor/leather">leather</Link> armor fits as snugly as a tight suit of silk against its wearer's skin and harbors an amoral and bloodthirsty intelligence. Via the telepathy it shares with its wielder, the armor gives constant advice on how to be stealthy, reach out of the way spots, and get the drop on foes. It also grants an extra +1d6 points of <Link to="/ability/sneak_attack">sneak attack</Link> damage, but the wearer must already have the sneak attack class feature to gain this bonus. Furthermore the armor has a maximum Dexterity bonus of +10 and no arcane spell failure.</p>
<h3 id="magic-armor-armor_of_the_shadow_lord-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/grease">grease</Link>, <Link to="/spell/invisibility">invisibility</Link>, <Link to="/spell/silence">silence</Link>, creator must have the sneak attack class feature; <strong>Price</strong> 58,660 gp</p>
<h3 id="magic-armor-armor_of_the_shadow_lord-statistics">Statistics</h3>
<p><strong>Alignment</strong> neutral; <strong>Ego</strong> 14<br/><strong>Senses</strong> 120 ft., darkvision<br/><strong>Int</strong> 14, <strong>Wis</strong> 16, <strong>Cha</strong> 14<br/><strong>Communication</strong> telepathy (Aklo, Common, and Elven)</p>
</>};
const _armor_of_arrow_attraction = {title: "Armor of Arrow Attraction", jsx: <><h2 id="magic-armor-armor_of_arrow_attraction-armor-of-arrow-attraction">Armor of Arrow Attraction</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 342</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 538</Link></p>
<p><strong>Aura</strong> strong abjuration; <strong>CL</strong> 16th<br/><strong>Slot</strong> armor; <strong>Weight</strong> 50 lbs.</p>
<p>Magical analysis indicates that this armor is a normal suit of +3 <Link to="/eq-armor/full_plate">full plate</Link>. The armor works normally with regard to melee attacks but actually attracts ranged weapons. The wearer takes a -15 penalty to AC against ranged weapons. The true nature of the armor does not reveal itself until the character is fired upon in earnest.</p>
<h3 id="magic-armor-armor_of_arrow_attraction-construction">Construction</h3>
<p><strong>Requirements</strong> +3 full plate; <strong>Cost</strong> -</p>
</>};
const _armor_of_rage = {title: "Armor of Rage", jsx: <><h2 id="magic-armor-armor_of_rage-armor-of-rage">Armor of Rage</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 342</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 538</Link></p>
<p><strong>Aura</strong> strong necromancy; <strong>CL</strong> 16th<br/><strong>Slot</strong> armor; <strong>Weight</strong> 50 lbs.</p>
<p>This armor is similar in appearance to armor of command and functions as a suit of +1 <Link to="/eq-armor/full_plate">full plate</Link>. However, when it is worn, the armor causes the character to take a -4 penalty to Charisma. All unfriendly creatures within 300 feet gain a +1 morale bonus on attack rolls against her. The effect is not noticeable to the wearer or those affected. In other words, the wearer does not immediately notice that donning the armor is the cause of her problems, nor do foes understand the reason for the depth of their enmity.</p>
<h3 id="magic-armor-armor_of_rage-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/magic-armor/breastplate_of_command">breastplate of command</Link>, +1 full plate; <strong>Cost</strong> -</p>
</>};
const _constrictor_armor = {title: "Constrictor Armor", jsx: <><h2 id="magic-armor-constrictor_armor-constrictor-armor">Constrictor Armor</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_82_secrets_of_the_sphinx">Pathfinder #82: Secrets of the Sphinx pg. 75</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 12th<br/><strong>Slot</strong> body; <strong>Weight</strong> 30 lbs.</p>
<p>Designed to resemble the wide scales on a serpent's belly, this armor functions as a +1 <Link to="/eq-armor/breastplate">breastplate</Link> of <Link to="/magic-enh/fire_resistance">fire resistance</Link>. The first time the wearer is struck in melee, the armor animates and begins crushing its wearer. On the round that the armor animates, it automatically <Link to="/rule/grapple">grapples</Link> the wearer. In following rounds, at the beginning of the wearer's turn, the armor makes a grapple combat maneuver check (CMB +20) to constrict the wearer. If successful, the armor deals 2d6 points of damage each round. Once animated, the armor releases its grip only when it is destroyed or its wearer dies. The wearer can't physically remove the armor once it activates, but others can help destroy or remove it. This armor functions normally (without animating) when worn by unliving creatures such as constructs and undead.</p>
<h3 id="magic-armor-constrictor_armor-construction">Construction</h3>
<p><strong>Requirements</strong> +1 breastplate of fire resistance; <strong>Cost</strong> -</p>
</>};
const _gravesoul_armor = {title: "Gravesoul Armor", jsx: <><h2 id="magic-armor-gravesoul_armor-gravesoul-armor">Gravesoul Armor</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 346</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 310</Link></p>
<p><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 10th<br/><strong>Slot</strong> armor; <strong>Weight</strong> 20 lbs.</p>
<p>This armor behaves in all ways as if it were +1 <Link to="/magic-enh/undead_controlling">undead controlling</Link> <Link to="/eq-armor/studded_leather">studded leather</Link> until its owner actually attempts to use its special property. At that point, the wearer and all living creatures within a 20-foot radius must succeed at a DC 15 Will saving throw to avoid believing that they are actually some sort of undead creature for the next 24 hours. The GM can either roll randomly (1d6; 1-3 <Link to="/template/zombie">zombies</Link>, 4-5 <Link to="/monster/ghoul">ghouls</Link>, 6 <Link to="/template/vampire">vampires</Link>) or choose which sorts of specific undead the affected creatures believe themselves to be. Creatures affected by the armor behave as normal for the sorts of undead they regard themselves as - "zombies" mindlessly attack unassociated creatures near them, vampires attempt to bite victims on the neck, and so on - but gain none of the special abilities of that creature. The affected creatures react negatively to effects that harm "their" type of undead, so "vampires" avoid garlic, <Link to="/monster/wraith">"wraiths"</Link> recoil from sunlight, and so on. The creatures continue to believe they are actually undead and ignore all evidence to the contrary. If attacked, they defend themselves, even if this requires using abilities they have but "their" type of undead normally lacks; for example, a barbarian who thinks she's a ghoul can still rage. <Link to="/ability/channel_energy">Channel energy</Link> and other undead-affecting effects have no effect on creatures affected by gravesoul armor.</p>
<p>This is a mind-affecting, compulsion enchantment. The wearer of the armor can use this power up to three times per day, though it can only work on a particular creature once in any 24-hour period. Regardless of the curse, the armor is still +1 studded leather, and some characters may find it useful despite its (non-existent) power over undead. Unlike most cursed items, this one is easily discarded without any magical assistance.</p>
<h3 id="magic-armor-gravesoul_armor-construction">Construction</h3>
<p><strong>Requirements</strong> +1 undead controlling studded leather; <strong>Cost</strong> -</p>
</>};
const _planar_invasion_shield = {title: "Planar Invasion Shield", jsx: <><h2 id="magic-armor-planar_invasion_shield-planar-invasion-shield">Planar Invasion Shield</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 349</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 310</Link></p>
<p><strong>Aura</strong> strong conjuration; <strong>CL</strong> 17th<br/><strong>Slot</strong> shield; <strong>Weight</strong> 15 lbs.</p>
<p>This shield behaves in all ways as an <Link to="/magic-armor/absorbing_shield">absorbing shield</Link> until its owner attempts to use its disintegration power in combat. Once he does, it instead causes one or more monsters to pour forth from the shield and attack the nearest creature each round (including the shield-bearer) for 1d6 rounds before retreating by the safest possible route. If there is no such path for them to escape, the monsters fight to the death. To determine the nature and number of the monsters, roll 2d4 to determine the level of the <Link to="/spell/summon_monster">summon monster</Link> spell and roll 1d3 to determine the number of creatures that appear. Monsters conjured by this shield remain until killed, act as normal for their kind, and are treated as summoned creatures with a permanent duration.</p>
<p>Once its curse activates, the shield calls forth monsters three times per day, approximately every 8 hours. If the monsters cannot emerge directly from the shield and survive (for example, because it's buried or underwater), they instead appear at the nearest safe location within 50 feet. Successful curse-breaking magic cast on the shield restores it to its previous guise as an absorbing shield and allows its wearer to abandon it.</p>
<h3 id="magic-armor-planar_invasion_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <em>absorbing shield;</em> <strong>Cost</strong> -</p>
</>};
